def _ui_inventory_build() -> list[dict[str, Any]]:
    """Best-effort inventory of all data-ui keys used in templates.

    This is used by the settings 'Iconbilder' editor to present a project-wide table.
    We do not attempt a full HTML parse; instead we use a small heuristic window.
    """

    templates_dir = (Path(__file__).resolve().parent / "templates")
    if not templates_dir.exists() or not templates_dir.is_dir():
        return []

    # data-ui key in attributes (single or double quotes)
    re_dui = re.compile(r"data-ui\s*=\s*['\"]([^'\"]+)['\"]")
    re_dui_set = re.compile(r"setAttribute\(\s*['\"]data-ui['\"]\s*,\s*['\"]([^'\"]+)['\"]\s*\)")
    re_aria = re.compile(r"aria-label\s*=\s*['\"]([^'\"]+)['\"]")
    re_title = re.compile(r"title\s*=\s*['\"]([^'\"]+)['\"]")
    re_span = re.compile(r"<span[^>]*>([^<]{1,120})</span>")
    re_svg = re.compile(r"(<svg\b[\s\S]{0,8000}</svg>)", re.IGNORECASE)

    by_key: dict[str, dict[str, Any]] = {}

    files = sorted([p for p in templates_dir.iterdir() if p.is_file() and p.suffix == ".html"], key=lambda p: p.name)
    for p in files:
        try:
            raw = p.read_text(encoding="utf-8", errors="replace")
        except Exception:
            continue
        lines = raw.splitlines()
        for i, line in enumerate(lines, start=1):
            if "data-ui" not in line:
                continue
            # include a small forward window to catch attributes and nearby <span> labels
            win = line
            try:
                # up to 3 next lines
                idx0 = i  # 1-based
                for j in range(idx0, min(len(lines), idx0 + 3)):
                    win += "\n" + lines[j]
            except Exception:
                pass

            seen_win_keys: set[str] = set()
            for m in list(re_dui.finditer(win)) + list(re_dui_set.finditer(win)):
                key = str(m.group(1) or "").strip()
                if not key:
                    continue
                # Keep inventory bounded; we only care about reasonable keys.
                if len(key) > 160:
                    continue
                if key in seen_win_keys:
                    continue
                seen_win_keys.add(key)

                area = _ui_inventory_area_for_template(p.name)

                # Prefer aria-label (user-facing) over title (often i18n token).
                aria = ""
                title = ""
                label = ""
                svg = ""
                try:
                    am = re_aria.search(win)
                    aria = str(am.group(1) or "").strip() if am else ""
                except Exception:
                    aria = ""
                try:
                    tm = re_title.search(win)
                    title = str(tm.group(1) or "").strip() if tm else ""
                except Exception:
                    title = ""
                try:
                    sm = re_span.search(win)
                    label = str(sm.group(1) or "").strip() if sm else ""
                except Exception:
                    label = ""
                try:
                    xm = re_svg.search(win)
                    svg = str(xm.group(1) or "").strip() if xm else ""
                    if len(svg) > 9000:
                        svg = ""
                except Exception:
                    svg = ""
                best_label = aria or label or ""
                best_label = best_label[:120]

                cur = by_key.get(key) or {
                    "key": key,
                    "areas": [],
                    "labels": [],
                    "svgs": [],
                    "files": [],
                    "examples": [],
                }
                if area and area not in cur["areas"]:
                    cur["areas"].append(area)
                if best_label and best_label not in cur["labels"]:
                    cur["labels"].append(best_label)
                if svg and svg not in cur["svgs"] and len(cur["svgs"]) < 1:
                    cur["svgs"].append(svg)
                if p.name not in cur["files"]:
                    cur["files"].append(p.name)
                if len(cur["examples"]) < 3:
                    cur["examples"].append({
                        "file": p.name,
                        "line": int(i),
                        "area": area,
                        "aria_label": aria or None,
                        "title": title or None,
                        "label": label or None,
                    })
                by_key[key] = cur

    out: list[dict[str, Any]] = []
    for k, v in by_key.items():
        try:
            areas = v.get("areas") if isinstance(v.get("areas"), list) else []
            labels = v.get("labels") if isinstance(v.get("labels"), list) else []
            svgs = v.get("svgs") if isinstance(v.get("svgs"), list) else []
            out.append({
                "key": str(k),
                "area": str(areas[0]) if areas else "",
                "areas": areas,
                "label": str(labels[0]) if labels else "",
                "labels": labels,
                "svg": str(svgs[0]) if svgs else "",
                "files": v.get("files") if isinstance(v.get("files"), list) else [],
                "examples": v.get("examples") if isinstance(v.get("examples"), list) else [],
            })
        except Exception:
            continue

    # Keep response bounded.
    out = sorted(out, key=lambda r: (str(r.get("area") or ""), str(r.get("key") or "")))
    return out[:4000]


ICON_SVG_PREFIX = "influxbro.icons.svg."
ICON_SVG_MAX_LEN = 10000


def _svg_local_name(tag: str) -> str:
    try:
        t = str(tag or "")
    except Exception:
        return ""
    if "}" in t:
        return t.rsplit("}", 1)[-1]
    return t


def _svg_attr_ok(name: str, value: str) -> bool:
    n = str(name or "").strip()
    if not n:
        return False
    nl = n.lower()
    if nl.startswith("on"):
        return False
    if "href" in nl or "xlink" in nl:
        return False
    if nl == "style":
        return False

    allowed = {
        "viewbox",
        "width",
        "height",
        "fill",
        "stroke",
        "stroke-width",
        "stroke-linecap",
        "stroke-linejoin",
        "stroke-miterlimit",
        "stroke-dasharray",
        "stroke-dashoffset",
        "opacity",
        "d",
        "cx",
        "cy",
        "r",
        "x",
        "y",
        "rx",
        "ry",
        "points",
        "transform",
        "fill-rule",
        "clip-rule",
        "clip-path",
        "mask",
        "id",
        "offset",
        "stop-color",
        "stop-opacity",
        "gradientunits",
        "gradienttransform",
        "x1",
        "y1",
        "x2",
        "y2",
        "fx",
        "fy",
    }
    if nl not in allowed:
        return False

    # If the value references an URL, only allow internal references.
    try:
        vl = str(value or "").strip().lower()
    except Exception:
        return False
    if "url(" in vl:
        return "url(#" in vl and "http" not in vl and "https" not in vl
    return True


def _svg_sanitize(svg_raw: str) -> tuple[str | None, str | None, int | None]:
    """Sanitize user-provided SVG for inline rendering.

    Returns (svg, error, http_status).
    """

    s = str(svg_raw or "").strip()
    if not s:
        return None, "svg required", 400
    if len(s) > ICON_SVG_MAX_LEN * 2:
        return None, f"svg too large (max {ICON_SVG_MAX_LEN} chars)", 413

    low = s.lower()
    if "<!doctype" in low or "<!entity" in low:
        return None, "doctype/entity not allowed", 400

    try:
        root = ET.fromstring(s)
    except Exception:
        return None, "invalid svg xml", 400

    if _svg_local_name(root.tag).lower() != "svg":
        return None, "root element must be <svg>", 400

    allowed_tags = {
        "svg",
        "g",
        "path",
        "circle",
        "rect",
        "line",
        "polyline",
        "polygon",
        "ellipse",
        "defs",
        "clippath",
        "mask",
        "lineargradient",
        "radialgradient",
        "stop",
        "title",
        "desc",
    }

    def _copy_el(el: ET.Element) -> ET.Element | None:
        name = _svg_local_name(el.tag).strip()
        if not name:
            return None
        nl = name.lower()
        if nl not in allowed_tags:
            return None
        out_el = ET.Element(name)

        # Copy allowed attributes only.
        for ak, av in (el.attrib or {}).items():
            try:
                if not _svg_attr_ok(ak, av):
                    continue
                out_el.set(str(ak), str(av))
            except Exception:
                continue

        # Copy children.
        for ch in list(el):
            c2 = _copy_el(ch)
            if c2 is not None:
                out_el.append(c2)
        return out_el

    clean = _copy_el(root)
    if clean is None:
        return None, "svg sanitization failed", 400
    if "xmlns" not in clean.attrib:
        clean.set("xmlns", "http://www.w3.org/2000/svg")

    try:
        out = ET.tostring(clean, encoding="unicode", method="xml")
    except Exception:
        return None, "could not serialize svg", 400

    out = str(out or "").strip()
    if not out:
        return None, "empty svg after sanitize", 400
    if len(out) > ICON_SVG_MAX_LEN:
        return None, f"svg too large after sanitize (max {ICON_SVG_MAX_LEN} chars)", 413
    return out, None, None


def _icon_svg_state_key(ui_key: str) -> str:
    return f"{ICON_SVG_PREFIX}{str(ui_key or '').strip()}"


def _dash_last_save(payload: dict[str, Any]) -> None:
    try:
        DATA_DIR.mkdir(parents=True, exist_ok=True)
        with DASH_LAST_LOCK:
            DASH_LAST_PATH.write_text(
                json.dumps(payload or {}, indent=2, sort_keys=True, ensure_ascii=True),
                encoding="utf-8",
            )
    except Exception:
        return


def _dash_last_load() -> dict[str, Any] | None:
    try:
        if not DASH_LAST_PATH.exists():
            return None
        with DASH_LAST_LOCK:
            raw = DASH_LAST_PATH.read_text(encoding="utf-8", errors="replace")
        j = json.loads(raw) if raw else None
        return j if isinstance(j, dict) else None
    except Exception:
        return None


def _dash_last_set_from_query(
    body: dict[str, Any],
    cache_id: str,
    key: dict[str, Any] | None,
) -> None:
    try:
        if not cache_id:
            return
        measurement = str(body.get("measurement") or "").strip()
        field = str(body.get("field") or "").strip()
        if not measurement or not field:
            return
        payload = {
            "v": 1,
            "at": _utc_now_iso_ms(),
            "cache_id": str(cache_id),
            "key": key if isinstance(key, dict) else None,
            "selection": {
                "measurement": measurement,
                "field": field,
                "entity_id": str(body.get("entity_id") or "").strip() or None,
                "friendly_name": str(body.get("friendly_name") or "").strip() or None,
                "range": str(body.get("range") or "").strip() or None,
                "start": str(body.get("start") or "").strip() or None,
                "stop": str(body.get("stop") or "").strip() or None,
                "unit": str(body.get("unit") or "").strip() or None,
                "detail_mode": str(body.get("detail_mode") or "").strip() or None,
                "manual_density_pct": body.get("manual_density_pct"),
            },
        }
        _dash_last_save(payload)
    except Exception:
        return

def load_cfg():
    # NOTE: No automatic autodetect at startup.
    # Autodetect is only triggered by explicit user action in the Config UI.
    global LAST_AUTODETECT_SOURCE
    LAST_AUTODETECT_SOURCE = None

    cfg = dict(DEFAULT_CFG)
    if RUNTIME_CFG_FILE.exists():
        try:
            disk = json.loads(RUNTIME_CFG_FILE.read_text(encoding="utf-8")) or {}
            if isinstance(disk, dict):
                cfg.update(disk)
        except Exception:
            pass

    # Normalize influx_version for all runtime callers.
    # This is intentionally best-effort and does not persist anything.
    try:
        v = int(cfg.get("influx_version", 2) or 2)
    except Exception:
        v = 2
    if v not in (1, 2):
        v = 2
    try:
        db = str(cfg.get("database") or "").strip()
    except Exception:
        db = ""
    has_v2 = bool(cfg.get("token")) and bool(cfg.get("org")) and bool(cfg.get("bucket"))
    if v != 2 and (not db) and has_v2:
        # Safety: prefer v2 to avoid confusing "v1 requires database" errors.
        v = 2
    cfg["influx_version"] = v

    # Keep UI font keys consistent even if config is old.
    try:
        _apply_ui_font_groups(cfg)
    except Exception:
        pass
    return cfg


def read_runtime_cfg() -> dict[str, Any]:
    try:
        if not RUNTIME_CFG_FILE.exists():
            return {}
        raw = json.loads(RUNTIME_CFG_FILE.read_text(encoding="utf-8")) or {}
        return raw if isinstance(raw, dict) else {}
    except Exception:
        return {}


def _clamp_int_cfg(cfg: dict[str, Any], key: str, default: int, lo: int, hi: int) -> None:
    try:
        cfg[key] = int(cfg.get(key, default))
    except Exception:
        cfg[key] = default
    if cfg[key] < lo:
        cfg[key] = lo
    if cfg[key] > hi:
        cfg[key] = hi


def _apply_ui_font_groups(cfg: dict[str, Any]) -> None:
    """Normalize the grouped font sizes and derive legacy keys.

    This is intentionally best-effort and does not persist anything.
    """

    # Migration (best-effort): if grouped keys are missing, derive them from legacy knobs.
    if cfg.get("ui_gui_title_px") is None:
        cfg["ui_gui_title_px"] = cfg.get("ui_pagecard_title_px", DEFAULT_CFG.get("ui_gui_title_px", 16))
    if cfg.get("ui_gui_heading_px") is None:
        cfg["ui_gui_heading_px"] = cfg.get("ui_section_title_font_px", DEFAULT_CFG.get("ui_gui_heading_px", 14))
    if cfg.get("ui_gui_body_px") is None:
        cfg["ui_gui_body_px"] = cfg.get("ui_font_size_px", DEFAULT_CFG.get("ui_gui_body_px", 12))
    if cfg.get("ui_gui_meta_px") is None:
        cfg["ui_gui_meta_px"] = cfg.get("ui_font_small_px", DEFAULT_CFG.get("ui_gui_meta_px", 10))

    if cfg.get("ui_tbl_title_px") is None:
        cfg["ui_tbl_title_px"] = DEFAULT_CFG.get("ui_tbl_title_px", 12)
    if cfg.get("ui_tbl_head_px") is None:
        cfg["ui_tbl_head_px"] = DEFAULT_CFG.get("ui_tbl_head_px", 11)
    if cfg.get("ui_tbl_cell_px") is None:
        # Old tables mostly used ui_font_small_px.
        cfg["ui_tbl_cell_px"] = cfg.get("ui_font_small_px", DEFAULT_CFG.get("ui_tbl_cell_px", 10))

    # Clamp to a compact safe range.
    _clamp_int_cfg(cfg, "ui_gui_title_px", 16, 8, 16)
    _clamp_int_cfg(cfg, "ui_gui_heading_px", 14, 8, 16)
    _clamp_int_cfg(cfg, "ui_gui_body_px", 12, 8, 16)
    _clamp_int_cfg(cfg, "ui_gui_meta_px", 10, 8, 16)
    _clamp_int_cfg(cfg, "ui_tbl_title_px", 12, 8, 16)
    _clamp_int_cfg(cfg, "ui_tbl_head_px", 11, 8, 16)
    _clamp_int_cfg(cfg, "ui_tbl_cell_px", 10, 8, 16)

    # Derive legacy keys so existing templates/JS keep working.
    cfg["ui_font_size_px"] = int(cfg.get("ui_gui_body_px") or 12)
    cfg["ui_font_small_px"] = int(cfg.get("ui_gui_meta_px") or 10)
    cfg["ui_popup_pre_font_px"] = int(cfg.get("ui_gui_meta_px") or 10)
    cfg["ui_popup_history_font_px"] = int(cfg.get("ui_gui_meta_px") or 10)
    cfg["ui_pagecard_title_px"] = int(cfg.get("ui_gui_title_px") or 16)
    cfg["ui_status_font_px"] = int(cfg.get("ui_gui_meta_px") or 10)
    cfg["ui_section_title_font_px"] = int(cfg.get("ui_gui_heading_px") or 14)
    cfg["ui_section_level2_font_px"] = int(cfg.get("ui_gui_body_px") or 12)
    cfg["ui_section_level3_font_px"] = int(cfg.get("ui_gui_meta_px") or 10)
    cfg["ui_sel_field_font_px"] = int(cfg.get("ui_gui_body_px") or 12)
    cfg["ui_sel_label_font_px"] = int(cfg.get("ui_gui_meta_px") or 10)
    cfg["ui_sel_desc_font_px"] = int(cfg.get("ui_gui_meta_px") or 10)


def _path_is_within(root: Path, p: Path) -> bool:
    try:
        rr = root.resolve()
        rp = p.resolve()
        return rp == rr or rr in rp.parents
    except Exception:
        return False


def _maybe_migrate_backups(cfg: dict[str, Any], target_dir: Path) -> None:
    """One-time migrate backups from old default (/data/backups) to /config.

    This is used to make backups visible in the HA file browser (under /config).
    """

    try:
        if not _path_is_within(CONFIG_DIR, target_dir):
            return
        # Only migrate when we're using the new default.
        if target_dir.resolve() != DEFAULT_BACKUP_DIR.resolve():
            return
        if bool(cfg.get("backup_migrated_to_config")):
            return

        src = OLD_DEFAULT_BACKUP_DIR
        if not src.exists() or not src.is_dir():
            cfg["backup_migrated_to_config"] = True
            save_cfg(cfg)
            return

        files = [p for p in src.iterdir() if p.is_file()]
        if not files:
            cfg["backup_migrated_to_config"] = True
            save_cfg(cfg)
            try:
                shutil.rmtree(src, ignore_errors=True)
            except Exception:
                pass
            return

        target_dir.mkdir(parents=True, exist_ok=True)

        for p in files:
            dst = target_dir / p.name
            if dst.exists():
                try:
                    if dst.stat().st_size == p.stat().st_size:
                        p.unlink(missing_ok=True)
                        continue
                except Exception:
                    pass
                # Avoid overwriting: copy with a suffix
                stem = p.name
                n = 1
                while True:
                    cand = target_dir / f"{stem}.dup{n}"
                    if not cand.exists():
                        dst = cand
                        break
                    n += 1

            shutil.copy2(p, dst)
            # Only delete source if destination exists and is non-empty (best-effort)
            try:
                if dst.exists() and dst.stat().st_size >= 0:
                    p.unlink(missing_ok=True)
            except Exception:
                pass

        # Remove old directory (user requested delete)
        try:
            shutil.rmtree(src, ignore_errors=True)
        except Exception:
            pass

        # Ensure persisted config points to the new path
        cfg["backup_dir"] = str(DEFAULT_BACKUP_DIR)
        cfg["backup_migrated_to_config"] = True
        save_cfg(cfg)
    except Exception:
        # Never break normal operation due to migration issues
        return


def backup_dir(cfg: dict[str, Any] | None = None) -> Path:
    """Return the configured backup directory (constrained under /config, /data or /share)."""

    try:
        c = cfg or load_cfg()
        raw = str(c.get("backup_dir") or "").strip()
    except Exception:
        c = cfg or {}
        raw = ""

    # Treat the old default as legacy; keep behavior aligned with the new default.
    if raw in (str(OLD_DEFAULT_BACKUP_DIR), "/data/backups"):
        raw = ""

    if not raw:
        target = BACKUP_DIR
    else:
        try:
            p = Path(raw)
            if not p.is_absolute():
                # Relative paths live under /config.
                p = CONFIG_DIR / raw
            p = p.resolve()
            cfg_root = CONFIG_DIR.resolve()
            data_root = DATA_DIR.resolve()
            share_root = SHARE_DIR.resolve()
            if _path_is_within(cfg_root, p) or _path_is_within(data_root, p) or _path_is_within(share_root, p):
                target = p
            else:
                target = BACKUP_DIR
        except Exception:
            target = BACKUP_DIR

    # Migrate old default backups to /config when applicable.
    # Use persisted runtime config (do not persist YAML overlays).
    try:
        _maybe_migrate_backups(load_cfg(), target)
    except Exception:
        pass

    return target


def _backup_target_id(name: str, idx: int) -> str:
    s = str(name or "").strip().lower()
    s = re.sub(r"[^a-z0-9]+", "_", s).strip("_")
    if not s:
        s = "target"
    return f"{s}_{int(idx)}"


def _backup_target_path(raw: str) -> Path:
    """Normalize a backup target path (constrained under /config, /data or /share)."""

    s = str(raw or "").strip()
    if not s:
        return DEFAULT_BACKUP_DIR
    try:
        p = Path(s)
        if not p.is_absolute():
            p = CONFIG_DIR / s
        p = p.resolve()
        cfg_root = CONFIG_DIR.resolve()
        data_root = DATA_DIR.resolve()
        share_root = SHARE_DIR.resolve()
        if _path_is_within(cfg_root, p) or _path_is_within(data_root, p) or _path_is_within(share_root, p):
            return p
    except Exception:
        return DEFAULT_BACKUP_DIR
    return DEFAULT_BACKUP_DIR


_DIR_WRITABLE_CACHE: dict[str, tuple[float, bool, str | None]] = {}


def _ensure_local_backups_alias(target_dir: Path) -> None:
    """Best-effort: provide the legacy local path `/data/backups`.

    This keeps the UI's "Lokal" target aligned with the historical location while
    preserving the actual configured backup directory.
    """

    try:
        alias = DATA_DIR / "backups"
        if alias.exists():
            return
        try:
            target_dir.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        try:
            DATA_DIR.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass
        os.symlink(str(target_dir), str(alias))
    except Exception:
        return


def _ensure_dir_writable(p: Path) -> tuple[bool, str | None]:
    """Return (available, error). Creates the directory if possible.

    Uses a short TTL cache to avoid frequent probe file I/O.
    """

    key = str(p)
    now = time.monotonic()
    cached = _DIR_WRITABLE_CACHE.get(key)
    if cached and (now - float(cached[0]) < 30.0):
        return bool(cached[1]), cached[2]

    try:
        p.mkdir(parents=True, exist_ok=True)
    except Exception as e:
        _DIR_WRITABLE_CACHE[key] = (now, False, str(e))
        return False, str(e)

    # Best-effort fast check
    try:
        if os.access(str(p), os.W_OK | os.X_OK):
            _DIR_WRITABLE_CACHE[key] = (now, True, None)
            return True, None
    except Exception:
        pass

    # Probe write once per TTL window to confirm actual writeability.
    try:
        probe = p / (".ib_write_probe_" + uuid.uuid4().hex)
        probe.write_text("ok", encoding="utf-8")
        probe.unlink(missing_ok=True)
        _DIR_WRITABLE_CACHE[key] = (now, True, None)
        return True, None
    except Exception as e:
        _DIR_WRITABLE_CACHE[key] = (now, False, str(e))
        return False, str(e)


def backup_targets(cfg: dict[str, Any] | None = None) -> tuple[list[dict[str, Any]], str | None]:
    """Return (targets, default_target_id).

    Targets are normalized and include availability info.
    """

    c = cfg or load_cfg()
    raw = c.get("backup_targets")
    items: list[dict[str, Any]] = raw if isinstance(raw, list) else []

    # Preserve legacy behavior by defaulting to the resolved backup_dir.
    if not items:
        _ensure_local_backups_alias(backup_dir(c))
        items = [
            {"name": "Lokal", "path": "/data/backups"},
            {"name": "QNAP", "path": "/share/QNAP_Addeon_Speicher/influxbro"},
        ]

    out: list[dict[str, Any]] = []
    for idx, it in enumerate(items):
        if not isinstance(it, dict):
            continue
        name = str(it.get("name") or "").strip() or f"Target {idx+1}"
        path_raw = str(it.get("path") or "").strip()
        if not path_raw:
            continue
        p = _backup_target_path(path_raw)
        ok, err = _ensure_dir_writable(p)
        out.append({
            "id": _backup_target_id(name, idx),
            "name": name,
            "path": str(p),
            "available": bool(ok),
            "error": (str(err)[:400] if err else None),
        })

    if not out:
        p = backup_dir(c)
        ok, err = _ensure_dir_writable(p)
        out = [{
            "id": "lokal_0",
            "name": "Lokal",
            "path": str(p),
            "available": bool(ok),
            "error": (str(err)[:400] if err else None),
        }]

    default_id = None
    for t in out:
        if t.get("available"):
            default_id = str(t.get("id") or "") or None
            break
    if default_id is None and out:
        default_id = str(out[0].get("id") or "") or None
    return out, default_id


def backup_dir_for_target(cfg: dict[str, Any], target: str | None) -> Path:
    targets, default_id = backup_targets(cfg)
    want = str(target or "").strip()
    pick = None
    if want:
        for t in targets:
            if want == str(t.get("id") or "") or want == str(t.get("name") or ""):
                pick = t
                break
    if pick is None and default_id:
        for t in targets:
            if default_id == str(t.get("id") or ""):
                pick = t
                break
    if pick is None and targets:
        pick = targets[0]
    p = _backup_target_path(str((pick or {}).get("path") or ""))
    return p


def _undo_mgr(cfg: dict[str, Any]) -> UndoManager:
    """Singleton undo manager (persistent under /config/influxbro/history)."""

    global UNDO_MANAGER
    with UNDO_MANAGER_LOCK:
        if UNDO_MANAGER is None:
            UNDO_MANAGER = UndoManager(UNDO_HISTORY_DIR, max_entries=int(cfg.get("undo_history_max", 100) or 100))
        else:
            try:
                UNDO_MANAGER.set_max_entries(int(cfg.get("undo_history_max", 100) or 100))
            except Exception:
                pass
        return UNDO_MANAGER


def _undo_row_tags(row: dict[str, Any]) -> dict[str, str]:
    tags: dict[str, str] = {}
    for k, v in (row or {}).items():
        if not k or str(k).startswith("_"):
            continue
        if k in ("tags",):
            continue
        if v is None:
            continue
        tags[str(k)] = str(v)
    # allow nested tags dict too
    try:
        t2 = row.get("tags")
        if isinstance(t2, dict):
            for k, v in t2.items():
                if not k or str(k).startswith("_"):
                    continue
                if v is None:
                    continue
                tags[str(k)] = str(v)
    except Exception:
        pass
    return tags
    return target


def _backup_disk_usage_bytes(dir_path: Path) -> dict[str, int] | None:
    """Return disk usage for a backup directory (best-effort)."""

    try:
        dir_path.mkdir(parents=True, exist_ok=True)
        du = shutil.disk_usage(str(dir_path))
        return {"total": int(du.total), "used": int(du.used), "free": int(du.free)}
    except Exception:
        return None


def _addon_data_usage_bytes() -> int | None:
    """Return total bytes used under /data for this add-on (best-effort)."""

    try:
        total = 0
        root = DATA_DIR
        if not root.exists():
            return 0
        for base, _, files in os.walk(str(root)):
            for fn in files:
                try:
                    p = os.path.join(base, fn)
                    total += int(os.path.getsize(p) or 0)
                except Exception:
                    continue
        return int(total)
    except Exception:
        return None


def _backup_require_free_space(cfg: dict[str, Any], dir_path: Path) -> tuple[bool, str | None]:
    """Return (ok, error_message) according to backup_min_free_mb for a target dir."""

    try:
        min_mb = int(cfg.get("backup_min_free_mb", 0) or 0)
    except Exception:
        min_mb = 0
    if min_mb <= 0:
        return True, None

    du = _backup_disk_usage_bytes(dir_path)
    if not du:
        return True, None
    free = int(du.get("free") or 0)
    if free >= min_mb * 1024 * 1024:
        return True, None
    free_mb = int(free / 1024 / 1024)
    return False, f"Nicht genug freier Speicher fuer Backup. Frei: {free_mb} MB; erforderlich: {min_mb} MB"


def _verify_result_path(job_id: str) -> Path:
    return VERIFY_RESULTS_DIR / f"{str(job_id or '').strip()}.json"


def _verify_save_result(job_id: str, payload: dict[str, Any]) -> None:
    VERIFY_RESULTS_DIR.mkdir(parents=True, exist_ok=True)
    _verify_result_path(job_id).write_text(json.dumps(payload, ensure_ascii=True, indent=2, sort_keys=True), encoding="utf-8")


def _verify_load_result(job_id: str) -> dict[str, Any] | None:
    p = _verify_result_path(job_id)
    if not p.exists():
        return None
    try:
        val = json.loads(p.read_text(encoding="utf-8", errors="replace"))
        return val if isinstance(val, dict) else None
    except Exception:
        return None


def _verify_tmp_bucket_name(kind: str) -> str:
    ts = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
    base = "verify_tmp_measurement" if kind == "measurement" else "verify_tmp_full"
    return _backup_safe(f"{base}_{ts}_{uuid.uuid4().hex[:8]}")


def _verify_create_bucket_v2(cfg: dict[str, Any], name: str) -> None:
    with v2_admin_client(cfg, timeout_seconds_override=min(20, int(cfg.get("timeout_seconds") or 10))) as c:
        try:
            orgs = c.organizations_api().find_organizations(org=str(cfg.get("org") or ""))  # type: ignore[attr-defined]
            orgs_list = getattr(orgs, "orgs", None) or []
            org_id = str(getattr(orgs_list[0], "id", "") or "") if orgs_list else ""
        except Exception:
            org_id = ""
        kwargs = {"bucket_name": name, "retention_rules": []}
        if org_id:
            kwargs["org_id"] = org_id
        else:
            kwargs["org"] = str(cfg.get("org") or "")
        c.buckets_api().create_bucket(**kwargs)


def _verify_delete_bucket_v2(cfg: dict[str, Any], name: str) -> bool:
    try:
        with v2_admin_client(cfg, timeout_seconds_override=min(20, int(cfg.get("timeout_seconds") or 10))) as c:
            b = c.buckets_api().find_buckets(org=str(cfg.get("org") or ""))
            buckets = getattr(b, "buckets", None) or []
            for buck in buckets:
                try:
                    if str(getattr(buck, "name", "") or "") == name:
                        c.buckets_api().delete_bucket(buck)
                        return True
                except Exception:
                    continue
    except Exception:
        return False
    return False


def _verify_storage_precheck(cfg: dict[str, Any], dir_path: Path) -> tuple[bool, str | None]:
    ok, msg = _backup_require_free_space(cfg, dir_path)
    if not ok:
        return ok, msg
    return True, None


def _verify_write_lp_to_bucket_v2(cfg: dict[str, Any], verify_bucket: str, lines: Iterable[str]) -> int:
    count = 0
    with v2_client(cfg) as c:
        wapi = c.write_api(write_options=SYNCHRONOUS)
        manager = InfluxWriteManager(wapi, cfg, bucket=verify_bucket, org=str(cfg.get("org") or ""), operation="verify_write", write_precision=WritePrecision.NS, batch_size=2000)
        for raw in lines:
            pts = _lp_parse_points_from_line(raw)
            if not pts:
                continue
            for p in pts:
                ts = str(p.get("_time") or "").strip()
                meas = str(p.get("_measurement") or "").strip()
                fld = str(p.get("_field") or "").strip()
                if not ts or not meas or not fld:
                    continue
                val = p.get("_value")
                if val is None:
                    continue
                dt = _parse_iso_datetime(ts)
                if not dt:
                    continue
                pt = Point(meas)
                for k, v in p.items():
                    if not k or str(k).startswith("_") or v is None:
                        continue
                    pt = pt.tag(str(k), str(v))
                pt = pt.field(fld, val).time(dt, WritePrecision.NS)
                manager.add_record(pt, 1)
                count += 1
        manager.finish()
    return count


def _verify_measurement_compare_v2(cfg: dict[str, Any], *, source_bucket: str, verify_bucket: str, measurement: str, field: str, entity_id: str | None, friendly_name: str | None, start_dt: datetime | None, stop_dt: datetime | None) -> dict[str, Any]:
    selector_range = _selector_range_key("custom" if start_dt and stop_dt else "all", start_dt, stop_dt)
    src = _measurement_profile_influx_v2(cfg, bucket=source_bucket, measurement=measurement, field=field, entity_id=entity_id, friendly_name=friendly_name, selector_range=selector_range, start_dt=start_dt, stop_dt=stop_dt)
    dst = _measurement_profile_influx_v2(cfg, bucket=verify_bucket, measurement=measurement, field=field, entity_id=entity_id, friendly_name=friendly_name, selector_range=selector_range, start_dt=start_dt, stop_dt=stop_dt)
    src_count = int(src.get("count") or 0)
    dst_count = int(dst.get("count") or 0)
    delta = dst_count - src_count
    delta_pct = (abs(delta) / src_count * 100.0) if src_count else (0.0 if dst_count == 0 else 100.0)
    return {
        "selection": {
            "entity_id": entity_id,
            "measurement": measurement,
            "field": field,
            "friendly_name": friendly_name,
            "range": selector_range,
            "start": _dt_to_rfc3339_utc_full(start_dt) if start_dt else None,
            "stop": _dt_to_rfc3339_utc_full(stop_dt) if stop_dt else None,
        },
        "points": {"src": src_count, "dst": dst_count, "delta": delta, "delta_pct": delta_pct},
        "time_ranges": {"src_start": src.get("oldest_time"), "src_stop": src.get("newest_time"), "dst_start": dst.get("oldest_time"), "dst_stop": dst.get("newest_time")},
        "measurements": {"src_count": 1 if src_count else 0, "dst_count": 1 if dst_count else 0, "missing": [measurement] if src_count and not dst_count else [], "additional": []},
        "cardinality": {"src": 1 if src_count else 0, "dst": 1 if dst_count else 0, "drift": bool(src_count != dst_count and delta_pct > 0)},
        "top_series_diff": [],
        "src_profile": src,
        "dst_profile": dst,
    }


def _verify_measurements_for_bucket_v2(cfg: dict[str, Any], bucket: str) -> list[str]:
    q = f'import "influxdata/influxdb/schema"\nschema.measurements(bucket: "{bucket}")'
    out: list[str] = []
    with v2_client(cfg) as c:
        for table in c.query_api().query(q, org=cfg["org"]) or []:
            for rec in getattr(table, "records", []) or []:
                v = str(rec.get_value() or "").strip()
                if v and v not in out:
                    out.append(v)
    return out


def _verify_count_for_measurement_v2(cfg: dict[str, Any], bucket: str, measurement: str) -> dict[str, Any]:
    q = f'''
from(bucket: "{bucket}")
  |> range(start: time(v: "1970-01-01T00:00:00Z"))
  |> filter(fn: (r) => r._measurement == {_flux_str(measurement)})
  |> keep(columns: ["_time", "_value"])
  |> count(column: "_value")
  |> group()
  |> sum(column: "_value")
'''
    count = 0
    with v2_client(cfg) as c:
        for table in c.query_api().query(q, org=cfg["org"]) or []:
            for rec in getattr(table, "records", []) or []:
                try:
                    count = int(rec.get_value() or 0)
                except Exception:
                    pass
                break
    q2 = f'''
from(bucket: "{bucket}")
  |> range(start: time(v: "1970-01-01T00:00:00Z"))
  |> filter(fn: (r) => r._measurement == {_flux_str(measurement)})
  |> keep(columns: ["_time"])
  |> first()
'''
    q3 = f'''
from(bucket: "{bucket}")
  |> range(start: time(v: "1970-01-01T00:00:00Z"))
  |> filter(fn: (r) => r._measurement == {_flux_str(measurement)})
  |> keep(columns: ["_time"])
  |> last()
'''
    start_iso = None
    stop_iso = None
    with v2_client(cfg) as c:
        res1 = c.query_api().query(q2, org=cfg["org"]) or []
        for table in res1:
            for rec in getattr(table, "records", []) or []:
                t = rec.get_time()
                start_iso = _dt_to_rfc3339_utc_ms(t) if isinstance(t, datetime) else t
                break
        res2 = c.query_api().query(q3, org=cfg["org"]) or []
        for table in res2:
            for rec in getattr(table, "records", []) or []:
                t = rec.get_time()
                stop_iso = _dt_to_rfc3339_utc_ms(t) if isinstance(t, datetime) else t
                break
    return {"count": count, "start": start_iso, "stop": stop_iso}


def _verify_full_compare_v2(cfg: dict[str, Any], *, source_bucket: str, verify_bucket: str) -> dict[str, Any]:
    src_ms = _verify_measurements_for_bucket_v2(cfg, source_bucket)
    dst_ms = _verify_measurements_for_bucket_v2(cfg, verify_bucket)
    missing = [m for m in src_ms if m not in dst_ms]
    additional = [m for m in dst_ms if m not in src_ms]
    src_total = 0
    dst_total = 0
    top: list[dict[str, Any]] = []
    src_ranges: dict[str, Any] = {}
    dst_ranges: dict[str, Any] = {}
    for m in src_ms[:200]:
        s = _verify_count_for_measurement_v2(cfg, source_bucket, m)
        d = _verify_count_for_measurement_v2(cfg, verify_bucket, m)
        src_total += int(s.get("count") or 0)
        dst_total += int(d.get("count") or 0)
        src_ranges[m] = {"start": s.get("start"), "stop": s.get("stop")}
        dst_ranges[m] = {"start": d.get("start"), "stop": d.get("stop")}
        if int(s.get("count") or 0) != int(d.get("count") or 0):
            delta = int(d.get("count") or 0) - int(s.get("count") or 0)
            pct = (abs(delta) / int(s.get("count") or 1) * 100.0) if int(s.get("count") or 0) else 100.0
            top.append({"series": m, "src": int(s.get("count") or 0), "dst": int(d.get("count") or 0), "delta": delta, "delta_pct": pct})
    delta = dst_total - src_total
    delta_pct = (abs(delta) / src_total * 100.0) if src_total else (0.0 if dst_total == 0 else 100.0)
    return {
        "points": {"src": src_total, "dst": dst_total, "delta": delta, "delta_pct": delta_pct},
        "measurements": {"src_count": len(src_ms), "dst_count": len(dst_ms), "missing": missing, "additional": additional},
        "time_ranges": {"src": src_ranges, "dst": dst_ranges},
        "cardinality": {"src": len(src_ms), "dst": len(dst_ms), "drift": bool(missing or additional)},
        "top_series_diff": top[:20],
    }


