def _measurement_profile_build(
    cfg: dict[str, Any],
    *,
    entity_id: str,
    measurement: str,
    field: str,
    friendly_name: str | None,
    bucket: str,
    body: dict[str, Any],
) -> dict[str, Any]:
    selector_range, start_dt, stop_dt = _measurement_profile_range(cfg, body)
    ha = _measurement_profile_ha(entity_id)
    yaml_info = _measurement_profile_yaml_search(entity_id, ha.get("friendly_name"), ha.get("unique_id"))
    references = _measurement_profile_references(entity_id, ha.get("friendly_name"), measurement, ha.get("unique_id"))
    if int(cfg.get("influx_version", 2) or 2) == 2:
        influx = _measurement_profile_influx_v2(
            cfg,
            bucket=bucket,
            measurement=measurement,
            field=field,
            entity_id=entity_id,
            friendly_name=friendly_name,
            selector_range=selector_range,
            start_dt=start_dt,
            stop_dt=stop_dt,
        )
    else:
        influx = _measurement_profile_influx_v1(
            cfg,
            measurement=measurement,
            field=field,
            entity_id=entity_id,
            friendly_name=friendly_name,
            selector_range=selector_range,
            start_dt=start_dt,
            stop_dt=stop_dt,
        )
    derived = _measurement_profile_derived(ha, influx, yaml_info)
    quality = _measurement_profile_quality(ha, yaml_info, influx, derived)
    return {
        "entity_id": entity_id,
        "ha": ha,
        "yaml": yaml_info,
        "references": references,
        "influx": influx,
        "derived": derived,
        "quality": quality,
    }


def _outlier_strategy_default_store() -> dict[str, Any]:
    return {"strategies": [], "overrides": {}}


def _outlier_strategy_load_store() -> dict[str, Any]:
    try:
        if not OUTLIER_STRATEGY_PATH.exists():
            return _outlier_strategy_default_store()
        with OUTLIER_STRATEGY_LOCK:
            raw = OUTLIER_STRATEGY_PATH.read_text(encoding="utf-8", errors="replace")
        data = json.loads(raw) if raw else {}
        if not isinstance(data, dict):
            return _outlier_strategy_default_store()
        out = _outlier_strategy_default_store()
        out["strategies"] = data.get("strategies") if isinstance(data.get("strategies"), list) else []
        out["overrides"] = data.get("overrides") if isinstance(data.get("overrides"), dict) else {}
        return out
    except Exception:
        return _outlier_strategy_default_store()


def _outlier_strategy_save_store(store: dict[str, Any]) -> None:
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    with OUTLIER_STRATEGY_LOCK:
        OUTLIER_STRATEGY_PATH.write_text(json.dumps(store or _outlier_strategy_default_store(), indent=2, sort_keys=True, ensure_ascii=True), encoding="utf-8")


def _outlier_strategy_types_norm(values: Any) -> list[str]:
    xs = values if isinstance(values, list) else []
    out: list[str] = []
    for v in xs:
        s = _outlier_type_to_new(v)
        if s and s in OUTLIER_STRATEGY_ALLOWED_TYPES and s not in out:
            out.append(s)
    return out


def _outlier_strategy_mode_norm(value: Any) -> str:
    mode = str(value or "auto").strip().lower() or "auto"
    return mode if mode in OUTLIER_STRATEGY_MODES else "auto"


def _outlier_strategy_params_norm(raw: Any) -> dict[str, dict[str, Any]]:
    src = raw if isinstance(raw, dict) else {}
    out: dict[str, dict[str, Any]] = {}
    for key, value in src.items():
        t = _outlier_type_to_new(key)
        if t not in OUTLIER_STRATEGY_ALLOWED_TYPES:
            continue
        if not isinstance(value, dict):
            continue
        out[t] = dict(value)
    return out


def _outlier_strategy_corrections_norm(raw: Any) -> dict[str, dict[str, Any]]:
    return _outlier_strategy_params_norm(raw)


def _outlier_strategy_match_norm(match: Any) -> dict[str, Any]:
    m = match if isinstance(match, dict) else {}
    return {
        "internal_types": [str(x or "").strip() for x in (m.get("internal_types") if isinstance(m.get("internal_types"), list) else []) if str(x or "").strip()],
        "device_classes": [str(x or "").strip() for x in (m.get("device_classes") if isinstance(m.get("device_classes"), list) else []) if str(x or "").strip()],
        "state_classes": [str(x or "").strip() for x in (m.get("state_classes") if isinstance(m.get("state_classes"), list) else []) if str(x or "").strip()],
        "field_types": [str(x or "").strip() for x in (m.get("field_types") if isinstance(m.get("field_types"), list) else []) if str(x or "").strip()],
        "units": [str(x or "").strip() for x in (m.get("units") if isinstance(m.get("units"), list) else []) if str(x or "").strip()],
        "domains": [str(x or "").strip() for x in (m.get("domains") if isinstance(m.get("domains"), list) else []) if str(x or "").strip()],
        "measurements": [str(x or "").strip() for x in (m.get("measurements") if isinstance(m.get("measurements"), list) else []) if str(x or "").strip()],
        "fields": [str(x or "").strip() for x in (m.get("fields") if isinstance(m.get("fields"), list) else []) if str(x or "").strip()],
        "entity_id_regex": str(m.get("entity_id_regex") or "").strip() or None,
    }


def _outlier_strategy_normalize_item(item: dict[str, Any]) -> dict[str, Any]:
    sid = str(item.get("id") or "").strip()
    if not sid:
        raise ValueError("strategy id required")
    try:
        priority = int(item.get("priority") or 0)
    except Exception:
        priority = 0
    match = _outlier_strategy_match_norm(item.get("match"))
    enable_types = _outlier_strategy_types_norm(item.get("enable_types"))
    disable_types = _outlier_strategy_types_norm(item.get("disable_types"))
    if set(enable_types) & set(disable_types):
        raise ValueError(f"strategy {sid} enables and disables the same type")
    return {
        "id": sid,
        "name": str(item.get("name") or sid).strip() or sid,
        "description": str(item.get("description") or "").strip(),
        "priority": priority,
        "match": match,
        "enable_types": enable_types,
        "disable_types": disable_types,
        "params": _outlier_strategy_params_norm(item.get("params")),
        "corrections": _outlier_strategy_corrections_norm(item.get("corrections")),
    }


def _outlier_strategy_measurement_key(entity_id: str, measurement: str, field: str) -> str:
    return "|".join([str(entity_id or "").strip(), str(measurement or "").strip(), str(field or "").strip()])


def _outlier_strategy_match_profile(strategy: dict[str, Any], profile: dict[str, Any]) -> tuple[bool, int, list[str]]:
    match = _outlier_strategy_match_norm(strategy.get("match"))
    derived = profile.get("derived") if isinstance(profile.get("derived"), dict) else {}
    ha = profile.get("ha") if isinstance(profile.get("ha"), dict) else {}
    influx = profile.get("influx") if isinstance(profile.get("influx"), dict) else {}
    entity_id = str(profile.get("entity_id") or "")
    checks = [
        ("internal_types", str(derived.get("internal_type") or ""), "internal_type"),
        ("device_classes", str(ha.get("device_class") or ""), "device_class"),
        ("state_classes", str(ha.get("state_class") or ""), "state_class"),
        ("field_types", str(influx.get("field_type") or ""), "field_type"),
        ("units", str(ha.get("unit_of_measurement") or ""), "unit"),
        ("domains", str(ha.get("domain") or ""), "domain"),
        ("measurements", str(influx.get("measurement") or ""), "measurement"),
        ("fields", str(influx.get("field") or ""), "field"),
    ]
    reasons: list[str] = []
    specificity = 0
    for key, actual, label in checks:
        expected = match.get(key) if isinstance(match.get(key), list) else []
        if not expected:
            continue
        specificity += 1
        if actual not in expected:
            return False, specificity, []
        reasons.append(f"{label}={actual}")
    regex = match.get("entity_id_regex")
    if regex:
        specificity += 1
        try:
            if not re.search(str(regex), entity_id):
                return False, specificity, []
            reasons.append(f"entity_id_regex={regex}")
        except re.error:
            return False, specificity, []
    return True, specificity, reasons


def _outlier_strategy_pick(profile: dict[str, Any], custom_strategies: list[dict[str, Any]]) -> dict[str, Any]:
    candidates = [*OUTLIER_STRATEGY_BUILTINS, *custom_strategies]
    matches: list[tuple[dict[str, Any], int, list[str]]] = []
    for st in candidates:
        ok, spec, reasons = _outlier_strategy_match_profile(st, profile)
        if ok:
            matches.append((st, spec, reasons))
    if not matches:
        fallback = {
            "id": "builtin.fallback",
            "name": "Fallback",
            "description": "Konservative Standardstrategie bei unklarer Klassifikation.",
            "priority": -1,
            "enable_types": ["range_violation", "time_gap", "null_value"],
            "disable_types": ["rate_jump", "reset_event", "negative_jump", "fault_cluster", "zero_value"],
            "match": {},
        }
        return {"selected": fallback, "reason_log": ["fallback_strategy"], "matched": []}
    matches.sort(key=lambda item: (-int(item[0].get("priority") or 0), -item[1], str(item[0].get("id") or "")))
    selected, _spec, reasons = matches[0]
    reason_log = [f"strategy={selected.get('id')}", *reasons]
    if len(matches) > 1:
        reason_log.append("multiple_matches_resolved_by_priority")
    return {
        "selected": selected,
        "reason_log": reason_log,
        "matched": [{"id": st.get("id"), "priority": st.get("priority"), "specificity": spec} for st, spec, _ in matches],
    }


def _outlier_strategy_effective(profile: dict[str, Any], strategy: dict[str, Any], override: dict[str, Any]) -> dict[str, Any]:
    order = [t for t in OUTLIER_STRATEGY_ALLOWED_TYPES if t != "ignored"]
    recommended_selected = [t for t in order if t in _outlier_strategy_types_norm(strategy.get("enable_types")) and t not in _outlier_strategy_types_norm(strategy.get("disable_types"))]
    recommended_unselected = [t for t in order if t not in recommended_selected]
    mode = _outlier_strategy_mode_norm(override.get("mode"))
    manual_enable = _outlier_strategy_types_norm(override.get("manual_enable_types"))
    manual_disable = _outlier_strategy_types_norm(override.get("manual_disable_types"))
    if mode == "all_on":
        effective = order[:]
    elif mode == "all_off":
        effective = []
    else:
        effective = []
        for t in order:
            active = t in recommended_selected
            if t in manual_enable:
                active = True
            if t in manual_disable:
                active = False
            if active:
                effective.append(t)
    effective_unselected = [t for t in order if t not in effective]
    strategy_params = _outlier_strategy_params_norm(strategy.get("params"))
    strategy_corrections = _outlier_strategy_corrections_norm(strategy.get("corrections"))
    param_overrides = _outlier_strategy_params_norm(override.get("param_overrides"))
    correction_overrides = _outlier_strategy_corrections_norm(override.get("correction_overrides"))
    effective_params = {t: dict(strategy_params.get(t) or {}) for t in effective}
    effective_corrections = {t: dict(strategy_corrections.get(t) or {}) for t in effective}
    for t in effective:
        effective_params[t].update(param_overrides.get(t) or {})
        effective_corrections[t].update(correction_overrides.get(t) or {})
    return {
        "mode": mode,
        "recommended_selected": recommended_selected,
        "recommended_unselected": recommended_unselected,
        "manual_enable_types": manual_enable,
        "manual_disable_types": manual_disable,
        "effective_selected": effective,
        "effective_unselected": effective_unselected,
        "param_overrides": param_overrides,
        "correction_overrides": correction_overrides,
        "effective_params": effective_params,
        "effective_corrections": effective_corrections,
    }


@app.get("/api/outlier_strategy")
def api_outlier_strategy_get():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    entity_id = str(request.args.get("entity_id") or "").strip()
    measurement = str(request.args.get("measurement") or "").strip()
    field = str(request.args.get("field") or "").strip() or "value"
    friendly_name = str(request.args.get("friendly_name") or "").strip() or None
    bucket = str(request.args.get("bucket") or cfg.get("bucket") or cfg.get("database") or "").strip()
    if not entity_id or not measurement or not field:
        return jsonify({"ok": False, "error": "entity_id, measurement and field required"}), 400
    body = {"range": request.args.get("range"), "start": request.args.get("start"), "stop": request.args.get("stop")}
    try:
        profile = _measurement_profile_build(
            cfg,
            entity_id=entity_id,
            measurement=measurement,
            field=field,
            friendly_name=friendly_name,
            bucket=bucket,
            body=body,
        )
    except Exception as e:
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500
    store = _outlier_strategy_load_store()
    custom_strategies = []
    seen: set[str] = set()
    for item in store.get("strategies") if isinstance(store.get("strategies"), list) else []:
        if not isinstance(item, dict):
            continue
        try:
            st = _outlier_strategy_normalize_item(item)
        except Exception:
            continue
        if st["id"] in seen:
            continue
        seen.add(st["id"])
        custom_strategies.append(st)
    picked = _outlier_strategy_pick(profile, custom_strategies)
    key = _outlier_strategy_measurement_key(entity_id, measurement, field)
    overrides = store.get("overrides") if isinstance(store.get("overrides"), dict) else {}
    override = overrides.get(key) if isinstance(overrides.get(key), dict) else {}
    eff = _outlier_strategy_effective(profile, picked["selected"], override)
    return jsonify({
        "ok": True,
        "profile": profile,
        "strategy": picked["selected"],
        "matched": picked["matched"],
        "reason_log": picked["reason_log"],
        "available_types": OUTLIER_STRATEGY_ALLOWED_TYPES,
        "type_definitions": OUTLIER_STRATEGY_TYPE_DEFS,
        "custom_strategies": custom_strategies,
        **eff,
    })


@app.post("/api/outlier_strategy/override")
def api_outlier_strategy_override_set():
    body = request.get_json(force=True) or {}
    entity_id = str(body.get("entity_id") or "").strip()
    measurement = str(body.get("measurement") or "").strip()
    field = str(body.get("field") or "").strip() or "value"
    if not entity_id or not measurement or not field:
        return jsonify({"ok": False, "error": "entity_id, measurement and field required"}), 400
    key = _outlier_strategy_measurement_key(entity_id, measurement, field)
    mode = _outlier_strategy_mode_norm(body.get("mode"))
    manual_enable = _outlier_strategy_types_norm(body.get("manual_enable_types"))
    manual_disable = _outlier_strategy_types_norm(body.get("manual_disable_types"))
    if set(manual_enable) & set(manual_disable):
        return jsonify({"ok": False, "error": "manual enable/disable overlap"}), 400
    param_overrides = _outlier_strategy_params_norm(body.get("param_overrides"))
    correction_overrides = _outlier_strategy_corrections_norm(body.get("correction_overrides"))
    store = _outlier_strategy_load_store()
    overrides = store.get("overrides") if isinstance(store.get("overrides"), dict) else {}
    if mode == "auto" and not manual_enable and not manual_disable and not param_overrides and not correction_overrides:
        overrides.pop(key, None)
    else:
        overrides[key] = {
            "mode": mode,
            "manual_enable_types": manual_enable if mode == "manual" else [],
            "manual_disable_types": manual_disable if mode == "manual" else [],
            "param_overrides": param_overrides,
            "correction_overrides": correction_overrides,
            "updated_at": _utc_now_iso_ms(),
        }
    store["overrides"] = overrides
    _outlier_strategy_save_store(store)
    return jsonify({"ok": True, "override": overrides.get(key) if key in overrides else {"mode": "auto", "manual_enable_types": [], "manual_disable_types": [], "param_overrides": {}, "correction_overrides": {}}})


@app.get("/api/outlier_strategy/config")
def api_outlier_strategy_config_get():
    store = _outlier_strategy_load_store()
    custom_strategies = []
    for item in store.get("strategies") if isinstance(store.get("strategies"), list) else []:
        if not isinstance(item, dict):
            continue
        try:
            custom_strategies.append(_outlier_strategy_normalize_item(item))
        except Exception:
            continue
    return jsonify({"ok": True, "available_types": OUTLIER_STRATEGY_ALLOWED_TYPES, "type_definitions": OUTLIER_STRATEGY_TYPE_DEFS, "builtin_strategies": OUTLIER_STRATEGY_BUILTINS, "custom_strategies": custom_strategies})


@app.post("/api/outlier_strategy/config")
def api_outlier_strategy_config_set():
    body = request.get_json(force=True) or {}
    raw = body.get("custom_strategies") if isinstance(body.get("custom_strategies"), list) else []
    seen: set[str] = set()
    xs: list[dict[str, Any]] = []
    for item in raw:
        if not isinstance(item, dict):
            continue
        st = _outlier_strategy_normalize_item(item)
        if st["id"] in seen:
            return jsonify({"ok": False, "error": f"duplicate strategy id: {st['id']}"}), 400
        seen.add(st["id"])
        xs.append(st)
    store = _outlier_strategy_load_store()
    store["strategies"] = xs
    _outlier_strategy_save_store(store)
    return jsonify({"ok": True, "custom_strategies": xs})


@app.get("/api/measurement_profile")
def api_measurement_profile():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    entity_id = str(request.args.get("entity_id") or "").strip()
    measurement = str(request.args.get("measurement") or "").strip()
    field = str(request.args.get("field") or "").strip() or "value"
    friendly_name = str(request.args.get("friendly_name") or "").strip() or None
    bucket = str(request.args.get("bucket") or cfg.get("bucket") or cfg.get("database") or "").strip()
    if not entity_id or not measurement or not field or not bucket:
        return jsonify({"ok": False, "error": "entity_id, measurement, field and bucket required"}), 400

    body = {
        "range": request.args.get("range"),
        "start": request.args.get("start"),
        "stop": request.args.get("stop"),
    }
    selector_range, start_dt, stop_dt = _measurement_profile_range(cfg, body)

    ha = _measurement_profile_ha(entity_id)
    yaml_info = _measurement_profile_yaml_search(entity_id, ha.get("friendly_name"), ha.get("unique_id"))
    try:
        if int(cfg.get("influx_version", 2) or 2) == 2:
            influx = _measurement_profile_influx_v2(
                cfg,
                bucket=bucket,
                measurement=measurement,
                field=field,
                entity_id=entity_id,
                friendly_name=friendly_name,
                selector_range=selector_range,
                start_dt=start_dt,
                stop_dt=stop_dt,
            )
        else:
            influx = _measurement_profile_influx_v1(
                cfg,
                measurement=measurement,
                field=field,
                entity_id=entity_id,
                friendly_name=friendly_name,
                selector_range=selector_range,
                start_dt=start_dt,
                stop_dt=stop_dt,
            )
    except Exception as e:
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500
    derived = _measurement_profile_derived(ha, influx, yaml_info)
    quality = _measurement_profile_quality(ha, yaml_info, influx, derived)
    references = _measurement_profile_references(entity_id, ha.get("friendly_name"), measurement, ha.get("unique_id"))
    return jsonify(
        {
            "ok": True,
            "entity_id": entity_id,
            "ha": ha,
            "yaml": yaml_info,
            "references": references,
            "influx": influx,
            "derived": derived,
            "quality": quality,
        }
    )


@app.get("/api/ha_debug")
def api_ha_debug():
    """Small diagnostics for HA connectivity.

    Does not expose the Supervisor token.
    """

    token_present = bool((os.environ.get("SUPERVISOR_TOKEN") or "").strip())
    out: dict[str, Any] = {
        "ok": True,
        "token_present": token_present,
        "supervisor_core_api": {"ok": False, "status": None, "error": None},
    }

    if not token_present:
        out["supervisor_core_api"]["error"] = "SUPERVISOR_TOKEN not set"
        return jsonify(out)

    token = (os.environ.get("SUPERVISOR_TOKEN") or "").strip()
    try:
        url = "http://supervisor/core/api/"
        req = urllib.request.Request(url, headers={"Authorization": f"Bearer {token}"}, method="GET")
        with urllib.request.urlopen(req, timeout=5) as resp:
            out["supervisor_core_api"]["ok"] = True
            out["supervisor_core_api"]["status"] = getattr(resp, "status", 200)
    except urllib.error.HTTPError as e:
        out["supervisor_core_api"]["status"] = e.code
        out["supervisor_core_api"]["error"] = f"HTTP {e.code} {getattr(e, 'reason', '')}".strip()
    except Exception as e:
        out["supervisor_core_api"]["error"] = str(e) or e.__class__.__name__

    return jsonify(out)


@app.get("/api/logs")
def api_logs():
    """Fetch InfluxBro add-on logs via Supervisor."""

    def _unwrap(txt: str) -> str:
        raw = (txt or "").strip()
        if not raw:
            return ""
        if not (raw.startswith("{") or raw.startswith("[")):
            return txt
        try:
            data = json.loads(raw)
        except Exception:
            return txt
        if isinstance(data, dict):
            d = data.get("data")
            if isinstance(d, str):
                return d
            if isinstance(d, dict):
                for k in ("content", "logs", "result", "stdout", "text"):
                    v = d.get(k)
                    if isinstance(v, str):
                        return v
            # Some endpoints return the body directly
            for k in ("result", "content", "logs", "stdout", "text"):
                v = data.get(k)
                if isinstance(v, str):
                    return v
        return txt

    def _short_err_body(txt: str) -> str:
        t = (txt or "").strip().replace("\n", " ")
        return (t[:240] + "...") if len(t) > 240 else t

    def _extract_slug(txt: str) -> str | None:
        raw = _unwrap(txt)
        try:
            data = json.loads(raw) if raw else {}
        except Exception:
            return None
        if not isinstance(data, dict):
            return None
        d = data.get("data") if "data" in data else data
        if not isinstance(d, dict):
            return None
        for k in ("slug", "addon", "add_on", "addon_slug"):
            v = d.get(k)
            if isinstance(v, str) and v.strip():
                return v.strip()
        return None

    try:
        tail = int(request.args.get("tail", "2000"))
    except Exception:
        tail = 2000
    if tail < 0:
        tail = 0
    if tail > 20000:
        tail = 20000

    sup_lines = min(max(tail, 0), 5000)
    q = f"?lines={sup_lines}" if sup_lines else ""
    # Try self first. Some Supervisor versions return 500 for self/logs; fall back to explicit slug.
    candidates = [
        "/addons/self/logs" + q,
        "/addons/self/logs",
    ]

    status = 0
    txt = ""
    used = ""
    for p in candidates:
        st, out = _supervisor_get(p, timeout_s=10)
        if st == 200 and out:
            status, txt, used = st, out, p
            break
        status, txt, used = st, out, p

    if status == 500:
        # Try to resolve slug and re-run logs with explicit addon id.
        st_info, info_txt = _supervisor_get("/addons/self/info", timeout_s=8)
        if st_info == 200 and info_txt:
            slug = _extract_slug(info_txt)
            if slug:
                for p in (f"/addons/{slug}/logs" + q, f"/addons/{slug}/logs"):
                    st, out = _supervisor_get(p, timeout_s=10)
                    if st == 200 and out:
                        status, txt, used = st, out, p
                        break
                    status, txt, used = st, out, p

    if status != 200:
        msg = _short_err_body(txt)
        return jsonify({
            "ok": False,
            "error": f"Logs not available: HTTP {status} ({used}) {msg}".strip(),
        }), 502

    txt = _unwrap(txt)
    lines = (txt or "").splitlines()
    if tail and len(lines) > tail:
        lines = lines[-tail:]
    return jsonify({"ok": True, "text": "\n".join(lines)})


@app.get("/api/logfile")
def api_logfile():
    """Fetch InfluxBro logfile from /data (rotating)."""

    try:
        tail = int(request.args.get("tail", "2000"))
    except Exception:
        tail = 2000
    if tail < 0:
        tail = 0
    if tail > 20000:
        tail = 20000

    try:
        if not LOG_FILE.exists():
            return jsonify({"ok": True, "text": ""})
        txt = LOG_FILE.read_text(encoding="utf-8", errors="replace")
    except Exception as e:
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 500

    lines = (txt or "").splitlines()
    if tail and len(lines) > tail:
        lines = lines[-tail:]
    return jsonify({"ok": True, "text": "\n".join(lines)})


@app.get("/api/log_excerpt")
def api_log_excerpt():
    """Return a best-effort excerpt of recent log lines.

    This is used by the UI error popup to show a quick context snippet.
    """

    try:
        minutes = int(request.args.get("minutes", "5"))
    except Exception:
        minutes = 5
    minutes = min(120, max(1, minutes))

    # Read a bounded tail; RotatingFileHandler caps file size anyway.
    try:
        tail = int(request.args.get("tail", "8000"))
    except Exception:
        tail = 8000
    tail = min(20000, max(200, tail))

    try:
        if not LOG_FILE.exists():
            return jsonify({"ok": True, "text": ""})
        txt = LOG_FILE.read_text(encoding="utf-8", errors="replace")
    except Exception as e:
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 500

    lines = (txt or "").splitlines()
    if tail and len(lines) > tail:
        lines = lines[-tail:]

    cutoff = datetime.now() - timedelta(minutes=minutes)

    # logging.Formatter default asctime: "YYYY-MM-DD HH:MM:SS,mmm"
    ts_re = re.compile(r"^(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})(?:,(\d{3}))?\s")

    def _parse_dt(line: str) -> datetime | None:
        m = ts_re.match(line or "")
        if not m:
            return None
        base = m.group(1)
        ms = m.group(2)
        try:
            dt = datetime.strptime(base, "%Y-%m-%d %H:%M:%S")
            if ms and ms.isdigit():
                dt = dt.replace(microsecond=int(ms) * 1000)
            return dt
        except Exception:
            return None

    # Walk from bottom to find the earliest included timestamped line.
    start_idx = 0
    found = False
    for i in range(len(lines) - 1, -1, -1):
        dt = _parse_dt(lines[i])
        if dt is None:
            continue
        if dt >= cutoff:
            start_idx = i
            found = True
            continue
        # first older timestamp => stop
        if found:
            start_idx = i + 1
        break

    out = lines[start_idx:] if lines else []
    return jsonify({"ok": True, "text": "\n".join(out), "minutes": minutes})


@app.get("/api/logs_diag")
def api_logs_diag():
    """Diagnostics for Supervisor logs access.

    Helps debug 403/404 by listing candidate paths and status codes.
    Does not expose the Supervisor token.
    """

    def _unwrap(txt: str) -> str:
        raw = (txt or "").strip()
        if not raw:
            return ""
        if not (raw.startswith("{") or raw.startswith("[")):
            return txt
        try:
            data = json.loads(raw)
        except Exception:
            return txt
        if isinstance(data, dict):
            d = data.get("data")
            if isinstance(d, str):
                return d
            if isinstance(d, dict):
                for k in ("content", "logs", "result", "stdout", "text"):
                    v = d.get(k)
                    if isinstance(v, str):
                        return v
            for k in ("result", "content", "logs", "stdout", "text"):
                v = data.get(k)
                if isinstance(v, str):
                    return v
        return txt

    def _snip(s: str, n: int = 200) -> str:
        t = (s or "").replace("\r", "").strip()
        t = t.replace("\n", " ")
        return (t[:n] + "...") if len(t) > n else t

    def _extract_slug(txt: str) -> str | None:
        raw = _unwrap(txt)
        try:
            data = json.loads(raw) if raw else {}
        except Exception:
            return None
        if not isinstance(data, dict):
            return None
        d = data.get("data") if "data" in data else data
        if not isinstance(d, dict):
            return None
        for k in ("slug", "addon", "add_on", "addon_slug"):
            v = d.get(k)
            if isinstance(v, str) and v.strip():
                return v.strip()
        return None

    token_present = bool(_supervisor_token())
    try:
        lines = int(request.args.get("lines", "80"))
    except Exception:
        lines = 80
    if lines < 0:
        lines = 0
    if lines > 500:
        lines = 500

    q = f"?lines={lines}" if lines else ""
    candidates = [
        "/addons/self/logs" + q,
        "/addons/self/logs",
    ]

    slug: str | None = None
    st_info, info_txt = _supervisor_get("/addons/self/info", timeout_s=8)
    if st_info == 200 and info_txt:
        slug = _extract_slug(info_txt)
        if slug:
            candidates.extend([
                f"/addons/{slug}/logs" + q,
                f"/addons/{slug}/logs",
            ])

    checks: list[dict[str, Any]] = []
    for p in candidates:
        st, out = _supervisor_get(p, timeout_s=8)
        checks.append({
            "path": p,
            "status": st,
            "ok": st == 200,
            "body": _snip(out),
            "unwrapped": _snip(_unwrap(out)),
        })

    return jsonify({
        "ok": True,
        "token_present": token_present,
        "self_info": {"status": st_info, "slug": slug, "body": _snip(info_txt)},
        "checks": checks,
    })


def _json_best_effort(txt: str) -> dict[str, Any] | None:
    try:
        data = json.loads(txt) if txt else None
    except Exception:
        return None
    return data if isinstance(data, dict) else None


def _github_repo_base(url: str) -> str:
    """Return https://github.com/<owner>/<repo> from a configured URL (best-effort)."""

    raw = (url or "").strip()
    if not raw:
        return ""
    # Accept URLs like:
    # - https://github.com/owner/repo
    # - https://github.com/owner/repo/tree/main/influxbro
    m = re.search(r"github\.com/([^/]+)/([^/]+)", raw)
    if not m:
        return ""
    owner = (m.group(1) or "").strip()
    repo = (m.group(2) or "").strip()
    # Strip suffixes like .git
    repo = repo[:-4] if repo.lower().endswith(".git") else repo
    if not owner or not repo:
        return ""
    return f"https://github.com/{owner}/{repo}"


