@app.get("/api/fullbackup_download")
def api_fullbackup_download():
    cfg = load_cfg()
    bdir = backup_dir_for_target(cfg, request.args.get("target"))
    backup_id = str(request.args.get("id") or "").strip()
    if not backup_id:
        return jsonify({"ok": False, "error": "id required"}), 400
    if _backup_safe(backup_id) != backup_id:
        return jsonify({"ok": False, "error": "invalid id"}), 400

    meta = _read_backup_meta(bdir, backup_id) or {}
    if str(meta.get("kind") or "") != "db_full":
        return jsonify({"ok": False, "error": "not a fullbackup (kind!=db_full)"}), 400

    # Prefer packed zip on disk
    zpath = _backup_zip_path(bdir, backup_id)
    if zpath.exists() and zpath.is_file():
        return send_file(zpath, as_attachment=True, download_name=zpath.name, mimetype="application/zip")

    # Legacy: zip meta+lp on the fly
    meta_path, lp_path = _fullbackup_files(bdir, backup_id)
    if not meta_path.exists() or not lp_path.exists():
        return jsonify({"ok": False, "error": "backup not found"}), 404

    try:
        buf = io.BytesIO()
        with zipfile.ZipFile(buf, mode="w", compression=zipfile.ZIP_DEFLATED) as z:
            z.write(meta_path, arcname=meta_path.name)
            z.write(lp_path, arcname=lp_path.name)
        buf.seek(0)
        fn = f"{backup_id}.zip"
        return send_file(buf, as_attachment=True, download_name=fn, mimetype="application/zip")
    except Exception as e:
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 500


@app.post("/api/fullbackup_delete")
def api_fullbackup_delete():
    body = request.get_json(force=True) or {}
    backup_id = (body.get("id") or "").strip()
    if not backup_id:
        return jsonify({"ok": False, "error": "id required"}), 400
    if _backup_safe(backup_id) != backup_id:
        return jsonify({"ok": False, "error": "invalid id"}), 400
    cfg = load_cfg()
    bdir = backup_dir_for_target(cfg, body.get("target"))
    bdir.mkdir(parents=True, exist_ok=True)

    meta = _read_backup_meta(bdir, backup_id) or {}
    if str(meta.get("kind") or "") != "db_full":
        return jsonify({"ok": False, "error": "not a fullbackup (kind!=db_full)"}), 400
    zpath = _backup_zip_path(bdir, backup_id)
    meta_path, lp_path = _fullbackup_files(bdir, backup_id)
    removed = 0
    for p in (zpath, meta_path, lp_path):
        try:
            if p.exists():
                p.unlink()
                removed += 1
        except Exception:
            pass
    if removed == 0:
        return jsonify({"ok": False, "error": "backup not found"}), 404
    return jsonify({"ok": True, "message": f"Deleted: {backup_id}"})


@app.post("/api/fullrestore_job/start")
def api_fullrestore_job_start():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}
    confirm = body.get("confirm", False)
    ok_confirm = confirm is True or str(confirm).strip().lower() in ("1", "true", "yes", "on")
    if not ok_confirm:
        return jsonify({"ok": False, "error": "Confirmation required"}), 400

    backup_id = str(body.get("id") or "").strip()
    if not backup_id:
        return jsonify({"ok": False, "error": "id required"}), 400

    influx_v = int(cfg.get("influx_version", 2) or 2)
    if influx_v == 3:
        return jsonify({"ok": False, "error": "fullrestore currently does not support InfluxDB v3"}), 400
    if influx_v == 2:
        if not str(cfg.get("org") or "").strip():
            return jsonify({
                "ok": False,
                "error": "InfluxDB v2 requires org. Bitte in /config YAML einlesen und speichern.",
            }), 400
    elif influx_v == 1:
        return jsonify({
            "ok": False,
            "error": "FullRestore ist nur fuer InfluxDB v2 unterstuetzt (Change-Service).",
        }), 400
    else:
        return jsonify({"ok": False, "error": f"unsupported influx_version: {influx_v}"}), 400

    bdir = backup_dir_for_target(cfg, body.get("target"))
    meta = _read_backup_meta(bdir, backup_id)
    if not meta:
        return jsonify({"ok": False, "error": "backup not found"}), 404
    if str(meta.get("kind") or "") != "db_full":
        return jsonify({"ok": False, "error": "not a fullbackup (kind!=db_full)"}), 400
    try:
        meta_v = int(meta.get("influx_version") or 0)
    except Exception:
        meta_v = 0
    if meta_v and meta_v != influx_v:
        return jsonify({"ok": False, "error": f"backup influx_version mismatch: backup={meta_v} cfg={influx_v}"}), 400
    fmt = str(meta.get("format") or "lp").strip() or "lp"
    if influx_v == 2 and fmt == "native_v2":
        if not _influx_cli_available():
            plat = _ha_platform()
            try:
                LOG.warning("native_cli_missing type=fullrestore platform=%s backup_id=%s", plat, backup_id)
            except Exception:
                pass
            return jsonify({
                "ok": False,
                "error": (
                    "Native FullRestore ist auf dieser Plattform nicht verfuegbar (Influx CLI fehlt). "
                    f"HA Plattform: {plat}."
                ),
            }), 400
        # Native restore uses the Influx CLI and requires an admin token.
        if not str(cfg.get("admin_token") or "").strip():
            return jsonify({"ok": False, "error": "Native restore requires admin_token (Einstellungen)"}), 400
        if meta.get("org") and str(meta.get("org")) != str(cfg.get("org") or ""):
            return jsonify({"ok": False, "error": "backup org mismatch (configure same org for restore)"}), 400
    elif influx_v == 2:
        if not (cfg.get("token") and cfg.get("bucket")):
            return jsonify({
                "ok": False,
                "error": "InfluxDB v2 (Line Protocol) requires token and bucket. Bitte in /config YAML einlesen und speichern.",
            }), 400
        if meta.get("bucket") and str(meta.get("bucket")) != str(cfg.get("bucket") or ""):
            return jsonify({"ok": False, "error": "backup bucket mismatch (configure same bucket for restore)"}), 400
        if meta.get("org") and str(meta.get("org")) != str(cfg.get("org") or ""):
            return jsonify({"ok": False, "error": "backup org mismatch (configure same org for restore)"}), 400
    if influx_v == 1:
        if meta.get("database") and str(meta.get("database")) != str(cfg.get("database") or ""):
            return jsonify({"ok": False, "error": "backup database mismatch (configure same database for restore)"}), 400

    target_bucket = str(body.get("target_bucket") or "").strip() or None
    overwrite = body.get("overwrite", False)
    overwrite_on = overwrite is True or str(overwrite).strip().lower() in ("1", "true", "yes", "on")

    job_id = uuid.uuid4().hex
    ip = _req_ip()
    ua = _req_ua()
    job = {
        "id": job_id,
        "state": "queued",
        "message": "Start...",
        "started_at": datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z"),
        "started_mono": time.monotonic(),
        "trigger_page": "restore",
        "trigger_ip": ip,
        "trigger_ua": ua,
        "backup_id": backup_id,
        "influx_version": influx_v,
        "format": fmt,
        "target_bucket": target_bucket,
        "overwrite": bool(overwrite_on),
        "read_lines": 0,
        "applied": 0,
        "cancelled": False,
        "error": None,
    }
    with FULLRESTORE_LOCK:
        FULLRESTORE_JOBS[job_id] = job
        cutoff = time.monotonic() - 24 * 3600
        old = [k for k, v in FULLRESTORE_JOBS.items() if float(v.get("started_mono") or 0) < cutoff]
        for k in old:
            FULLRESTORE_JOBS.pop(k, None)

    try:
        LOG.info("job_start type=fullrestore job_id=%s ip=%s ua=%s backup_id=%s", job_id, ip, ua, backup_id)
    except Exception:
        pass

    t = threading.Thread(target=_fullrestore_job_thread, args=(job_id, cfg, bdir, backup_id), daemon=True)
    t.start()
    return jsonify({"ok": True, "job_id": job_id})


def _audit_window_value(window_raw: str | None) -> str:
    raw = str(window_raw or "-90d").strip() or "-90d"
    if re.match(r"^-(?:\d+(?:ms|s|m|h|d|w))+$", raw):
        return raw
    raise ValueError("window invalid")


def _audit_tag_key_value(tag_key_raw: str | None) -> str:
    raw = str(tag_key_raw or "entity_id").strip() or "entity_id"
    if re.match(r"^[A-Za-z_][A-Za-z0-9_]*$", raw):
        return raw
    raise ValueError("tag_key invalid")


def _rollup_profile_by_id(cfg: dict[str, Any], profile_id: str) -> dict[str, Any] | None:
    profiles = _rollup_profiles_load(cfg)
    return next((p for p in profiles if isinstance(p, dict) and str(p.get("id") or "") == profile_id), None)


def _audit_pick_latest_backup_run(profile_id: str) -> dict[str, Any] | None:
    for run in _rollup_runs_list(limit=200):
        if not isinstance(run, dict):
            continue
        if str(run.get("profile_id") or "") != profile_id:
            continue
        if str(run.get("backup_id") or "").strip():
            return run
    return None


@app.get("/api/audit")
def api_audit():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    if int(cfg.get("influx_version", 2) or 2) != 2:
        return jsonify({"ok": False, "error": "audit supports InfluxDB v2 only"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({"ok": False, "error": "InfluxDB v2 requires token, org, bucket"}), 400

    profile_id = str(request.args.get("profile_id") or "default").strip() or "default"
    prof = _rollup_profile_by_id(cfg, profile_id)
    if not prof:
        return jsonify({"ok": False, "error": "profile not found"}), 404

    raw_bucket = str(request.args.get("raw_bucket") or prof.get("source_bucket") or "").strip()
    agg_bucket = str(request.args.get("agg_bucket") or request.args.get("longterm_bucket") or prof.get("target_bucket") or "").strip()
    measurement_raw = str(request.args.get("measurement_raw") or "").strip()
    measurement_agg = str(request.args.get("measurement_agg") or measurement_raw).strip()
    field = str(request.args.get("field") or "value").strip() or "value"
    try:
        tag_key = _audit_tag_key_value(request.args.get("tag_key"))
        window = _audit_window_value(request.args.get("window"))
    except ValueError as e:
        return jsonify({"ok": False, "error": str(e)}), 400

    if not raw_bucket or not agg_bucket:
        return jsonify({"ok": False, "error": "raw_bucket and agg_bucket required"}), 400

    latest_run = _audit_pick_latest_backup_run(profile_id)
    backup_meta = None
    if latest_run:
        try:
            backup_meta = _rollup_backup_validate(str(latest_run.get("backup_id") or ""))
        except Exception:
            backup_meta = None

    backup = {
        "exists": bool(backup_meta),
        "backup_id": str((backup_meta or {}).get("backup_id") or (latest_run or {}).get("backup_id") or ""),
        "created_at": str((backup_meta or {}).get("created_at") or (latest_run or {}).get("created_at") or ""),
        "restore_available": bool(backup_meta),
        "profile_id": profile_id,
    }

    counts = {"raw": 0, "agg": 0}
    per_tag_raw: dict[str, int] = {}
    per_tag_agg: dict[str, int] = {}

    q_total_raw = f'''
from(bucket: "{raw_bucket}")
  |> range(start: {window})
  |> filter(fn: (r) => r._field == {_flux_str(field)}{f' and r._measurement == {_flux_str(measurement_raw)}' if measurement_raw else ''})
  |> keep(columns: ["_value"])
  |> count(column: "_value")
  |> group()
  |> sum(column: "_value")
'''
    q_total_agg = f'''
from(bucket: "{agg_bucket}")
  |> range(start: {window})
  |> filter(fn: (r) => r._field == {_flux_str(field)}{f' and r._measurement == {_flux_str(measurement_agg)}' if measurement_agg else ''})
  |> keep(columns: ["_value"])
  |> count(column: "_value")
  |> group()
  |> sum(column: "_value")
'''
    q_per_tag_raw = f'''
from(bucket: "{raw_bucket}")
  |> range(start: {window})
  |> filter(fn: (r) => r._field == {_flux_str(field)}{f' and r._measurement == {_flux_str(measurement_raw)}' if measurement_raw else ''})
  |> filter(fn: (r) => exists r.{tag_key})
  |> group(columns: ["{tag_key}"])
  |> count(column: "_value")
'''
    q_per_tag_agg = f'''
from(bucket: "{agg_bucket}")
  |> range(start: {window})
  |> filter(fn: (r) => r._field == {_flux_str(field)}{f' and r._measurement == {_flux_str(measurement_agg)}' if measurement_agg else ''})
  |> filter(fn: (r) => exists r.{tag_key})
  |> group(columns: ["{tag_key}"])
  |> count(column: "_value")
'''

    try:
        with v2_client(cfg) as c:
            qapi = c.query_api()
            for rec in qapi.query_stream(q_total_raw, org=cfg["org"]):
                try:
                    counts["raw"] += int(rec.get_value() or 0)
                except Exception:
                    continue
            for rec in qapi.query_stream(q_total_agg, org=cfg["org"]):
                try:
                    counts["agg"] += int(rec.get_value() or 0)
                except Exception:
                    continue
            for rec in qapi.query_stream(q_per_tag_raw, org=cfg["org"]):
                key = str((rec.values or {}).get(tag_key) or "").strip()
                if not key:
                    continue
                try:
                    per_tag_raw[key] = per_tag_raw.get(key, 0) + int(rec.get_value() or 0)
                except Exception:
                    continue
            for rec in qapi.query_stream(q_per_tag_agg, org=cfg["org"]):
                key = str((rec.values or {}).get(tag_key) or "").strip()
                if not key:
                    continue
                try:
                    per_tag_agg[key] = per_tag_agg.get(key, 0) + int(rec.get_value() or 0)
                except Exception:
                    continue
    except Exception as e:
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500

    all_keys = sorted(set(per_tag_raw) | set(per_tag_agg))
    per_tag = []
    warnings: list[str] = []
    if counts["agg"] <= 0:
        warnings.append("Keine verdichteten Punkte im Zielbucket gefunden.")
    if not backup["exists"]:
        warnings.append("Kein validiertes Rollup-Backup fuer dieses Profil gefunden.")

    raw_total = int(counts["raw"] or 0)
    agg_total = int(counts["agg"] or 0)
    aggregation_strength = (raw_total / agg_total) if raw_total > 0 and agg_total > 0 else 0.0
    saving_percent = (100.0 * (1.0 - (agg_total / raw_total))) if raw_total > 0 and agg_total >= 0 else 0.0
    if aggregation_strength and aggregation_strength < 1.0:
        warnings.append("Aggregationsfaktor kleiner 1.0 - Rollup reduziert die Daten derzeit nicht.")

    for key in all_keys:
        raw_points = int(per_tag_raw.get(key, 0) or 0)
        agg_points = int(per_tag_agg.get(key, 0) or 0)
        ratio = (raw_points / agg_points) if raw_points > 0 and agg_points > 0 else 0.0
        saved = (100.0 * (1.0 - (agg_points / raw_points))) if raw_points > 0 and agg_points >= 0 else 0.0
        row_warnings: list[str] = []
        if agg_points == 0:
            row_warnings.append("agg_points_zero")
        if ratio and ratio < 1.0:
            row_warnings.append("aggregation_strength_lt_1")
        if not backup["exists"]:
            row_warnings.append("backup_missing")
        if not backup["restore_available"]:
            row_warnings.append("restore_unavailable")
        per_tag.append({
            "tag_key": tag_key,
            "tag_value": key,
            "raw_points": raw_points,
            "agg_points": agg_points,
            "reduction_ratio": ratio,
            "saving_percent": saved,
            "backup_exists": bool(backup["exists"]),
            "restore_available": bool(backup["restore_available"]),
            "warnings": row_warnings,
        })

    per_tag.sort(key=lambda row: (-(float(row.get("saving_percent") or 0.0)), str(row.get("tag_value") or "")))
    return jsonify({
        "ok": True,
        "profile_id": profile_id,
        "raw_bucket": raw_bucket,
        "agg_bucket": agg_bucket,
        "measurement_raw": measurement_raw,
        "measurement_agg": measurement_agg,
        "field": field,
        "window": window,
        "tag_key": tag_key,
        "point_counts": {
            "raw": raw_total,
            "agg": agg_total,
            "aggregation_strength": aggregation_strength,
            "saving_percent": saving_percent,
        },
        "cardinality": {
            "raw": len(per_tag_raw),
            "agg": len(per_tag_agg),
        },
        "backup": backup,
        "per_tag": per_tag,
        "warnings": warnings,
    })


