@app.post("/api/backup_delete")
def api_backup_delete():
    body = request.get_json(force=True) or {}
    backup_id = (body.get("id") or "").strip()
    if not backup_id:
        return jsonify({"ok": False, "error": "id required"}), 400
    if _backup_safe(backup_id) != backup_id:
        return jsonify({"ok": False, "error": "invalid id"}), 400
    cfg = load_cfg()
    bdir = backup_dir_for_target(cfg, body.get("target"))
    bdir.mkdir(parents=True, exist_ok=True)

    meta = _read_backup_meta(bdir, backup_id) or {}
    if str(meta.get("kind") or "") == "db_full":
        return jsonify({"ok": False, "error": "this is a fullbackup; use /api/fullbackup_delete"}), 400

    zpath = _backup_zip_path(bdir, backup_id)
    meta_path, lp_path = _backup_files(bdir, backup_id)
    removed = 0
    for p in (zpath, meta_path, lp_path):
        try:
            if p.exists():
                p.unlink()
                removed += 1
        except Exception:
            pass
    if removed == 0:
        return jsonify({"ok": False, "error": "backup not found"}), 404
    return jsonify({"ok": True, "message": f"Deleted: {backup_id}"})


@app.post("/api/backup_restore")
def api_backup_restore():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}
    confirm = body.get("confirm", False)
    ok_confirm = confirm is True or str(confirm).strip().lower() in ("1", "true", "yes", "on")
    if not ok_confirm:
        return jsonify({"ok": False, "error": "Confirmation required"}), 400

    backup_id = (body.get("id") or "").strip()
    if not backup_id:
        return jsonify({"ok": False, "error": "id required"}), 400
    if _backup_safe(backup_id) != backup_id:
        return jsonify({"ok": False, "error": "invalid id"}), 400

    if int(cfg.get("influx_version", 2)) != 2:
        return jsonify({"ok": False, "error": "restore currently supports InfluxDB v2 only"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({
            "ok": False,
            "error": "InfluxDB v2 requires token, org, bucket. Bitte in /config YAML einlesen und speichern.",
        }), 400

    bdir = backup_dir_for_target(cfg, body.get("target"))
    meta = _read_backup_meta(bdir, backup_id) or {}
    if str(meta.get("kind") or "") == "db_full":
        return jsonify({"ok": False, "error": "this is a fullbackup; use /api/fullrestore_job/start"}), 400

    # Preflight: ensure the payload exists and is readable.
    zpath = _backup_zip_path(bdir, backup_id)
    if zpath.exists():
        try:
            with zipfile.ZipFile(zpath, mode="r") as z:
                bad = z.testzip()
                if bad:
                    return jsonify({"ok": False, "error": f"backup corrupt (zip): {bad}"}), 400
        except Exception as e:
            return jsonify({"ok": False, "error": f"backup corrupt (zip): {_short_influx_error(e)}"}), 400
    try:
        with _open_backup_lp_text(bdir, backup_id, is_fullbackup=False):
            pass
    except Exception:
        return jsonify({"ok": False, "error": "backup not found"}), 404

    try:
        parent_id = uuid.uuid4().hex
        parent = {
            "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
            "block_id": parent_id,
            "created_at": _utc_now_iso_ms(),
            "source": {
                "user_id": None,
                "ip": _req_ip(),
                "ua": _req_ua(),
                "trigger_page": "backups",
                "trigger_source": "backup_restore",
                "trigger_action": "restore",
                "trigger_button": None,
            },
            "operation_source": "backup_restore",
            "reason": f"backup_restore:{backup_id}",
            "status": "created",
            "undo_status": "not_run",
            "repeat_status": "not_run",
            "affected_count": 0,
            "payload_mode": "inline",
            "payload_inline": [],
            "series_summary": {
                "measurement": str(meta.get("measurement") or ""),
                "field": str(meta.get("field") or ""),
                "entity_id": meta.get("entity_id"),
                "friendly_name": meta.get("friendly_name"),
            },
            "meta": {
                "backup_id": backup_id,
                "target": body.get("target"),
                "child_blocks": [],
                "undo_supported": False,
            },
        }
        save_change_block(parent, items=[])

        child_ids: list[str] = []
        child_items: list[dict[str, Any]] = []
        chunk_idx = 0
        applied = 0
        skipped = 0

        def flush_child() -> None:
            nonlocal chunk_idx, child_items, applied
            if not child_items:
                return
            cid = uuid.uuid4().hex
            cb = {
                "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
                "block_id": cid,
                "created_at": _utc_now_iso_ms(),
                "source": parent["source"],
                "operation_source": "backup_restore",
                "reason": f"backup_restore:{backup_id}#{chunk_idx}",
                "status": "created",
                "undo_status": "not_run",
                "repeat_status": "not_run",
                "affected_count": len(child_items),
                "series_summary": parent.get("series_summary") or {},
                "meta": {
                    "parent_block_id": parent_id,
                    "chunk_index": chunk_idx,
                    "undo_supported": False,
                },
            }
            save_change_block(cb, items=child_items)
            out = execute_change_block(cid)
            if not out.get("ok"):
                raise RuntimeError("restore conflict")
            try:
                applied += int(out.get("applied") or 0)
            except Exception:
                pass
            child_ids.append(cid)
            chunk_idx += 1
            child_items = []
            _cb_patch_block_meta(parent_id, {"child_blocks": list(child_ids)})

        max_items = 5000
        with _open_backup_lp_text(bdir, backup_id, is_fullbackup=False) as f:
            for raw in f:
                pts = _lp_parse_points_from_line(raw)
                if not pts:
                    skipped += 1
                    continue
                for p in pts:
                    ts = str(p.get("_time") or "").strip()
                    meas = str(p.get("_measurement") or "").strip()
                    fld = str(p.get("_field") or "").strip()
                    if not ts or not meas or not fld:
                        skipped += 1
                        continue
                    tags = {k: str(v) for k, v in p.items() if k and not str(k).startswith("_") and v is not None}
                    pid = {
                        "bucket": str(cfg.get("bucket") or ""),
                        "org": str(cfg.get("org") or ""),
                        "measurement": meas,
                        "field": fld,
                        "timestamp": ts,
                        "tag_set": tags,
                    }
                    child_items.append({
                        "schema_version": CHANGE_ITEM_SCHEMA_VERSION,
                        "item_id": uuid.uuid4().hex,
                        "block_id": "",
                        "op": "update",
                        "point_identity": pid,
                        "old_point": None,
                        "new_point": p,
                        "conflict_policy": "blind",
                    })
                    if len(child_items) >= max_items:
                        flush_child()

        flush_child()

        # Promote child blocks list to the parent block.
        _cb_patch_block_meta(parent_id, {
            "child_blocks": list(child_ids),
            "applied": applied,
            "skipped": skipped,
        })

        # Register ref-only Undo entry (undo not supported, but repeat is).
        try:
            _undo_mgr(cfg).register_action(
                action_type="update",
                bucket=str(cfg.get("bucket") or ""),
                measurement=str(meta.get("measurement") or "backup"),
                group_label=f"backup_restore ({applied})",
                before_rows=[],
                after_rows=[],
                meta={"change_block_id": parent_id, "backup_id": backup_id, "undo_supported": False},
            )
        except Exception:
            pass

        return jsonify({
            "ok": True,
            "message": f"Restored points: {applied}",
            "applied": applied,
            "skipped": skipped,
            "change_block_id": parent_id,
            "child_blocks": child_ids,
        })
    except Exception as e:
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500


@app.post("/api/backup_copy")
def api_backup_copy():
    """Copy points from a backup to a target signal.

    This rewrites measurement/field and optionally overrides entity_id/friendly_name tags.
    Existing points in the target series are overwritten (upsert) for matching timestamp+tags.
    """

    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}
    confirm = body.get("confirm", False)
    ok_confirm = confirm is True or str(confirm).strip().lower() in ("1", "true", "yes", "on")
    if not ok_confirm:
        return jsonify({"ok": False, "error": "Confirmation required"}), 400

    backup_id = (body.get("id") or "").strip()
    if not backup_id:
        return jsonify({"ok": False, "error": "id required"}), 400

    target_measurement = (body.get("target_measurement") or "").strip()
    target_field = (body.get("target_field") or "").strip()
    if not target_measurement or not target_field:
        return jsonify({"ok": False, "error": "target_measurement and target_field required"}), 400

    target_entity_id = (body.get("target_entity_id") or "").strip() or None
    target_friendly_name = (body.get("target_friendly_name") or "").strip() or None

    start_dt: datetime | None = None
    stop_dt: datetime | None = None
    start_ns: int | None = None
    stop_ns: int | None = None
    if body.get("start") and body.get("stop"):
        try:
            start_dt, stop_dt = _get_start_stop_from_payload(body)
            if not start_dt or not stop_dt:
                raise ValueError("start and stop required")
            start_ns = _dt_to_ns(start_dt)
            stop_ns = _dt_to_ns(stop_dt)
        except Exception as e:
            return jsonify({"ok": False, "error": f"invalid start/stop: {e}"}), 400

    if int(cfg.get("influx_version", 2)) != 2:
        return jsonify({"ok": False, "error": "copy currently supports InfluxDB v2 only"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({
            "ok": False,
            "error": "InfluxDB v2 requires token, org, bucket. Bitte in /config YAML einlesen und speichern.",
        }), 400

    bdir = backup_dir_for_target(cfg, body.get("target"))
    try:
        # Ensure the payload exists (zip or legacy)
        with _open_backup_lp_text(bdir, backup_id, is_fullbackup=False):
            pass
    except Exception:
        return jsonify({"ok": False, "error": "backup not found"}), 404

    tgt_meas = _lp_escape_key(target_measurement)
    tgt_field = _lp_escape_key(target_field)

    try:
        preview_limit = int(cfg.get("restore_preview_lines", 5))
    except Exception:
        preview_limit = 5
    if preview_limit < 0:
        preview_limit = 0
    if preview_limit > 200:
        preview_limit = 200
    preview_lines: list[str] = []
    override_tags: dict[str, str] = {}
    if target_entity_id:
        override_tags["entity_id"] = _lp_escape_tag_value(target_entity_id)
    if target_friendly_name:
        override_tags["friendly_name"] = _lp_escape_tag_value(target_friendly_name)

    def _is_escaped(s: str, i: int) -> bool:
        # true if s[i] is escaped by an odd number of backslashes before it
        n = 0
        j = i - 1
        while j >= 0 and s[j] == "\\":
            n += 1
            j -= 1
        return (n % 2) == 1

    def _find_unescaped(s: str, ch: str) -> int:
        for i, c in enumerate(s):
            if c != ch:
                continue
            if not _is_escaped(s, i):
                return i
        return -1

    def _split_unescaped(s: str, ch: str) -> list[str]:
        out: list[str] = []
        cur: list[str] = []
        for i, c in enumerate(s):
            if c == ch and not _is_escaped(s, i):
                out.append("".join(cur))
                cur = []
            else:
                cur.append(c)
        out.append("".join(cur))
        return out

    def _split_tag_kv(tok: str) -> tuple[str, str] | None:
        i = _find_unescaped(tok, "=")
        if i <= 0:
            return None
        return tok[:i], tok[i + 1 :]

    def _rewrite_line(line: str) -> str | None:
        # Split: <measurement,tags> <fieldset> <timestamp>
        # NOTE: tag values can contain escaped spaces ("\\ "), so we must not use find(" ")
        # blindly.
        s = line.strip("\r\n")
        if not s.strip():
            return None

        # Timestamp is always the last token (unescaped).
        j = s.rfind(" ")
        if j <= 0:
            return None
        ts_raw = s[j + 1 :].strip()
        if not ts_raw:
            return None
        # Guard against weird tails
        if not ts_raw.isdigit():
            return None

        rest = s[:j]

        # Split mt vs fieldset on the first unescaped space.
        i = _find_unescaped(rest, " ")
        if i <= 0:
            return None
        mt = rest[:i]
        fieldset = rest[i + 1 :].strip()
        if not fieldset:
            return None

        # Optional time filter
        if start_ns is not None and stop_ns is not None:
            try:
                ts = int(ts_raw)
            except Exception:
                return None
            if ts < start_ns or ts > stop_ns:
                return None

        # Parse measurement + tags (comma is escaped in line protocol).
        parts = _split_unescaped(mt, ",")
        if not parts:
            return None
        tags_in = parts[1:]
        tag_map: dict[str, str] = {}
        tag_order: list[str] = []
        for tok in tags_in:
            kv = _split_tag_kv(tok)
            if not kv:
                continue
            k, v = kv
            tag_order.append(k)
            tag_map[k] = v
        for k, v in override_tags.items():
            tag_map[k] = v

        tags_out: list[str] = []
        for k in tag_order:
            if k in tag_map:
                tags_out.append(f"{k}={tag_map[k]}")
        for k in sorted(tag_map.keys()):
            if k not in tag_order:
                tags_out.append(f"{k}={tag_map[k]}")

        # Replace field key (first field key only, keep remaining fields as-is)
        fields = _split_unescaped(fieldset, ",")
        if not fields:
            return None
        f0 = fields[0]
        eq = f0.find("=")
        if eq <= 0:
            return None
        field_val = f0[eq + 1 :]
        fields[0] = f"{tgt_field}={field_val}"
        new_fieldset = ",".join(fields)

        if tags_out:
            new_mt = tgt_meas + "," + ",".join(tags_out)
        else:
            new_mt = tgt_meas
        return f"{new_mt} {new_fieldset} {ts_raw}"

    try:
        parent_id = uuid.uuid4().hex
        parent = {
            "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
            "block_id": parent_id,
            "created_at": _utc_now_iso_ms(),
            "source": {
                "user_id": None,
                "ip": _req_ip(),
                "ua": _req_ua(),
                "trigger_page": "backups",
                "trigger_source": "backup_copy",
                "trigger_action": "copy",
                "trigger_button": None,
            },
            "operation_source": "backup_copy",
            "reason": f"backup_copy:{backup_id}",
            "status": "created",
            "undo_status": "not_run",
            "repeat_status": "not_run",
            "affected_count": 0,
            "payload_mode": "inline",
            "payload_inline": [],
            "series_summary": {
                "measurement": target_measurement,
                "field": target_field,
                "entity_id": target_entity_id,
                "friendly_name": target_friendly_name,
            },
            "meta": {
                "backup_id": backup_id,
                "child_blocks": [],
                "undo_supported": False,
            },
        }
        save_change_block(parent, items=[])

        child_ids: list[str] = []
        child_items: list[dict[str, Any]] = []
        chunk_idx = 0
        applied = 0
        skipped = 0

        def flush_child() -> None:
            nonlocal chunk_idx, child_items, applied
            if not child_items:
                return
            cid = uuid.uuid4().hex
            cb = {
                "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
                "block_id": cid,
                "created_at": _utc_now_iso_ms(),
                "source": parent["source"],
                "operation_source": "backup_copy",
                "reason": f"backup_copy:{backup_id}#{chunk_idx}",
                "status": "created",
                "undo_status": "not_run",
                "repeat_status": "not_run",
                "affected_count": len(child_items),
                "series_summary": parent.get("series_summary") or {},
                "meta": {
                    "parent_block_id": parent_id,
                    "chunk_index": chunk_idx,
                    "undo_supported": False,
                },
            }
            save_change_block(cb, items=child_items)
            out = execute_change_block(cid)
            if not out.get("ok"):
                raise RuntimeError("copy conflict")
            try:
                applied += int(out.get("applied") or 0)
            except Exception:
                pass
            child_ids.append(cid)
            chunk_idx += 1
            child_items = []
            _cb_patch_block_meta(parent_id, {"child_blocks": list(child_ids)})

        max_items = 5000
        with _open_backup_lp_text(bdir, backup_id, is_fullbackup=False) as f:
            for raw in f:
                out = _rewrite_line(raw)
                if not out:
                    skipped += 1
                    continue
                if preview_limit > 0 and len(preview_lines) < preview_limit:
                    preview_lines.append(out)

                pts = _lp_parse_points_from_line(out)
                if not pts:
                    skipped += 1
                    continue
                for p in pts:
                    ts = str(p.get("_time") or "").strip()
                    meas = str(p.get("_measurement") or "").strip()
                    fld = str(p.get("_field") or "").strip()
                    if not ts or not meas or not fld:
                        skipped += 1
                        continue
                    tags = {k: str(v) for k, v in p.items() if k and not str(k).startswith("_") and v is not None}
                    pid = {
                        "bucket": str(cfg.get("bucket") or ""),
                        "org": str(cfg.get("org") or ""),
                        "measurement": meas,
                        "field": fld,
                        "timestamp": ts,
                        "tag_set": tags,
                    }
                    child_items.append({
                        "schema_version": CHANGE_ITEM_SCHEMA_VERSION,
                        "item_id": uuid.uuid4().hex,
                        "block_id": "",
                        "op": "update",
                        "point_identity": pid,
                        "old_point": None,
                        "new_point": p,
                        "conflict_policy": "blind",
                    })
                    if len(child_items) >= max_items:
                        flush_child()

        flush_child()
        _cb_patch_block_meta(parent_id, {"child_blocks": list(child_ids), "applied": applied, "skipped": skipped})

        try:
            _undo_mgr(cfg).register_action(
                action_type="update",
                bucket=str(cfg.get("bucket") or ""),
                measurement=str(target_measurement or "backup"),
                group_label=f"backup_copy ({applied})",
                before_rows=[],
                after_rows=[],
                meta={
                    "change_block_id": parent_id,
                    "backup_id": backup_id,
                    "undo_supported": False,
                    "target_measurement": target_measurement,
                    "target_field": target_field,
                },
            )
        except Exception:
            pass

        return jsonify({
            "ok": True,
            "message": f"Copied points: {applied}",
            "applied": applied,
            "skipped": skipped,
            "preview_limit": preview_limit,
            "preview_lines": preview_lines,
            "change_block_id": parent_id,
            "child_blocks": child_ids,
        })
    except Exception as e:
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500


def _restore_copy_job_public(job: dict[str, Any]) -> dict[str, Any]:
    total_b = job.get("total_bytes")
    read_b = int(job.get("read_bytes") or 0)
    pct = None
    if isinstance(total_b, int) and total_b > 0:
        pct = min(100.0, (read_b / float(total_b)) * 100.0)
    return {
        "id": job.get("id"),
        "state": job.get("state"),
        "message": job.get("message"),
        "started_at": job.get("started_at"),
        "elapsed": _job_elapsed_hms(job),
        "change_block_id": job.get("change_block_id"),
        "applied": int(job.get("applied") or 0),
        "skipped": int(job.get("skipped") or 0),
        "read_bytes": read_b,
        "total_bytes": total_b,
        "percent": pct,
        "current_time_ms": job.get("current_time_ms"),
        "last_written_time_ms": job.get("last_written_time_ms"),
        "cancelled": bool(job.get("cancelled")),
        "error": job.get("error"),
        "ready": job.get("state") in ("done", "error", "cancelled"),
    }


def _restore_copy_job_thread(
    job_id: str,
    cfg: dict[str, Any],
    bdir: Path,
    backup_id: str,
    target_measurement: str,
    target_field: str,
    target_entity_id: str | None,
    target_friendly_name: str | None,
    start_ns: int | None,
    stop_ns: int | None,
) -> None:
    with RESTORE_COPY_LOCK:
        job = RESTORE_COPY_JOBS.get(job_id)
    if not job:
        return

    def set_state(state: str, msg: str) -> None:
        with RESTORE_COPY_LOCK:
            if job_id in RESTORE_COPY_JOBS:
                RESTORE_COPY_JOBS[job_id]["state"] = state
                RESTORE_COPY_JOBS[job_id]["message"] = msg
                if state in ("done", "error", "cancelled"):
                    _job_set_finished(RESTORE_COPY_JOBS[job_id])

    def set_error(msg: str) -> None:
        with RESTORE_COPY_LOCK:
            if job_id in RESTORE_COPY_JOBS:
                RESTORE_COPY_JOBS[job_id]["error"] = msg

    def set_progress(**kw: Any) -> None:
        with RESTORE_COPY_LOCK:
            j = RESTORE_COPY_JOBS.get(job_id)
            if not j:
                return
            for k, v in kw.items():
                j[k] = v

    set_state("running", "Starte...")

    # Determine total size best-effort (zip preferred).
    total_bytes = None
    try:
        zpath = _backup_zip_path(bdir, backup_id)
        if zpath.exists():
            total_bytes = int(zpath.stat().st_size)
        else:
            _meta_path, lp_path = _backup_files(bdir, backup_id)
            if lp_path.exists():
                total_bytes = int(lp_path.stat().st_size)
    except Exception:
        total_bytes = None
    set_progress(total_bytes=total_bytes)

    tgt_meas = _lp_escape_key(target_measurement)
    tgt_field = _lp_escape_key(target_field)

    try:
        preview_limit = int(cfg.get("restore_preview_lines", 5))
    except Exception:
        preview_limit = 5
    if preview_limit < 0:
        preview_limit = 0
    if preview_limit > 200:
        preview_limit = 200

    preview_lines: list[str] = []
    override_tags: dict[str, str] = {}
    if target_entity_id:
        override_tags["entity_id"] = _lp_escape_tag_value(target_entity_id)
    if target_friendly_name:
        override_tags["friendly_name"] = _lp_escape_tag_value(target_friendly_name)

    def _is_escaped(s: str, i: int) -> bool:
        n = 0
        j = i - 1
        while j >= 0 and s[j] == "\\":
            n += 1
            j -= 1
        return (n % 2) == 1

    def _find_unescaped(s: str, ch: str) -> int:
        for i, c in enumerate(s):
            if c != ch:
                continue
            if not _is_escaped(s, i):
                return i
        return -1

    def _split_unescaped(s: str, ch: str) -> list[str]:
        out: list[str] = []
        cur: list[str] = []
        for i, c in enumerate(s):
            if c == ch and not _is_escaped(s, i):
                out.append("".join(cur))
                cur = []
            else:
                cur.append(c)
        out.append("".join(cur))
        return out

    def _split_tag_kv(tok: str) -> tuple[str, str] | None:
        i = _find_unescaped(tok, "=")
        if i <= 0:
            return None
        return tok[:i], tok[i + 1 :]

    def _raw_ts_ns(line: str) -> int | None:
        s = (line or "").strip("\r\n")
        j = s.rfind(" ")
        if j <= 0:
            return None
        ts_raw = s[j + 1 :].strip()
        if not ts_raw or not ts_raw.isdigit():
            return None
        try:
            return int(ts_raw)
        except Exception:
            return None

    def _rewrite_line(line: str) -> str | None:
        s = line.strip("\r\n")
        if not s.strip():
            return None

        j = s.rfind(" ")
        if j <= 0:
            return None
        ts_raw = s[j + 1 :].strip()
        if not ts_raw or not ts_raw.isdigit():
            return None

        rest = s[:j]
        i = _find_unescaped(rest, " ")
        if i <= 0:
            return None
        mt = rest[:i]
        fieldset = rest[i + 1 :].strip()
        if not fieldset:
            return None

        if start_ns is not None and stop_ns is not None:
            try:
                ts = int(ts_raw)
            except Exception:
                return None
            if ts < start_ns or ts > stop_ns:
                return None

        parts = _split_unescaped(mt, ",")
        if not parts:
            return None
        tags_in = parts[1:]
        tag_map: dict[str, str] = {}
        tag_order: list[str] = []
        for tok in tags_in:
            kv = _split_tag_kv(tok)
            if not kv:
                continue
            k, v = kv
            tag_order.append(k)
            tag_map[k] = v
        for k, v in override_tags.items():
            tag_map[k] = v

        tags_out: list[str] = []
        for k in tag_order:
            if k in tag_map:
                tags_out.append(f"{k}={tag_map[k]}")
        for k in sorted(tag_map.keys()):
            if k not in tag_order:
                tags_out.append(f"{k}={tag_map[k]}")

        fields = _split_unescaped(fieldset, ",")
        if not fields:
            return None
        f0 = fields[0]
        eq = f0.find("=")
        if eq <= 0:
            return None
        field_val = f0[eq + 1 :]
        fields[0] = f"{tgt_field}={field_val}"
        new_fieldset = ",".join(fields)

        if tags_out:
            new_mt = tgt_meas + "," + ",".join(tags_out)
        else:
            new_mt = tgt_meas
        return f"{new_mt} {new_fieldset} {ts_raw}"

    applied = 0
    dirty_series: set[tuple[str, str, str | None, str | None]] = set()
    skipped = 0
    read_bytes = 0
    batch: list[str] = []
    last_written_time_ms: int | None = None
    current_time_ms: int | None = None
    last_tick = time.monotonic()

    try:
        parent_id = uuid.uuid4().hex
        parent = {
            "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
            "block_id": parent_id,
            "created_at": _utc_now_iso_ms(),
            "source": {"user_id": None, "ip": None, "ua": None, "trigger_page": "restore", "trigger_source": "restore_copy_job", "trigger_action": "copy", "trigger_button": None},
            "operation_source": "restore_copy_job",
            "reason": f"restore_copy_job:{backup_id}",
            "status": "created",
            "undo_status": "not_run",
            "repeat_status": "not_run",
            "affected_count": 0,
            "payload_mode": "inline",
            "payload_inline": [],
            "series_summary": {
                "measurement": target_measurement,
                "field": target_field,
                "entity_id": target_entity_id,
                "friendly_name": target_friendly_name,
            },
            "meta": {"child_blocks": [], "undo_supported": False, "backup_id": backup_id},
        }
        save_change_block(parent, items=[])
        with RESTORE_COPY_LOCK:
            if job_id in RESTORE_COPY_JOBS:
                RESTORE_COPY_JOBS[job_id]["change_block_id"] = parent_id

        child_ids: list[str] = []
        child_items: list[dict[str, Any]] = []
        chunk_idx = 0
        last_ts_ns_in_chunk: int | None = None

        def flush_child() -> None:
            nonlocal chunk_idx, child_items, applied, last_written_time_ms, last_ts_ns_in_chunk
            if not child_items:
                return
            cid = uuid.uuid4().hex
            cb = {
                "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
                "block_id": cid,
                "created_at": _utc_now_iso_ms(),
                "source": parent["source"],
                "operation_source": "restore_copy_job",
                "reason": f"restore_copy_job:{backup_id}#{chunk_idx}",
                "status": "created",
                "undo_status": "not_run",
                "repeat_status": "not_run",
                "affected_count": len(child_items),
                "series_summary": parent.get("series_summary") or {},
                "meta": {"parent_block_id": parent_id, "chunk_index": chunk_idx, "undo_supported": False},
            }
            save_change_block(cb, items=child_items)
            out = execute_change_block(cid)
            if not out.get("ok"):
                raise RuntimeError("copy conflict")
            try:
                applied += int(out.get("applied") or 0)
            except Exception:
                pass
            if last_ts_ns_in_chunk is not None:
                last_written_time_ms = int(last_ts_ns_in_chunk // 1_000_000)
            child_ids.append(cid)
            chunk_idx += 1
            child_items = []
            last_ts_ns_in_chunk = None
            _cb_patch_block_meta(parent_id, {"child_blocks": list(child_ids)})

        max_items = 5000
        set_state("running", "Lese Backup...")
        with _open_backup_lp_text(bdir, backup_id, is_fullbackup=False) as f:
            for raw in f:
                with RESTORE_COPY_LOCK:
                    j = RESTORE_COPY_JOBS.get(job_id) or {}
                    if bool(j.get("cancelled")):
                        set_state("cancelled", "Abgebrochen")
                        return

                    try:
                        read_bytes += len(raw.encode("utf-8"))
                    except Exception:
                        read_bytes += len(str(raw or ""))

                    raw = str(raw or "").strip("\n")

                    ts_ns = _raw_ts_ns(raw)
                    if ts_ns is not None:
                        current_time_ms = int(ts_ns // 1_000_000)

                    out = _rewrite_line(raw)
                    if not out:
                        skipped += 1
                    else:
                        if preview_limit > 0 and len(preview_lines) < preview_limit:
                            preview_lines.append(out)
                        ts2 = _raw_ts_ns(out)
                        if ts2 is not None:
                            last_ts_ns_in_chunk = ts2

                        pts = _lp_parse_points_from_line(out)
                        for p in pts:
                            ts = str(p.get("_time") or "").strip()
                            meas = str(p.get("_measurement") or "").strip()
                            fld = str(p.get("_field") or "").strip()
                            if not ts or not meas or not fld:
                                continue
                            tags = {k: str(v) for k, v in p.items() if k and not str(k).startswith("_") and v is not None}
                            pid = {
                                "bucket": str(cfg.get("bucket") or ""),
                                "org": str(cfg.get("org") or ""),
                                "measurement": meas,
                                "field": fld,
                                "timestamp": ts,
                                "tag_set": tags,
                            }
                            child_items.append({
                                "schema_version": CHANGE_ITEM_SCHEMA_VERSION,
                                "item_id": uuid.uuid4().hex,
                                "block_id": "",
                                "op": "update",
                                "point_identity": pid,
                                "old_point": None,
                                "new_point": p,
                                "conflict_policy": "blind",
                            })

                    now = time.monotonic()
                    if (now - last_tick) >= 0.25:
                        set_progress(
                            read_bytes=read_bytes,
                            applied=applied,
                            skipped=skipped,
                            current_time_ms=current_time_ms,
                            last_written_time_ms=last_written_time_ms,
                        )
                        last_tick = now

                    if len(child_items) >= max_items:
                        set_state("running", "Schreibe via Change-Service...")
                        flush_child()
                        set_progress(
                            read_bytes=read_bytes,
                            applied=applied,
                            skipped=skipped,
                            current_time_ms=current_time_ms,
                            last_written_time_ms=last_written_time_ms,
                        )

            if child_items:
                set_state("running", "Schreibe via Change-Service...")
                flush_child()
                set_progress(
                    read_bytes=read_bytes,
                    applied=applied,
                    skipped=skipped,
                    current_time_ms=current_time_ms,
                    last_written_time_ms=last_written_time_ms,
                )

        _cb_patch_block_meta(parent_id, {"child_blocks": list(child_ids), "applied": applied, "skipped": skipped})

        with RESTORE_COPY_LOCK:
            if job_id in RESTORE_COPY_JOBS:
                RESTORE_COPY_JOBS[job_id]["result"] = {
                    "applied": applied,
                    "skipped": skipped,
                    "preview_limit": preview_limit,
                    "preview_lines": preview_lines,
                }
        try:
            if applied > 0:
                _dash_cache_mark_dirty_series(target_measurement, target_field, target_entity_id, target_friendly_name, "restore_copy")
                _stats_cache_mark_dirty_series(target_measurement, target_field, target_entity_id, target_friendly_name, "restore_copy")
        except Exception:
            pass
        set_state("done", f"Copied points: {applied}")
    except Exception as e:
        set_error(_short_influx_error(e))
        set_state("error", "Fehler")


@app.post("/api/restore_job/start")
def api_restore_job_start():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}
    confirm = body.get("confirm", False)
    ok_confirm = confirm is True or str(confirm).strip().lower() in ("1", "true", "yes", "on")
    if not ok_confirm:
        return jsonify({"ok": False, "error": "Confirmation required"}), 400

    backup_id = (body.get("id") or "").strip()
    if not backup_id:
        return jsonify({"ok": False, "error": "id required"}), 400
    if _backup_safe(backup_id) != backup_id:
        return jsonify({"ok": False, "error": "invalid id"}), 400

    bdir = backup_dir_for_target(cfg, body.get("target"))
    meta = _read_backup_meta(bdir, backup_id) or {}
    if str(meta.get("kind") or "") == "db_full":
        return jsonify({"ok": False, "error": "selected backup is a fullbackup; use FullRestore"}), 400

    target_measurement = (body.get("target_measurement") or "").strip()
    target_field = (body.get("target_field") or "").strip()
    if not target_measurement or not target_field:
        return jsonify({"ok": False, "error": "target_measurement and target_field required"}), 400

    target_entity_id = (body.get("target_entity_id") or "").strip() or None
    target_friendly_name = (body.get("target_friendly_name") or "").strip() or None

    start_ns: int | None = None
    stop_ns: int | None = None
    if body.get("start") and body.get("stop"):
        try:
            start_dt, stop_dt = _get_start_stop_from_payload(body)
            if not start_dt or not stop_dt:
                raise ValueError("start and stop required")
            start_ns = _dt_to_ns(start_dt)
            stop_ns = _dt_to_ns(stop_dt)
        except Exception as e:
            return jsonify({"ok": False, "error": f"invalid start/stop: {e}"}), 400

    if int(cfg.get("influx_version", 2)) != 2:
        return jsonify({"ok": False, "error": "copy currently supports InfluxDB v2 only"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({
            "ok": False,
            "error": "InfluxDB v2 requires token, org, bucket. Bitte in /config YAML einlesen und speichern.",
        }), 400

    job_id = uuid.uuid4().hex
    ip = _req_ip()
    ua = _req_ua()
    job = {
        "id": job_id,
        "state": "queued",
        "message": "Start...",
        "started_at": datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z"),
        "started_mono": time.monotonic(),
        "trigger_page": "restore",
        "trigger_ip": ip,
        "trigger_ua": ua,
        "applied": 0,
        "skipped": 0,
        "read_bytes": 0,
        "total_bytes": None,
        "current_time_ms": None,
        "last_written_time_ms": None,
        "cancelled": False,
        "error": None,
        "result": None,
    }

    try:
        start_s = _dt_to_rfc3339_utc(start_dt) if (body.get("start") and body.get("stop") and start_dt) else ""
        stop_s = _dt_to_rfc3339_utc(stop_dt) if (body.get("start") and body.get("stop") and stop_dt) else ""
    except Exception:
        start_s = ""
        stop_s = ""
    try:
        LOG.info(
            "job_start type=restore_copy job_id=%s ip=%s ua=%s backup_id=%s target=%s/%s entity_id=%s friendly_name=%s start=%s stop=%s",
            job_id,
            ip,
            ua,
            backup_id,
            target_measurement,
            target_field,
            target_entity_id or "",
            target_friendly_name or "",
            start_s,
            stop_s,
        )
    except Exception:
        pass

    # Cleanup old jobs
    with RESTORE_COPY_LOCK:
        RESTORE_COPY_JOBS[job_id] = job
        cutoff = time.monotonic() - 3600
        old = [k for k, v in RESTORE_COPY_JOBS.items() if float(v.get("started_mono") or 0) < cutoff]
        for k in old:
            if k != job_id:
                RESTORE_COPY_JOBS.pop(k, None)

    t = threading.Thread(
        target=_restore_copy_job_thread,
        args=(
            job_id,
            cfg,
            bdir,
            backup_id,
            target_measurement,
            target_field,
            target_entity_id,
            target_friendly_name,
            start_ns,
            stop_ns,
        ),
        daemon=True,
    )
    t.start()
    return jsonify({"ok": True, "job_id": job_id})


@app.get("/api/restore_job/status")
def api_restore_job_status():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return jsonify({"ok": False, "error": "job_id required"}), 400
    with RESTORE_COPY_LOCK:
        job = RESTORE_COPY_JOBS.get(job_id)
    if not job:
        return jsonify({"ok": False, "error": "job not found"}), 404
    return jsonify({"ok": True, "status": _restore_copy_job_public(job)})


@app.get("/api/restore_job/result")
def api_restore_job_result():
    job_id = (request.args.get("job_id") or "").strip()
    if not job_id:
        return jsonify({"ok": False, "error": "job_id required"}), 400
    with RESTORE_COPY_LOCK:
        job = RESTORE_COPY_JOBS.get(job_id)
        res = job.get("result") if job else None
        state = job.get("state") if job else None
        err = job.get("error") if job else None
    if not job:
        return jsonify({"ok": False, "error": "job not found"}), 404
    if state != "done":
        return jsonify({"ok": True, "ready": False, "state": state, "error": err})
    return jsonify({"ok": True, "ready": True, **(res or {})})


@app.post("/api/restore_job/cancel")
def api_restore_job_cancel():
    body = request.get_json(force=True) or {}
    job_id = (body.get("job_id") or "").strip()
    if not job_id:
        return jsonify({"ok": False, "error": "job_id required"}), 400
    with RESTORE_COPY_LOCK:
        job = RESTORE_COPY_JOBS.get(job_id)
        if not job:
            return jsonify({"ok": False, "error": "job not found"}), 404
        job["cancelled"] = True
    try:
        LOG.info("job_cancel type=restore_copy job_id=%s ip=%s ua=%s", job_id, _req_ip(), _req_ua())
    except Exception:
        pass
    return jsonify({"ok": True})


def _verify_job_public(job: dict[str, Any]) -> dict[str, Any]:
    return {
        "job_id": job.get("id"),
        "mode": job.get("mode"),
        "status": job.get("state"),
        "progress": int(job.get("progress") or 0),
        "step": job.get("step"),
        "started_at": job.get("started_at"),
        "finished_at": job.get("finished_at"),
        "source_bucket": job.get("source_bucket"),
        "verify_bucket": job.get("verify_bucket"),
        "cleanup_requested": bool(job.get("cleanup_requested")),
        "error": job.get("error"),
        "message": job.get("message"),
    }


def _verify_set(job_id: str, **kw: Any) -> None:
    with VERIFY_JOBS_LOCK:
        if job_id not in VERIFY_JOBS:
            return
        VERIFY_JOBS[job_id].update(kw)


def _verify_run_thread(job_id: str, cfg: dict[str, Any], payload: dict[str, Any]) -> None:
    def set_state(state: str, message: str, *, progress: int | None = None, step: str | None = None, error: str | None = None) -> None:
        upd: dict[str, Any] = {"state": state, "message": message}
        if progress is not None:
            upd["progress"] = progress
        if step is not None:
            upd["step"] = step
        if error is not None:
            upd["error"] = error
        if state in ("done", "warning", "failed"):
            upd["finished_at"] = _utc_now_iso_ms()
        _verify_set(job_id, **upd)

    try:
        mode = str(payload.get("mode") or "measurement")
        cleanup_requested = bool(payload.get("cleanup_verify_bucket", True))
        verify_bucket = _verify_tmp_bucket_name(mode)
        set_state("running", "Preflight", progress=5, step="precheck")

        bdir = backup_dir_for_target(cfg, payload.get("target"))
        ok_free, msg = _verify_storage_precheck(cfg, bdir)
        if not ok_free:
            set_state("failed", "Speichercheck fehlgeschlagen", progress=100, step="precheck", error=msg)
            return
        if int(cfg.get("influx_version", 2) or 2) != 2:
            set_state("failed", "Nicht unterstützt", progress=100, step="precheck", error="Verify MVP unterstützt aktuell InfluxDB v2")
            return
        if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
            set_state("failed", "Konfiguration fehlt", progress=100, step="precheck", error="InfluxDB v2 requires token, org, bucket")
            return

        backup_id = str(payload.get("backup_id") or "").strip()
        source_bucket = str(payload.get("bucket") or cfg.get("bucket") or "").strip()
        if mode == "measurement":
            source_bucket = str(cfg.get("bucket") or "").strip()
            if str(payload.get("backup_mode") or "") == "create_new":
                set_state("running", "Neues Messwert-Backup wird erstellt", progress=15, step="backup_create")
                measurement = str(payload.get("measurement") or "").strip()
                field = str(payload.get("field") or "").strip() or "value"
                entity_id = str(payload.get("entity_id") or "").strip() or None
                friendly_name = str(payload.get("friendly_name") or "").strip() or None
                selector_range, start_dt, stop_dt = _measurement_profile_range(cfg, payload)
                if not start_dt or not stop_dt:
                    start_dt = datetime(1970, 1, 1, tzinfo=timezone.utc)
                    stop_dt = datetime.now(timezone.utc)
                backup_id = _backup_create_range(cfg, measurement=measurement, field=field, entity_id=entity_id, friendly_name=friendly_name, start_dt=start_dt, stop_dt=stop_dt, display_name=friendly_name or entity_id or measurement)
            if not backup_id:
                set_state("failed", "Backup fehlt", progress=100, step="backup_select", error="backup_id required")
                return
            set_state("running", "Temporären Prüf-Bucket erstellen", progress=25, step="restore_temp_bucket")
            _verify_create_bucket_v2(cfg, verify_bucket)
            bdir = backup_dir_for_target(cfg, payload.get("target"))
            with _open_backup_lp_text(bdir, backup_id, is_fullbackup=False) as f:
                _verify_write_lp_to_bucket_v2(cfg, verify_bucket, f)
            set_state("running", "Original und Restore vergleichen", progress=70, step="compare_points")
            start_dt = _parse_iso_datetime(str(payload.get("start") or "")) if payload.get("start") else None
            stop_dt = _parse_iso_datetime(str(payload.get("stop") or "")) if payload.get("stop") else None
            result = _verify_measurement_compare_v2(
                cfg,
                source_bucket=source_bucket,
                verify_bucket=verify_bucket,
                measurement=str(payload.get("measurement") or ""),
                field=str(payload.get("field") or "value"),
                entity_id=str(payload.get("entity_id") or "").strip() or None,
                friendly_name=str(payload.get("friendly_name") or "").strip() or None,
                start_dt=start_dt,
                stop_dt=stop_dt,
            )
        else:
            if str(payload.get("backup_mode") or "") == "create_new":
                set_state("running", "Neues Fullbackup wird erstellt", progress=15, step="backup_create")
                ts = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")
                backup_id = f"fullbackup__db_full__v2__verify__{ts}"
                meta_path, lp_path = _fullbackup_files(bdir, backup_id)
                if _backup_zip_path(bdir, backup_id).exists() or meta_path.exists() or lp_path.exists():
                    raise RuntimeError("backup id collision")
                count = 0
                oldest = None
                newest = None
                q = f'''\
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "1970-01-01T00:00:00Z"))
  |> sort(columns: ["_time"])
'''
                with v2_client(cfg) as c:
                    qapi = c.query_api()
                    with lp_path.open("w", encoding="utf-8") as f:
                        for rec in qapi.query_stream(q, org=cfg["org"]):
                            t = rec.get_time(); v = rec.get_value(); m = rec.values.get("_measurement"); fld = rec.values.get("_field")
                            if v is None or not m or not fld:
                                continue
                            p = Point(str(m))
                            for k, tv in (rec.values or {}).items():
                                if k in ("result", "table") or str(k).startswith("_") or tv is None:
                                    continue
                                p = p.tag(str(k), str(tv))
                            p = p.field(str(fld), v)
                            if isinstance(t, datetime):
                                p = p.time(t, WritePrecision.NS)
                            lp = p.to_line_protocol()
                            if lp:
                                f.write(lp + "\n")
                                count += 1
                                if isinstance(t, datetime):
                                    oldest = t if oldest is None or t < oldest else oldest
                                    newest = t if newest is None or t > newest else newest
                meta = {"id": backup_id, "created_at": _utc_now_iso_ms(), "kind": "db_full", "format": "lp", "influx_version": 2, "bucket": cfg.get("bucket"), "point_count": count, "bytes": int(lp_path.stat().st_size) if lp_path.exists() else 0, "oldest_time": _dt_to_rfc3339_utc(oldest) if oldest else None, "newest_time": _dt_to_rfc3339_utc(newest) if newest else None, "start": _dt_to_rfc3339_utc(oldest) if oldest else None, "stop": _dt_to_rfc3339_utc(newest) if newest else None}
                meta_path.write_text(json.dumps(meta, indent=2, sort_keys=True), encoding="utf-8")
                _backup_pack_zip(bdir, backup_id, meta_path, lp_path, gzip_payload=bool(cfg.get("write_gzip_enabled", True)), gzip_level=int(cfg.get("write_gzip_level", 6) or 6))
            if not backup_id:
                set_state("failed", "Backup fehlt", progress=100, step="backup_select", error="backup_id required")
                return
            meta = _read_backup_meta(bdir, backup_id) or {}
            if str(meta.get("format") or "lp") == "native_v2":
                set_state("failed", "Nicht unterstützt", progress=100, step="backup_select", error="Native v2 Verify ist im MVP noch nicht unterstützt")
                return
            set_state("running", "Temporären Prüf-Bucket erstellen", progress=25, step="restore_temp_bucket")
            _verify_create_bucket_v2(cfg, verify_bucket)
            with _open_backup_lp_text(bdir, backup_id, is_fullbackup=True) as f:
                _verify_write_lp_to_bucket_v2(cfg, verify_bucket, f)
            set_state("running", "Original und Restore vergleichen", progress=70, step="compare_measurements")
            result = _verify_full_compare_v2(cfg, source_bucket=source_bucket, verify_bucket=verify_bucket)

        status = "done"
        allowed = float(payload.get("allowed_delta_pct") or 0.1)
        if float((result.get("points") or {}).get("delta_pct") or 0.0) > allowed or (result.get("measurements") or {}).get("missing") or (result.get("measurements") or {}).get("additional"):
            status = "failed"
        elif bool((result.get("cardinality") or {}).get("drift")):
            status = "warning"
        result.update({"job_id": job_id, "status": status.upper(), "mode": mode, "profile": str(payload.get("profile") or "fast"), "source_bucket": source_bucket, "verify_bucket": verify_bucket, "cleanup_requested": cleanup_requested})
        cleanup_done = False
        if cleanup_requested:
            set_state("running", "Temporären Prüf-Bucket löschen", progress=90, step="cleanup")
            cleanup_done = _verify_delete_bucket_v2(cfg, verify_bucket)
        result["cleanup_done"] = cleanup_done
        _verify_save_result(job_id, result)
        set_state(status, "Verifikation abgeschlossen", progress=100, step="finished")
    except Exception as e:
        _verify_set(job_id, state="failed", message="Verifikation fehlgeschlagen", progress=100, step="finished", error=_short_influx_error(e), finished_at=_utc_now_iso_ms())


@app.post("/api/verify/measurement")
def api_verify_measurement_start():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}
    if not str(body.get("entity_id") or "").strip() or not str(body.get("measurement") or "").strip() or not str(body.get("field") or "").strip():
        return jsonify({"ok": False, "error": "entity_id, measurement and field required"}), 400
    if str(body.get("backup_mode") or "existing") == "existing" and not str(body.get("backup_id") or "").strip():
        return jsonify({"ok": False, "error": "backup_id required for backup_mode=existing"}), 400
    job_id = "verify_measurement_" + uuid.uuid4().hex
    with VERIFY_JOBS_LOCK:
        VERIFY_JOBS[job_id] = {"id": job_id, "mode": "measurement", "state": "queued", "progress": 0, "step": "queued", "started_at": _utc_now_iso_ms(), "cleanup_requested": bool(body.get("cleanup_verify_bucket", True)), "source_bucket": str(cfg.get("bucket") or "")}
    payload = dict(body); payload["mode"] = "measurement"
    threading.Thread(target=_verify_run_thread, args=(job_id, dict(cfg), payload), daemon=True).start()
    return jsonify({"ok": True, "job_id": job_id, "mode": "measurement", "status": "queued"})


@app.post("/api/verify/fullbackup")
def api_verify_fullbackup_start():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}
    bucket = str(body.get("bucket") or cfg.get("bucket") or "").strip()
    if not bucket:
        return jsonify({"ok": False, "error": "bucket required"}), 400
    if str(body.get("backup_mode") or "existing") == "existing" and not str(body.get("backup_id") or "").strip():
        return jsonify({"ok": False, "error": "backup_id required for backup_mode=existing"}), 400
    job_id = "verify_full_" + uuid.uuid4().hex
    with VERIFY_JOBS_LOCK:
        VERIFY_JOBS[job_id] = {"id": job_id, "mode": "fullbackup", "state": "queued", "progress": 0, "step": "queued", "started_at": _utc_now_iso_ms(), "cleanup_requested": bool(body.get("cleanup_verify_bucket", True)), "source_bucket": bucket}
    payload = dict(body); payload["mode"] = "fullbackup"; payload["bucket"] = bucket
    threading.Thread(target=_verify_run_thread, args=(job_id, dict(cfg), payload), daemon=True).start()
    return jsonify({"ok": True, "job_id": job_id, "mode": "fullbackup", "status": "queued"})


@app.get("/api/verify/status/<job_id>")
def api_verify_status(job_id: str):
    with VERIFY_JOBS_LOCK:
        job = VERIFY_JOBS.get(str(job_id or "").strip())
    if not job:
        return jsonify({"ok": False, "error": "job not found"}), 404
    return jsonify({"ok": True, "job": _verify_job_public(job)})


@app.get("/api/verify/result/<job_id>")
def api_verify_result(job_id: str):
    with VERIFY_JOBS_LOCK:
        job = VERIFY_JOBS.get(str(job_id or "").strip())
    if not job:
        return jsonify({"ok": False, "error": "job not found"}), 404
    if str(job.get("state") or "") not in ("done", "warning", "failed"):
        return jsonify({"ok": True, "ready": False, "state": job.get("state"), "error": job.get("error")})
    res = _verify_load_result(job_id) or {}
    return jsonify({"ok": True, "ready": True, "result": res})


@app.delete("/api/verify/temp/<job_id>")
def api_verify_temp_delete(job_id: str):
    with VERIFY_JOBS_LOCK:
        job = VERIFY_JOBS.get(str(job_id or "").strip()) or {}
    vb = str(job.get("verify_bucket") or "").strip()
    if not vb:
        return jsonify({"ok": False, "error": "verify bucket not found"}), 404
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    deleted = _verify_delete_bucket_v2(cfg, vb)
    return jsonify({"ok": True, "job_id": job_id, "verify_bucket": vb, "deleted": bool(deleted)})


def _combine_job_public(job: dict[str, Any]) -> dict[str, Any]:
    return {
        "id": job.get("id"),
        "state": job.get("state"),
        "message": job.get("message"),
        "started_at": job.get("started_at"),
        "elapsed": _job_elapsed_hms(job),
        "change_block_id": job.get("change_block_id"),
        "read": int(job.get("read") or 0),
        "written": int(job.get("written") or 0),
        "skipped": int(job.get("skipped") or 0),
        "backup_id": job.get("backup_id"),
        "backup_before": bool(job.get("backup_before", True)),
        "delete_target_first": bool(job.get("delete_target_first", False)),
        "current_time_ms": job.get("current_time_ms"),
        "last_written_time_ms": job.get("last_written_time_ms"),
        "cancelled": bool(job.get("cancelled")),
        "error": job.get("error"),
        "ready": job.get("state") in ("done", "error", "cancelled"),
    }


def _combine_job_thread(
    job_id: str,
    cfg: dict[str, Any],
    source: dict[str, Any],
    target: dict[str, Any],
    start_dt: datetime,
    stop_dt: datetime,
) -> None:
    with COMBINE_LOCK:
        job = COMBINE_JOBS.get(job_id)
    if not job:
        return

    def set_state(state: str, msg: str) -> None:
        with COMBINE_LOCK:
            if job_id in COMBINE_JOBS:
                COMBINE_JOBS[job_id]["state"] = state
                COMBINE_JOBS[job_id]["message"] = msg
                if state in ("done", "error", "cancelled"):
                    _job_set_finished(COMBINE_JOBS[job_id])

    def set_error(msg: str) -> None:
        with COMBINE_LOCK:
            if job_id in COMBINE_JOBS:
                COMBINE_JOBS[job_id]["error"] = msg

    def set_progress(**kw: Any) -> None:
        with COMBINE_LOCK:
            j = COMBINE_JOBS.get(job_id)
            if not j:
                return
            for k, v in kw.items():
                j[k] = v

    def is_cancelled() -> bool:
        with COMBINE_LOCK:
            j = COMBINE_JOBS.get(job_id) or {}
            return bool(j.get("cancelled"))

    set_state("running", "Starte...")

    src_m = str(source.get("measurement") or "").strip()
    src_f = str(source.get("field") or "").strip()
    src_eid = str(source.get("entity_id") or "").strip() or None
    src_fn = str(source.get("friendly_name") or "").strip() or None

    tgt_m = str(target.get("measurement") or "").strip()
    tgt_f = str(target.get("field") or "").strip()
    tgt_eid = str(target.get("entity_id") or "").strip() or None
    tgt_fn = str(target.get("friendly_name") or "").strip() or None

    backup_before = bool(job.get("backup_before", True))
    delete_target_first = bool(job.get("delete_target_first", False))

    if not (src_m and src_f and tgt_m and tgt_f):
        set_error("missing measurement/field")
        set_state("error", "Fehler")
        return

    # For safety/rollback, require at least one identifying tag on both sides.
    if not (src_eid or src_fn):
        set_error("source requires entity_id or friendly_name")
        set_state("error", "Fehler")
        return
    if not (tgt_eid or tgt_fn):
        set_error("target requires entity_id or friendly_name")
        set_state("error", "Fehler")
        return

    try:
        max_points = int(cfg.get("ui_query_manual_max_points", 200000) or 200000)
    except Exception:
        max_points = 200000
    if max_points < 1000:
        max_points = 1000
    if max_points > 2000000:
        max_points = 2000000

    start = _dt_to_rfc3339_utc(start_dt)
    stop = _dt_to_rfc3339_utc(stop_dt)
    extra = flux_tag_filter(src_eid, src_fn)

    q = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "{start}"), stop: time(v: "{stop}"))
  |> filter(fn: (r) => r._measurement == {_flux_str(src_m)} and r._field == {_flux_str(src_f)}{extra})
  |> sort(columns: ["_time"], desc: false)
  |> limit(n: {max_points})
'''

    log_query("combine.copy (flux)", q)

    read = 0
    written = 0
    skipped = 0
    last_written_time_ms = None
    set_state("running", "Lese Punkte...")

    # Optional: create a rollback-safe backup of the target series in the same time window.
    backup_id = None
    try:
        if backup_before:
            set_state("running", "Backup Zielbereich...")
            disp = f"combine_target__{tgt_fn or tgt_eid or tgt_m}"
            backup_id = _backup_create_range(
                cfg,
                measurement=tgt_m,
                field=tgt_f,
                entity_id=tgt_eid,
                friendly_name=tgt_fn,
                start_dt=start_dt,
                stop_dt=stop_dt,
                display_name=disp,
            )
            set_progress(backup_id=backup_id)
    except Exception as e:
        set_error(f"backup_before failed: {_short_influx_error(e)}")
        set_state("error", "Fehler")
        return

    # Optional: delete target range first (destructive).
    parent_id = uuid.uuid4().hex
    undo_supported = bool(delete_target_first)
    parent = {
        "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
        "block_id": parent_id,
        "created_at": _utc_now_iso_ms(),
        "source": {"user_id": None, "ip": None, "ua": None, "trigger_page": "combine", "trigger_source": "combine_job", "trigger_action": "copy", "trigger_button": None},
        "operation_source": "combine_copy",
        "reason": "combine_copy",
        "status": "created",
        "undo_status": "not_run",
        "repeat_status": "not_run",
        "affected_count": 0,
        "payload_mode": "inline",
        "payload_inline": [],
        "series_summary": {"measurement": tgt_m, "field": tgt_f, "entity_id": tgt_eid, "friendly_name": tgt_fn},
        "meta": {
            "child_blocks": [],
            "undo_supported": undo_supported,
            "backup_id": backup_id,
            "backup_before": bool(backup_before),
            "delete_target_first": bool(delete_target_first),
            "source": {"measurement": src_m, "field": src_f, "entity_id": src_eid, "friendly_name": src_fn},
            "target": {"measurement": tgt_m, "field": tgt_f, "entity_id": tgt_eid, "friendly_name": tgt_fn},
            "range": {"start": _dt_to_rfc3339_utc_full(start_dt), "stop": _dt_to_rfc3339_utc_full(stop_dt)},
        },
    }
    save_change_block(parent, items=[])
    try:
        set_progress(change_block_id=parent_id)
    except Exception:
        pass

    child_ids: list[str] = []
    chunk_idx = 0

    def exec_child(items: list[dict[str, Any]], *, kind: str) -> int:
        nonlocal chunk_idx
        if not items:
            return 0
        cid = uuid.uuid4().hex
        cb = {
            "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
            "block_id": cid,
            "created_at": _utc_now_iso_ms(),
            "source": parent["source"],
            "operation_source": "combine_copy",
            "reason": f"combine_copy:{kind}#{chunk_idx}",
            "status": "created",
            "undo_status": "not_run",
            "repeat_status": "not_run",
            "affected_count": len(items),
            "series_summary": parent.get("series_summary") or {},
            "meta": {"parent_block_id": parent_id, "chunk_index": chunk_idx, "kind": kind, "undo_supported": undo_supported},
        }
        save_change_block(cb, items=items)
        out = execute_change_block(cid)
        if not out.get("ok"):
            raise RuntimeError("combine conflict")
        child_ids.append(cid)
        chunk_idx += 1
        _cb_patch_block_meta(parent_id, {"child_blocks": list(child_ids)})
        try:
            return int(out.get("applied") or 0)
        except Exception:
            return 0

    max_items = 5000

    # Optional: delete target range first (destructive) via exact deletes.
    try:
        if delete_target_first:
            set_state("running", "Loesche Zielbereich...")
            extra_t = flux_tag_filter(tgt_eid, tgt_fn)
            q_del = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "{_dt_to_rfc3339_utc_full(start_dt)}"), stop: time(v: "{_dt_to_rfc3339_utc_full(stop_dt)}"))
  |> filter(fn: (r) => r._measurement == {_flux_str(tgt_m)} and r._field == {_flux_str(tgt_f)}{extra_t})
  |> group()
  |> sort(columns: ["_time"])
'''
            del_items: list[dict[str, Any]] = []
            with v2_client(cfg) as c:
                qapi = c.query_api()
                for rec in qapi.query_stream(q_del, org=cfg["org"]):
                    if is_cancelled():
                        set_state("cancelled", "Abgebrochen")
                        return
                    t = rec.get_time()
                    v = rec.get_value()
                    if not isinstance(t, datetime):
                        continue
                    tags: dict[str, str] = {}
                    for k, tv in (rec.values or {}).items():
                        if k in ("result", "table"):
                            continue
                        if str(k).startswith("_"):
                            continue
                        if tv is None:
                            continue
                        tags[str(k)] = str(tv)
                    ts = _dt_to_rfc3339_utc_full(t.astimezone(timezone.utc))
                    pid = {"bucket": str(cfg.get("bucket") or ""), "org": str(cfg.get("org") or ""), "measurement": tgt_m, "field": tgt_f, "timestamp": ts, "tag_set": tags}
                    old_row = {"_time": ts, "_measurement": tgt_m, "_field": tgt_f, "_value": v, **tags}
                    del_items.append({
                        "schema_version": CHANGE_ITEM_SCHEMA_VERSION,
                        "item_id": uuid.uuid4().hex,
                        "block_id": "",
                        "op": "delete",
                        "point_identity": pid,
                        "old_point": old_row,
                        "new_point": None,
                        "conflict_policy": "blind",
                    })
                    if len(del_items) >= max_items:
                        exec_child(del_items, kind="delete")
                        del_items = []
            exec_child(del_items, kind="delete")
    except Exception as e:
        set_error(f"delete_target_first failed: {_short_influx_error(e)}")
        set_state("error", "Fehler")
        return

    # Copy as ChangeBlocks writes.
    try:
        with v2_client(cfg) as c:
            qapi = c.query_api()
            op_write = "create" if delete_target_first else "update"
            wr_items: list[dict[str, Any]] = []
            for rec in qapi.query_stream(q, org=cfg["org"]):
                if is_cancelled():
                    set_state("cancelled", "Abgebrochen")
                    return
                read += 1
                try:
                    ts = rec.get_time()
                    val = rec.get_value()
                    if not isinstance(ts, datetime):
                        skipped += 1
                        continue
                    if val is None:
                        skipped += 1
                        continue

                    tags: dict[str, str] = {}
                    for k, tv in (rec.values or {}).items():
                        if k in ("result", "table"):
                            continue
                        if str(k).startswith("_"):
                            continue
                        if tv is None:
                            continue
                        tags[str(k)] = str(tv)
                    if tgt_eid:
                        tags["entity_id"] = str(tgt_eid)
                    if tgt_fn:
                        tags["friendly_name"] = str(tgt_fn)

                    ts_iso = _dt_to_rfc3339_utc_full(ts.astimezone(timezone.utc))
                    row = {"_time": ts_iso, "_measurement": tgt_m, "_field": tgt_f, "_value": val, **tags}
                    pid = {"bucket": str(cfg.get("bucket") or ""), "org": str(cfg.get("org") or ""), "measurement": tgt_m, "field": tgt_f, "timestamp": ts_iso, "tag_set": tags}
                    wr_items.append({
                        "schema_version": CHANGE_ITEM_SCHEMA_VERSION,
                        "item_id": uuid.uuid4().hex,
                        "block_id": "",
                        "op": op_write,
                        "point_identity": pid,
                        "old_point": None,
                        "new_point": row,
                        "conflict_policy": "blind",
                    })
                    last_written_time_ms = int(ts.timestamp() * 1000)
                    if len(wr_items) >= max_items:
                        w = exec_child(wr_items, kind="write")
                        written += w
                        wr_items = []
                except Exception:
                    skipped += 1
                    continue

                if read % 1000 == 0:
                    cur_ms = None
                    try:
                        cur_ms = int(ts.timestamp() * 1000) if isinstance(ts, datetime) else None
                    except Exception:
                        cur_ms = None
                    set_progress(read=read, written=written, skipped=skipped, current_time_ms=cur_ms, last_written_time_ms=last_written_time_ms)
                    set_state("running", f"Kopiere... {read}")

            if wr_items:
                w = exec_child(wr_items, kind="write")
                written += w

        _cb_patch_block_meta(parent_id, {"child_blocks": list(child_ids), "read": read, "written": written, "skipped": skipped})

        set_progress(read=read, written=written, skipped=skipped, last_written_time_ms=last_written_time_ms)

        try:
            _history_append({
                "kind": "combine",
                "action": "combine_copy",
                "source": {"measurement": src_m, "field": src_f, "entity_id": src_eid, "friendly_name": src_fn},
                "target": {"measurement": tgt_m, "field": tgt_f, "entity_id": tgt_eid, "friendly_name": tgt_fn},
                "series": {
                    "measurement": tgt_m,
                    "field": tgt_f,
                    "entity_id": tgt_eid,
                    "friendly_name": tgt_fn,
                    "tags": {"entity_id": tgt_eid, "friendly_name": tgt_fn},
                },
                "start": start,
                "stop": stop,
                "backup_id": backup_id,
                "backup_before": bool(backup_before),
                "delete_target_first": bool(delete_target_first),
                "read": read,
                "written": written,
                "skipped": skipped,
                "change_block_id": parent_id,
                "ip": _req_ip(),
                "ua": _req_ua(),
            })
        except Exception:
            pass

        try:
            _undo_mgr(cfg).register_action(
                action_type="update",
                bucket=str(cfg.get("bucket") or ""),
                measurement=tgt_m,
                group_label=f"combine_copy ({written})",
                before_rows=[],
                after_rows=[],
                meta={"change_block_id": parent_id, "undo_supported": undo_supported, "backup_id": backup_id},
            )
        except Exception:
            pass

        try:
            _dash_cache_mark_dirty_series(tgt_m, tgt_f, tgt_eid, tgt_fn, "combine")
            _stats_cache_mark_dirty_series(tgt_m, tgt_f, tgt_eid, tgt_fn, "combine")
        except Exception:
            pass

        set_state("done", f"Fertig. geschrieben: {written}")
    except Exception as e:
        set_error(_short_influx_error(e))
        set_state("error", "Fehler")


@app.post("/api/combine_job/start")
def api_combine_job_start():
    try:
        cfg = _overlay_from_yaml_if_enabled(load_cfg())
        body = request.get_json(force=True) or {}

        confirm = body.get("confirm", False)
        ok_confirm = confirm is True or str(confirm).strip().lower() in ("1", "true", "yes", "on")
        if not ok_confirm:
            return jsonify({"ok": False, "error": "Confirmation required"}), 400

        if int(cfg.get("influx_version", 2)) != 2:
            return jsonify({"ok": False, "error": "combine currently supports InfluxDB v2 only"}), 400
        if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
            return jsonify({
                "ok": False,
                "error": "InfluxDB v2 requires token, org, bucket. Bitte in /config YAML einlesen und speichern.",
            }), 400

        src = body.get("source")
        tgt = body.get("target")
        if not isinstance(src, dict) or not isinstance(tgt, dict):
            return jsonify({"ok": False, "error": "source and target required"}), 400

        direction = str(body.get("direction") or "src_to_tgt").strip().lower()
        if direction not in ("src_to_tgt", "tgt_to_src"):
            return jsonify({"ok": False, "error": "direction must be src_to_tgt or tgt_to_src"}), 400
        if direction == "tgt_to_src":
            src, tgt = tgt, src

        # Validate payload early so the user sees a clear API error (instead of a background job failure).
        try:
            _combine_series_payload(src)
            _combine_series_payload(tgt)
        except Exception as e:
            return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 400

        backup_before = body.get("backup_before", True)
        backup_before_on = backup_before is True or str(backup_before).strip().lower() in ("1", "true", "yes", "on")

        delete_first = body.get("delete_target_first", False)
        delete_first_on = delete_first is True or str(delete_first).strip().lower() in ("1", "true", "yes", "on")
        if delete_first_on:
            if not ALLOW_DELETE:
                return jsonify({"ok": False, "error": "Delete is disabled (ALLOW_DELETE=false)"}), 400

        try:
            start_dt, stop_dt = _get_start_stop_from_payload(body)
        except Exception as e:
            return jsonify({"ok": False, "error": f"invalid start/stop: {e}"}), 400
        if not start_dt or not stop_dt:
            return jsonify({"ok": False, "error": "start and stop required"}), 400

        job_id = uuid.uuid4().hex
        ip = _req_ip()
        ua = _req_ua()
        job = {
            "id": job_id,
            "state": "queued",
            "message": "Start...",
            "started_at": datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z"),
            "started_mono": time.monotonic(),
            "trigger_page": "combine",
            "trigger_ip": ip,
            "trigger_ua": ua,
            "read": 0,
            "written": 0,
            "skipped": 0,
            "current_time_ms": None,
            "last_written_time_ms": None,
            "cancelled": False,
            "error": None,
            "backup_before": bool(backup_before_on),
            "delete_target_first": bool(delete_first_on),
        }

        try:
            LOG.info("job_start type=combine job_id=%s ip=%s ua=%s", job_id, ip, ua)
        except Exception:
            pass

        with COMBINE_LOCK:
            COMBINE_JOBS[job_id] = job
            cutoff = time.monotonic() - 6 * 3600
            old = [k for k, v in COMBINE_JOBS.items() if float(v.get("started_mono") or 0) < cutoff]
            for k in old:
                if k != job_id:
                    COMBINE_JOBS.pop(k, None)

        t = threading.Thread(target=_combine_job_thread, args=(job_id, cfg, src, tgt, start_dt, stop_dt), daemon=True)
        t.start()
        return jsonify({"ok": True, "job_id": job_id})
    except Exception as e:
        try:
            LOG.exception("api_combine_job_start failed")
        except Exception:
            pass
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500


def _combine_series_payload(x: dict[str, Any]) -> tuple[str, str, str | None, str | None]:
    m = str(x.get("measurement") or "").strip()
    f = str(x.get("field") or "value").strip() or "value"
    eid = str(x.get("entity_id") or "").strip() or None
    fn = str(x.get("friendly_name") or "").strip() or None
    if not m or not f:
        raise ValueError("measurement and field required")
    if not eid and not fn:
        raise ValueError("entity_id or friendly_name required")
    return m, f, eid, fn


def _combine_window_seconds(start_dt: datetime, stop_dt: datetime, bins: int) -> int:
    try:
        s = float((stop_dt - start_dt).total_seconds())
    except Exception:
        s = 0.0
    if s <= 0:
        return 1
    b = int(bins)
    if b < 50:
        b = 50
    if b > 600:
        b = 600
    every = int(max(1.0, s / float(b)))
    if every > 86400:
        every = 86400
    return every


@app.post("/api/combine_timeline")
def api_combine_timeline():
    """Return bucketed counts for a series in a time window (for timeline UI)."""

    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    if int(cfg.get("influx_version", 2)) != 2:
        return jsonify({"ok": False, "error": "combine timeline supports InfluxDB v2 only"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({"ok": False, "error": "InfluxDB v2 requires token, org, bucket"}), 400

    body = request.get_json(force=True) or {}
    series = body.get("series")
    if not isinstance(series, dict):
        return jsonify({"ok": False, "error": "series required"}), 400
    try:
        start_dt, stop_dt = _get_start_stop_from_payload(body)
    except Exception as e:
        return jsonify({"ok": False, "error": f"invalid start/stop: {e}"}), 400
    if not start_dt or not stop_dt:
        return jsonify({"ok": False, "error": "start and stop required"}), 400

    try:
        bins = int(body.get("bins") or 220)
    except Exception:
        bins = 220
    bins = min(600, max(50, bins))

    try:
        m, f, eid, fn = _combine_series_payload(series)
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 400

    every_s = _combine_window_seconds(start_dt, stop_dt, bins)
    start = _dt_to_rfc3339_utc(start_dt)
    stop = _dt_to_rfc3339_utc(stop_dt)
    extra = flux_tag_filter(eid, fn)
    q = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "{start}"), stop: time(v: "{stop}"))
  |> filter(fn: (r) => r._measurement == {_flux_str(m)} and r._field == {_flux_str(f)}{extra})
  |> aggregateWindow(every: {every_s}s, fn: count, createEmpty: false)
  |> keep(columns: ["_time", "_value"])
  |> sort(columns: ["_time"], desc: false)
'''

    pts: list[dict[str, Any]] = []
    try:
        with v2_client(cfg, timeout_seconds_override=min(30, int(cfg.get("timeout_seconds") or 10))) as c:
            qapi = c.query_api()
            for rec in qapi.query_stream(q, org=cfg["org"]):
                try:
                    t = rec.get_time()
                    v = rec.get_value()
                    if not isinstance(t, datetime):
                        continue
                    if v is None:
                        continue
                    pts.append({"t_ms": int(t.timestamp() * 1000), "v": int(v)})
                except Exception:
                    continue
        return jsonify({"ok": True, "every_seconds": every_s, "points": pts})
    except Exception as e:
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500


@app.post("/api/combine_preview")
def api_combine_preview():
    """Return downsampled numeric values for a series in a time window (for mini-graph UI)."""

    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    if int(cfg.get("influx_version", 2)) != 2:
        return jsonify({"ok": False, "error": "combine preview supports InfluxDB v2 only"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({"ok": False, "error": "InfluxDB v2 requires token, org, bucket"}), 400

    body = request.get_json(force=True) or {}
    series = body.get("series")
    if not isinstance(series, dict):
        return jsonify({"ok": False, "error": "series required"}), 400
    try:
        start_dt, stop_dt = _get_start_stop_from_payload(body)
    except Exception as e:
        return jsonify({"ok": False, "error": f"invalid start/stop: {e}"}), 400
    if not start_dt or not stop_dt:
        return jsonify({"ok": False, "error": "start and stop required"}), 400

    try:
        points = int(body.get("points") or 260)
    except Exception:
        points = 260
    points = min(800, max(60, points))

    try:
        m, f, eid, fn = _combine_series_payload(series)
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 400

    every_s = _combine_window_seconds(start_dt, stop_dt, points)
    start = _dt_to_rfc3339_utc(start_dt)
    stop = _dt_to_rfc3339_utc(stop_dt)
    extra = flux_tag_filter(eid, fn)
    q = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "{start}"), stop: time(v: "{stop}"))
  |> filter(fn: (r) => r._measurement == {_flux_str(m)} and r._field == {_flux_str(f)}{extra})
  |> aggregateWindow(every: {every_s}s, fn: mean, createEmpty: false)
  |> keep(columns: ["_time", "_value"])
  |> sort(columns: ["_time"], desc: false)
'''

    pts: list[dict[str, Any]] = []
    try:
        with v2_client(cfg, timeout_seconds_override=min(30, int(cfg.get("timeout_seconds") or 10))) as c:
            qapi = c.query_api()
            for rec in qapi.query_stream(q, org=cfg["org"]):
                try:
                    t = rec.get_time()
                    v = rec.get_value()
                    if not isinstance(t, datetime):
                        continue
                    if v is None or isinstance(v, bool) or not isinstance(v, (int, float)):
                        continue
                    pts.append({"t_ms": int(t.timestamp() * 1000), "v": float(v)})
                except Exception:
                    continue
        return jsonify({"ok": True, "every_seconds": every_s, "points": pts})
    except Exception as e:
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500


@app.get("/api/combine_job/status")
def api_combine_job_status():
    job_id = (request.args.get("job_id") or "").strip()
