@app.get("/api/watchlists/inbox")
def api_watchlists_inbox():
    q = str(request.args.get("q") or "").strip().lower()
    only = str(request.args.get("status") or "").strip().lower()
    xs = _watchlist_inbox_load()
    out: list[dict[str, Any]] = []
    for it in xs:
        if not isinstance(it, dict):
            continue
        st = str(it.get("status") or "new").strip().lower() or "new"
        if only:
            if st != only:
                continue
        else:
            # Default: only open entries.
            if st in ("done", "muted"):
                continue
        txt = json.dumps(it, ensure_ascii=True).lower()
        if q and q not in txt:
            continue
        out.append(it)
    out.sort(key=lambda r: str(r.get("updated_at") or r.get("created_at") or ""), reverse=True)
    return jsonify({"ok": True, "rows": out, "summary": _watchlist_inbox_summary(xs)})


@app.post("/api/watchlists/inbox/mark")
def api_watchlists_inbox_mark():
    body = request.get_json(force=True) or {}
    iid = str(body.get("id") or "").strip()
    action = str(body.get("action") or "").strip().lower()
    snooze_minutes = body.get("snooze_minutes")
    if action not in ("ack", "done", "mute", "unmute", "new"):
        return jsonify({"ok": False, "error": "action must be ack|done|mute|unmute|new"}), 400
    xs = _watchlist_inbox_load()
    hit = None
    for it in xs:
        if isinstance(it, dict) and str(it.get("id") or "") == iid:
            hit = it
            break
    if not hit:
        return jsonify({"ok": False, "error": "item not found"}), 404
    now = _utc_now_iso_ms()
    hit["updated_at"] = now
    if action == "ack":
        hit["status"] = "ack"
    elif action == "done":
        hit["status"] = "done"
    elif action == "mute":
        hit["status"] = "muted"
        try:
            mins = int(snooze_minutes or 0)
        except Exception:
            mins = 0
        if mins > 0:
            until = datetime.now(timezone.utc) + timedelta(minutes=max(1, mins))
            hit["snooze_until"] = _dt_to_rfc3339_utc(until)
    elif action == "unmute":
        hit["status"] = "new"
        hit.pop("snooze_until", None)
    elif action == "new":
        hit["status"] = "new"
    _watchlist_inbox_save(xs)
    return jsonify({"ok": True, "row": hit, "summary": _watchlist_inbox_summary(xs)})


@app.get("/api/watchlists/inbox_summary")
def api_watchlists_inbox_summary():
    xs = _watchlist_inbox_load()
    return jsonify({"ok": True, "summary": _watchlist_inbox_summary(xs)})


# ------------------------------
# Data Quality Center (DQ) Phase 1
# ------------------------------

DQ_RUN_SCHEMA_VERSION = 1
DQ_FINDING_SCHEMA_VERSION = 1

DQ_RUNS_INFLIGHT: dict[str, dict[str, Any]] = {}


def _dq_run_path(run_id: str) -> Path:
    rid = str(run_id or "").strip() or "unknown"
    return (DQ_RUNS_DIR / f"{rid}.json")


def _dq_run_save(run: dict[str, Any]) -> None:
    try:
        rid = str(run.get("id") or "").strip() or uuid.uuid4().hex
        run["id"] = rid
        run.setdefault("schema_version", DQ_RUN_SCHEMA_VERSION)
        run["updated_at"] = _utc_now_iso_ms()

        DQ_RUNS_DIR.mkdir(parents=True, exist_ok=True)
        p = _dq_run_path(rid)
        tmp = p.with_suffix(p.suffix + ".tmp")
        raw = json.dumps(run, indent=2, sort_keys=True, ensure_ascii=True)
        with DQ_LOCK:
            tmp.write_text(raw, encoding="utf-8")
            tmp.replace(p)
    except Exception:
        return


def _dq_run_load(run_id: str) -> dict[str, Any] | None:
    try:
        p = _dq_run_path(run_id)
        if not p.exists():
            return None
        with DQ_LOCK:
            raw = p.read_text(encoding="utf-8", errors="replace")
        j = json.loads(raw) if raw else None
        return j if isinstance(j, dict) else None
    except Exception:
        return None


def _dq_runs_list(limit: int = 50) -> list[dict[str, Any]]:
    try:
        lim = min(200, max(1, int(limit or 50)))
    except Exception:
        lim = 50
    try:
        if not DQ_RUNS_DIR.exists():
            return []
        ps = [p for p in DQ_RUNS_DIR.iterdir() if p.is_file() and p.suffix == ".json"]
        ps.sort(key=lambda p: float(p.stat().st_mtime if p.exists() else 0), reverse=True)
        out: list[dict[str, Any]] = []
        for p in ps[:lim]:
            try:
                raw = p.read_text(encoding="utf-8", errors="replace")
                j = json.loads(raw) if raw else None
                if not isinstance(j, dict):
                    continue
                out.append({
                    "id": j.get("id"),
                    "schema_version": j.get("schema_version"),
                    "state": j.get("state"),
                    "started_at": j.get("started_at"),
                    "updated_at": j.get("updated_at"),
                    "summary": j.get("summary"),
                    "params": j.get("params"),
                    "error": j.get("error"),
                })
            except Exception:
                continue
        return out
    except Exception:
        return []


def _dq_score_from_findings(findings: list[dict[str, Any]]) -> tuple[int, str, list[dict[str, Any]]]:
    score = 100
    breakdown: list[dict[str, Any]] = []
    for f in findings:
        sev = str(f.get("severity") or "info").strip().lower()
        kind = str(f.get("kind") or "").strip()
        if sev in ("crit", "critical"):
            delta = 25
        elif sev in ("warn", "warning"):
            delta = 12
        else:
            delta = 5
        score -= delta
        breakdown.append({"kind": kind, "severity": sev, "delta": -delta, "reason": str(f.get("message") or "")[:180]})
    score = max(0, min(100, score))
    if score >= 80:
        st = "green"
    elif score >= 50:
        st = "yellow"
    else:
        st = "red"
    return score, st, breakdown


def _dq_ha_meta(entity_id: str, cache: dict[str, dict[str, Any]]) -> dict[str, Any]:
    eid = str(entity_id or "").strip()
    if not eid:
        return {"ok": True, "available": False, "error": "entity_id required", "entity": None}
    if eid in cache:
        return cache[eid]
    resolved, rerr = _resolve_ha_entity_id(eid)
    if not resolved:
        cache[eid] = {"ok": True, "available": False, "error": rerr or "invalid entity_id", "entity": None}
        return cache[eid]
    try:
        status, txt = _supervisor_get("/core/api/states/" + urllib.parse.quote(resolved, safe=""), timeout_s=8)
        if status != 200:
            cache[eid] = {"ok": True, "available": False, "error": f"HTTP {status}" if status else txt, "entity": None}
            return cache[eid]
        data = json.loads(txt) if txt else {}
        attrs = (data.get("attributes") or {}) if isinstance(data, dict) else {}
        ent = {
            "entity_id": data.get("entity_id") if isinstance(data, dict) else resolved,
            "state": data.get("state") if isinstance(data, dict) else None,
            "friendly_name": attrs.get("friendly_name"),
            "device_class": attrs.get("device_class"),
            "state_class": attrs.get("state_class"),
            "unit_of_measurement": attrs.get("unit_of_measurement"),
            "icon": attrs.get("icon"),
            "attributes": attrs,
            "resolved_entity_id": resolved,
        }
        cache[eid] = {"ok": True, "available": True, "error": None, "entity": ent}
        return cache[eid]
    except Exception as e:
        cache[eid] = {"ok": True, "available": False, "error": str(e) or e.__class__.__name__, "entity": None}
        return cache[eid]


def _dq_flux_base(cfg: dict[str, Any], *, start: str, stop: str, m: str, f: str, eid: str | None, fn: str | None) -> str:
    parts = [
        f"from(bucket: \"{cfg['bucket']}\")",
        f"  |> range(start: time(v: \"{start}\"), stop: time(v: \"{stop}\"))",
        f"  |> filter(fn: (r) => r._measurement == {_flux_str(m)})",
        f"  |> filter(fn: (r) => r._field == {_flux_str(f)})",
    ]
    if eid:
        parts.append(f"  |> filter(fn: (r) => r.entity_id == {_flux_str(eid)})")
    if fn:
        parts.append(f"  |> filter(fn: (r) => r.friendly_name == {_flux_str(fn)})")
    parts.append("  |> keep(columns: ['_time','_value','_measurement','_field','entity_id','friendly_name'])")
    parts.append("  |> sort(columns: ['_time'])")
    return "\n".join(parts) + "\n"


def _dq_series_inventory_fallback(cfg: dict[str, Any], *, start_dt: datetime, stop_dt: datetime, limit: int, q: str) -> list[dict[str, Any]]:
    if int(cfg.get("influx_version", 2)) != 2 or not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return []
    start = _dt_to_rfc3339_utc(start_dt)
    stop = _dt_to_rfc3339_utc(stop_dt)
    qtxt = str(q or '').strip().lower()
    flux = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "{start}"), stop: time(v: "{stop}"))
  |> filter(fn: (r) => exists r._measurement and exists r._field)
  |> keep(columns: ["_measurement","_field","entity_id","friendly_name"])
  |> group(columns: ["_measurement","_field","entity_id","friendly_name"])
  |> limit(n: 1)
'''
    rows = []
    seen = set()
    with v2_client(cfg) as c:
        for rec in c.query_api().query_stream(flux, org=cfg["org"]):
            vals = getattr(rec, 'values', {}) or {}
            row = {
                'measurement': str(vals.get('_measurement') or ''),
                'field': str(vals.get('_field') or ''),
                'entity_id': str(vals.get('entity_id') or ''),
                'friendly_name': str(vals.get('friendly_name') or ''),
                'last_value': None,
            }
            key = (row['measurement'], row['field'], row['entity_id'], row['friendly_name'])
            if key in seen:
                continue
            seen.add(key)
            if qtxt:
                hay = ' '.join(key).lower()
                if qtxt not in hay:
                    continue
            rows.append(row)
            if len(rows) >= max(1, int(limit or 200)):
                break
    return rows


def _dq_analyze_one(cfg: dict[str, Any], *, start_dt: datetime, stop_dt: datetime, series: dict[str, Any], ha: dict[str, Any] | None, stale_minutes: int) -> dict[str, Any]:
    m = str(series.get("measurement") or "").strip()
    f = str(series.get("field") or "").strip()
    eid = str(series.get("entity_id") or "").strip() or None
    fn = str(series.get("friendly_name") or "").strip() or None
    sk = _analysis_series_key(m, f, eid, fn)
    label = sk

    findings: list[dict[str, Any]] = []
    recs: list[str] = []
    stats: dict[str, Any] = {}

    # HA metadata findings (primary signal)
    ha_av = bool(ha and ha.get("available"))
    ent = (ha.get("entity") if isinstance(ha, dict) else None) if ha_av else None
    dc = str(ent.get("device_class") or "") if isinstance(ent, dict) else ""
    sc = str(ent.get("state_class") or "") if isinstance(ent, dict) else ""
    uom = str(ent.get("unit_of_measurement") or "") if isinstance(ent, dict) else ""
    if eid and not ha_av:
        findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "ha_missing", "severity": "warn", "message": "HA Metadaten nicht verfuegbar", "evidence": {"entity_id": eid, "error": ha.get('error') if isinstance(ha, dict) else None}})
        recs.append("Home Assistant Erreichbarkeit/Token pruefen (HA-Metadaten).")
    if eid and ha_av:
        if not dc:
            findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "ha_device_class_missing", "severity": "info", "message": "HA device_class fehlt", "evidence": {"entity_id": eid}})
            recs.append("device_class in HA pruefen/setzen.")
        if not sc:
            findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "ha_state_class_missing", "severity": "info", "message": "HA state_class fehlt", "evidence": {"entity_id": eid}})
            recs.append("state_class in HA pruefen/setzen.")
        if not uom:
            findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "ha_uom_missing", "severity": "info", "message": "HA unit_of_measurement fehlt", "evidence": {"entity_id": eid}})
            recs.append("unit_of_measurement in HA pruefen/setzen.")
        label = str(ent.get("friendly_name") or sk)

    # Influx read-only analysis
    if int(cfg.get("influx_version", 2)) != 2 or not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "influx_unavailable", "severity": "warn", "message": "Influx v2 Konfiguration nicht verfuegbar", "evidence": {"influx_version": cfg.get('influx_version')}})
        recs.append("Influx v2 Verbindung/Token/Org/Bucket pruefen.")
        score, status, breakdown = _dq_score_from_findings(findings)
        return {
            "schema_version": 1,
            "series_key": sk,
            "label": label,
            "measurement": m,
            "field": f,
            "entity_id": eid,
            "friendly_name": fn,
            "ha": ha,
            "stats": stats,
            "findings": findings,
            "recommendations": recs[:10],
            "score": score,
            "status": status,
            "score_breakdown": breakdown,
        }

    start = _dt_to_rfc3339_utc(start_dt)
    stop = _dt_to_rfc3339_utc(stop_dt)
    base = _dq_flux_base(cfg, start=start, stop=stop, m=m, f=f, eid=eid, fn=fn)

    with v2_client(cfg) as c:
        qapi = c.query_api()

        # count/first/last (works for any _value type)
        try:
            q = base + "  |> count()\n"
            tables = qapi.query(q, org=cfg["org"])
            for t in tables or []:
                for rec in getattr(t, "records", []) or []:
                    stats["count"] = int(rec.get_value() or 0)
        except Exception:
            stats["count"] = None
        try:
            q = base + "  |> first()\n"
            tables = qapi.query(q, org=cfg["org"])
            for t in tables or []:
                for rec in getattr(t, "records", []) or []:
                    stats["oldest_time"] = _dt_to_rfc3339_utc(rec.get_time()) if isinstance(rec.get_time(), datetime) else rec.get_time()
                    stats["oldest_value"] = rec.get_value()
        except Exception:
            pass
        try:
            q = base + "  |> last()\n"
            tables = qapi.query(q, org=cfg["org"])
            for t in tables or []:
                for rec in getattr(t, "records", []) or []:
                    stats["newest_time"] = _dt_to_rfc3339_utc(rec.get_time()) if isinstance(rec.get_time(), datetime) else rec.get_time()
                    stats["newest_value"] = rec.get_value()
        except Exception:
            pass

        # max gap in seconds (time-only)
        try:
            q = base + "  |> elapsed(unit: 1s)\n  |> max(column: 'elapsed')\n"
            tables = qapi.query(q, org=cfg["org"])
            for t in tables or []:
                for rec in getattr(t, "records", []) or []:
                    stats["max_gap_seconds"] = int(rec.get_value() or 0)
        except Exception:
            pass

        # numeric-only checks (best-effort)
        try:
            q = base + "  |> map(fn: (r) => ({r with _value: float(v: r._value)}))\n  |> filter(fn: (r) => r._value < 0.0)\n  |> count()\n"
            tables = qapi.query(q, org=cfg["org"])
            for t in tables or []:
                for rec in getattr(t, "records", []) or []:
                    stats["negative_count"] = int(rec.get_value() or 0)
        except Exception:
            stats["negative_count"] = None

        try:
            q = base + "  |> map(fn: (r) => ({r with _value: float(v: r._value)}))\n  |> filter(fn: (r) => r._value == 0.0)\n  |> count()\n"
            tables = qapi.query(q, org=cfg["org"])
            for t in tables or []:
                for rec in getattr(t, "records", []) or []:
                    stats["zero_count"] = int(rec.get_value() or 0)
        except Exception:
            stats["zero_count"] = None

        # counter-reset hint: negative differences in window
        try:
            q = base + "  |> map(fn: (r) => ({r with _value: float(v: r._value)}))\n  |> limit(n: 2000)\n  |> difference(nonNegative: false)\n  |> filter(fn: (r) => r._value < 0.0)\n  |> count()\n"
            tables = qapi.query(q, org=cfg["org"])
            for t in tables or []:
                for rec in getattr(t, "records", []) or []:
                    stats["neg_diff_count"] = int(rec.get_value() or 0)
        except Exception:
            stats["neg_diff_count"] = None

    # Findings from stats
    newest_s = str(stats.get("newest_time") or "").strip() or None
    if newest_s:
        try:
            dt0 = _trace_parse_iso(newest_s)
            if dt0 and dt0 < (datetime.now(timezone.utc) - timedelta(minutes=max(1, int(stale_minutes or 60)))):
                findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "stale", "severity": "crit", "message": f"keine Daten seit > {int(stale_minutes)}min", "evidence": {"newest_time": newest_s}})
                recs.append("Pruefe Influx Schreibfrequenz / HA Update / Netz.")
        except Exception:
            pass

    try:
        mg = int(stats.get("max_gap_seconds") or 0)
        if mg >= int(max(1, stale_minutes)) * 60:
            sev = "warn" if mg < int(max(1, stale_minutes)) * 120 else "crit"
            findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "gaps", "severity": sev, "message": "Luecken im Zeitfenster", "evidence": {"max_gap_seconds": mg}})
            recs.append("Datenluecken analysieren (Recorder/HA/Influx).")
    except Exception:
        pass

    try:
        neg = stats.get("negative_count")
        if isinstance(neg, int) and neg > 0:
            sev = "warn"
            if sc in ("total_increasing", "total"):
                sev = "crit"
            findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "negative_values", "severity": sev, "message": "negative Werte im Zeitfenster", "evidence": {"negative_count": neg, "state_class": sc}})
            recs.append("Negative Werte pruefen (Sensor, Template, Einheit).")
    except Exception:
        pass

    try:
        zd = stats.get("zero_count")
        cnt = stats.get("count")
        if isinstance(zd, int) and isinstance(cnt, int) and cnt > 0:
            ratio = float(zd) / float(cnt)
            if ratio >= 0.5 and zd >= 10:
                findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "zero_spikes", "severity": "warn", "message": "ungewoehnlich viele Nullwerte", "evidence": {"zero_count": zd, "count": cnt, "ratio": round(ratio, 3)}})
                recs.append("Nullwerte/Ungueltig-Regeln pruefen (Template/Integration).")
    except Exception:
        pass

    try:
        nd = stats.get("neg_diff_count")
        if isinstance(nd, int) and nd > 0 and sc in ("total_increasing", "total"):
            findings.append({"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "counter_reset_hint", "severity": "crit", "message": "Hinweis auf Counter-Reset (negative Differenzen)", "evidence": {"neg_diff_count": nd, "state_class": sc}})
            recs.append("Counter-Reset pruefen; ggf. state_class/Integration korrigieren.")
    except Exception:
        pass

    score, status, breakdown = _dq_score_from_findings(findings)
    return {
        "schema_version": 1,
        "series_key": sk,
        "label": label,
        "measurement": m,
        "field": f,
        "entity_id": eid,
        "friendly_name": fn,
        "ha": ha,
        "stats": stats,
        "findings": findings,
        "recommendations": recs[:10],
        "score": score,
        "status": status,
        "score_breakdown": breakdown,
    }


def _dq_quality_run_thread(run_id: str) -> None:
    rid = str(run_id or "").strip()
    run = _dq_run_load(rid) or {"id": rid}
    run["state"] = "running"
    run["updated_at"] = _utc_now_iso_ms()
    _dq_run_save(run)

    try:
        cfg = _overlay_from_yaml_if_enabled(load_cfg())
        params = run.get("params") if isinstance(run.get("params"), dict) else {}
        try:
            days = int(params.get("days") or 30)
        except Exception:
            days = 30
        days = max(1, min(3650, days))
        try:
            limit = int(params.get("limit") or 200)
        except Exception:
            limit = 200
        limit = max(1, min(1000, limit))
        q = str(params.get("q") or "").strip()
        try:
            stale_minutes = int(params.get("stale_minutes") or 60)
        except Exception:
            stale_minutes = 60
        stale_minutes = max(1, min(525600, stale_minutes))

        stop_dt = datetime.now(timezone.utc)
        start_dt = stop_dt - timedelta(days=days)

        # Base series set (best-effort): use existing inventory query (read-only).
        try:
            inv = _build_series_inventory(
                cfg,
                days=days,
                limit=limit,
                offset=0,
                state="",
                q=q,
                field_filter=None,
                stale_days=max(1, min(3650, int(max(1, stale_minutes) / (60 * 24)))) if stale_minutes else 30,
                enrich_n=0,
            )
            rows = inv.get("rows") if isinstance(inv, dict) and isinstance(inv.get("rows"), list) else []
        except Exception:
            rows = _dq_series_inventory_fallback(cfg, start_dt=start_dt, stop_dt=stop_dt, limit=limit, q=q)

        ha_cache: dict[str, dict[str, Any]] = {}
        items: list[dict[str, Any]] = []
        errors = 0

        for i, r in enumerate(rows[:limit]):
            if not isinstance(r, dict):
                continue
            try:
                eid = str(r.get("entity_id") or "").strip()
                ha = _dq_ha_meta(eid, ha_cache) if eid else {"ok": True, "available": False, "error": "no entity_id", "entity": None}
                it = _dq_analyze_one(cfg, start_dt=start_dt, stop_dt=stop_dt, series=r, ha=ha, stale_minutes=stale_minutes)
                items.append(it)
            except Exception as e:
                errors += 1
                items.append({
                    "schema_version": 1,
                    "series_key": _analysis_series_key(str(r.get('measurement') or ''), str(r.get('field') or ''), str(r.get('entity_id') or '') or None, str(r.get('friendly_name') or '') or None),
                    "label": str(r.get("measurement") or "") + "/" + str(r.get("field") or ""),
                    "measurement": r.get("measurement"),
                    "field": r.get("field"),
                    "entity_id": r.get("entity_id"),
                    "friendly_name": r.get("friendly_name"),
                    "ha": None,
                    "stats": {},
                    "findings": [{"schema_version": DQ_FINDING_SCHEMA_VERSION, "kind": "analyze_error", "severity": "warn", "message": str(e) or e.__class__.__name__, "evidence": {"index": i}}],
                    "recommendations": ["Serie separat pruefen; Fehler blockiert den Lauf nicht."],
                    "score": 50,
                    "status": "yellow",
                    "score_breakdown": [],
                })
                continue

            if i % 20 == 0:
                run["updated_at"] = _utc_now_iso_ms()
                run["state"] = "running"
                run["progress"] = {"done": i + 1, "total": min(len(rows), limit)}
                _dq_run_save(run)

        # Summaries
        green = len([x for x in items if isinstance(x, dict) and str(x.get("status") or "") == "green"])
        yellow = len([x for x in items if isinstance(x, dict) and str(x.get("status") or "") == "yellow"])
        red = len([x for x in items if isinstance(x, dict) and str(x.get("status") or "") == "red"])
        run["items"] = items
        run["summary"] = {
            "items": len(items),
            "green": green,
            "yellow": yellow,
            "red": red,
            "errors": int(errors),
        }
        run["state"] = "done"
        run["finished_at"] = _utc_now_iso_ms()
        _dq_run_save(run)
    except Exception as e:
        run["state"] = "error"
        run["error"] = str(e) or e.__class__.__name__
        run["finished_at"] = _utc_now_iso_ms()
        _dq_run_save(run)
    finally:
        with DQ_LOCK:
            DQ_RUNS_INFLIGHT.pop(rid, None)


def _dq_quality_run_start(params: dict[str, Any]) -> str:
    rid = uuid.uuid4().hex

    def _int(name: str, default: int, lo: int, hi: int) -> int:
        try:
            v = int(params.get(name) if isinstance(params, dict) else default)
        except Exception:
            v = default
        return max(lo, min(hi, v))

    run = {
        "id": rid,
        "schema_version": DQ_RUN_SCHEMA_VERSION,
        "created_at": _utc_now_iso_ms(),
        "started_at": _utc_now_iso_ms(),
        "updated_at": _utc_now_iso_ms(),
        "state": "starting",
        "params": {
            "days": _int("days", 30, 1, 3650),
            "limit": _int("limit", 200, 1, 1000),
            "q": str(params.get("q") or "").strip(),
            "stale_minutes": _int("stale_minutes", 60, 1, 525600),
        },
        "items": [],
        "summary": {},
    }
    _dq_run_save(run)
    with DQ_LOCK:
        DQ_RUNS_INFLIGHT[rid] = {"id": rid, "state": "starting", "started_at": run["started_at"]}
    th = threading.Thread(target=_dq_quality_run_thread, args=(rid,), daemon=True)
    th.start()
    return rid


@app.post("/api/dq/quality_run/start")
def api_dq_quality_run_start():
    body = request.get_json(force=True) or {}
    try:
        rid = _dq_quality_run_start(body if isinstance(body, dict) else {})
        return jsonify({"ok": True, "run_id": rid})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 500


@app.get("/api/dq/quality_run")
def api_dq_quality_run_get():
    rid = str(request.args.get("id") or "").strip()
    if not rid:
        return jsonify({"ok": False, "error": "id required"}), 400
    run = _dq_run_load(rid)
    if not run:
        return jsonify({"ok": False, "error": "run not found"}), 404
    return jsonify({"ok": True, "run": run})


@app.get("/api/dq/quality_runs")
def api_dq_quality_runs_list():
    try:
        limit = int(request.args.get("limit") or 50)
    except Exception:
        limit = 50
    return jsonify({"ok": True, "runs": _dq_runs_list(limit)})


@app.get("/api/dq/orphans")
def api_dq_orphans():
    """List orphan candidates (series with ha_missing) from a DQ quality run.

    This is a lightweight view for Epic #406 (Module: Verwaiste Messwerte).
    """

    rid = str(request.args.get("run_id") or "").strip()
    try:
        limit = int(request.args.get("limit") or 200)
    except Exception:
        limit = 200
    limit = max(1, min(2000, limit))

    if not rid:
        # Prefer latest done run.
        for r in _dq_runs_list(50):
            if isinstance(r, dict) and str(r.get("state") or "") == "done" and str(r.get("id") or ""):
                rid = str(r.get("id") or "")
                break

    if not rid:
        return jsonify({"ok": True, "run_id": None, "orphans": [], "total": 0, "error": "no dq run found"})

    run = _dq_run_load(rid)
    if not run:
        return jsonify({"ok": False, "error": "run not found"}), 404

    items = run.get("items") if isinstance(run.get("items"), list) else []
    out: list[dict[str, Any]] = []
    for it in items:
        if not isinstance(it, dict):
            continue
        eid = str(it.get("entity_id") or "").strip()
        if not eid:
            continue
        findings = it.get("findings") if isinstance(it.get("findings"), list) else []
        ha_missing = next((f for f in findings if isinstance(f, dict) and str(f.get("kind") or "") == "ha_missing"), None)
        if not ha_missing:
            continue
        ha_err = None
        try:
            ev = ha_missing.get("evidence") if isinstance(ha_missing.get("evidence"), dict) else {}
            ha_err = ev.get("error")
        except Exception:
            ha_err = None
        stats = it.get("stats") if isinstance(it.get("stats"), dict) else {}
        out.append({
            "series_key": it.get("series_key"),
            "measurement": it.get("measurement"),
            "field": it.get("field"),
            "entity_id": eid,
            "friendly_name": it.get("friendly_name"),
            "newest_time": stats.get("newest_time"),
            "score": it.get("score"),
            "status": it.get("status"),
            "ha_error": ha_err,
            "recommendations": it.get("recommendations"),
        })
        if len(out) >= limit:
            break

    return jsonify({
        "ok": True,
        "run_id": rid,
        "run_state": run.get("state"),
        "orphans": out,
        "total": len(out),
    })


@app.get("/api/dq/merge_candidates")
def api_dq_merge_candidates():
    """Suggest merge candidates for entity_id renames (best-effort).

    Heuristic:
    - within one DQ run, find pairs with same measurement+field+friendly_name
    - one side HA available, other side HA missing

    This is a supporting view for Epic #406 (Module: Zusammenfuehren).
    """

    rid = str(request.args.get("run_id") or "").strip()
    try:
        limit = int(request.args.get("limit") or 200)
    except Exception:
        limit = 200
    limit = max(1, min(2000, limit))

    if not rid:
        for r in _dq_runs_list(50):
            if isinstance(r, dict) and str(r.get("state") or "") == "done" and str(r.get("id") or ""):
                rid = str(r.get("id") or "")
                break

    if not rid:
        return jsonify({"ok": True, "run_id": None, "candidates": [], "total": 0, "error": "no dq run found"})

    run = _dq_run_load(rid)
    if not run:
        return jsonify({"ok": False, "error": "run not found"}), 404

    items = run.get("items") if isinstance(run.get("items"), list) else []

    def _ha_av(it: dict[str, Any]) -> bool:
        try:
            ha = it.get("ha") if isinstance(it.get("ha"), dict) else {}
            return bool(ha.get("available"))
        except Exception:
            return False

    # Key by (measurement, field, friendly_name)
    by_key: dict[tuple[str, str, str], list[dict[str, Any]]] = {}
    for it in items:
        if not isinstance(it, dict):
            continue
        m = str(it.get("measurement") or "").strip()
        f = str(it.get("field") or "").strip()
        fn = str(it.get("friendly_name") or "").strip()
        eid = str(it.get("entity_id") or "").strip()
        if not m or not f or not fn or not eid:
            continue
        by_key.setdefault((m, f, fn), []).append(it)

    out: list[dict[str, Any]] = []
    seen: set[str] = set()
    for (m, f, fn), xs in by_key.items():
        if len(xs) < 2:
            continue
        av = [x for x in xs if _ha_av(x)]
        miss = [x for x in xs if not _ha_av(x)]
        if not av or not miss:
            continue

        # Prefer highest score target among HA-available.
        av.sort(key=lambda x: int(x.get("score") or 0), reverse=True)
        tgt = av[0]

        # Collect sources (ha_missing) as candidates.
        for src in miss:
            src_e = str(src.get("entity_id") or "").strip()
            tgt_e = str(tgt.get("entity_id") or "").strip()
            if not src_e or not tgt_e or src_e == tgt_e:
                continue
            key2 = f"{m}|{f}|{fn}|{src_e}|{tgt_e}"
            if key2 in seen:
                continue
            seen.add(key2)

            # Extract HA error (if present)
            ha_err = None
            try:
                finds = src.get("findings") if isinstance(src.get("findings"), list) else []
                hm = next((ff for ff in finds if isinstance(ff, dict) and str(ff.get("kind") or "") == "ha_missing"), None)
                if hm and isinstance(hm.get("evidence"), dict):
                    ha_err = hm.get("evidence", {}).get("error")
            except Exception:
                ha_err = None

            out.append({
                "measurement": m,
                "field": f,
                "friendly_name": fn,
                "source": {
                    "entity_id": src_e,
                    "series_key": src.get("series_key"),
                    "newest_time": (src.get("stats") or {}).get("newest_time") if isinstance(src.get("stats"), dict) else None,
                    "score": src.get("score"),
                    "ha_error": ha_err,
                },
                "target": {
                    "entity_id": tgt_e,
                    "series_key": tgt.get("series_key"),
                    "newest_time": (tgt.get("stats") or {}).get("newest_time") if isinstance(tgt.get("stats"), dict) else None,
                    "score": tgt.get("score"),
                },
                "hint": "Umbenennung vermutet (gleicher friendly_name; Quelle HA-fehlt)",
            })

            if len(out) >= limit:
                break
        if len(out) >= limit:
            break

    return jsonify({
        "ok": True,
        "run_id": rid,
        "run_state": run.get("state"),
        "candidates": out,
        "total": len(out),
    })


@app.get("/api/dq/migration_candidates")
def api_dq_migration_candidates():
    """Suggest simple migration candidates.

    Current scope (MVP): entity_id without domain (object_id only) that can be
    resolved to a concrete HA entity_id (e.g. "kitchen_temp" -> "sensor.kitchen_temp").

    This supports Epic #406 (Module: Migration).
    """

    rid = str(request.args.get("run_id") or "").strip()
    try:
        limit = int(request.args.get("limit") or 200)
    except Exception:
        limit = 200
    limit = max(1, min(2000, limit))

    if not rid:
        for r in _dq_runs_list(50):
            if isinstance(r, dict) and str(r.get("state") or "") == "done" and str(r.get("id") or ""):
                rid = str(r.get("id") or "")
                break

    if not rid:
        return jsonify({"ok": True, "run_id": None, "candidates": [], "total": 0, "error": "no dq run found"})

    run = _dq_run_load(rid)
    if not run:
        return jsonify({"ok": False, "error": "run not found"}), 404

    items = run.get("items") if isinstance(run.get("items"), list) else []
    out: list[dict[str, Any]] = []
    seen: set[str] = set()

    for it in items:
        if not isinstance(it, dict):
            continue
        raw_eid = str(it.get("entity_id") or "").strip()
        if not raw_eid:
            continue
        if "." in raw_eid:
            continue
        resolved, rerr = _resolve_ha_entity_id(raw_eid)
        if not resolved or rerr:
            continue
        if resolved == raw_eid:
            continue

        m = str(it.get("measurement") or "").strip()
        f = str(it.get("field") or "").strip()
        fn = str(it.get("friendly_name") or "").strip()
        if not m or not f:
            continue

        k = f"{m}|{f}|{raw_eid}|{resolved}|{fn}"
        if k in seen:
            continue
        seen.add(k)

        out.append({
            "measurement": m,
            "field": f,
            "friendly_name": fn,
            "source_entity_id": raw_eid,
            "target_entity_id": resolved,
            "hint": "entity_id ohne Domain kann auf HA Entity aufgeloest werden",
        })
        if len(out) >= limit:
            break

    return jsonify({
        "ok": True,
        "run_id": rid,
        "run_state": run.get("state"),
        "candidates": out,
        "total": len(out),
    })


def _dq_points_from_bucket_v2(
    cfg: dict[str, Any],
    *,
    bucket: str,
    measurement: str,
    field: str,
    entity_id: str | None,
    friendly_name: str | None,
    start_dt: datetime,
    stop_dt: datetime,
    max_points: int,
    agg_fn: str = "max",
) -> dict[str, Any]:
    """Fetch time/value rows from a given bucket (best-effort), with optional downsampling."""

    extra = flux_tag_filter(entity_id, friendly_name)
    dur_ms = max(0.0, (stop_dt - start_dt).total_seconds() * 1000.0)
    every_ms = int(math.ceil(dur_ms / float(max_points))) if (dur_ms > 0 and max_points > 0) else 1
    if every_ms < 1:
        every_ms = 1

    agg_fn = str(agg_fn or "max").strip().lower()
    if agg_fn not in ("max", "min"):
        agg_fn = "max"

    start = _dt_to_rfc3339_utc(start_dt)
    stop = _dt_to_rfc3339_utc(stop_dt)

    agg = ""
    mode = "raw"
    if every_ms > 1:
        agg = f'  |> aggregateWindow(every: {every_ms}ms, fn: {agg_fn}, createEmpty: false)\n'
        mode = f"downsample_{agg_fn}"

    q = f'''
from(bucket: "{bucket}")
  |> range(start: time(v: "{start}"), stop: time(v: "{stop}"))
  |> filter(fn: (r) => r._measurement == {_flux_str(measurement)} and r._field == {_flux_str(field)}{extra})
{agg}  |> keep(columns: ["_time","_value"])
  |> sort(columns: ["_time"], desc: false)
  |> limit(n: {int(max_points)})
'''

    rows: list[dict[str, Any]] = []
    non_numeric = 0
    with v2_client(cfg) as c:
        qapi = c.query_api()
        for rec in qapi.query_stream(q, org=cfg["org"]):
            try:
                ts = rec.get_time()
                val = rec.get_value()
                if not isinstance(ts, datetime):
                    continue
                # Normalize to numeric where possible.
                if isinstance(val, bool):
                    val2: float | int = 1 if val else 0
                elif isinstance(val, (int, float)):
                    val2 = val
                else:
                    non_numeric += 1
                    continue
                rows.append({"time": _dt_to_rfc3339_utc_ms(ts), "value": val2})
            except Exception:
                continue

    return {
        "bucket": bucket,
        "measurement": measurement,
        "field": field,
        "rows": rows,
        "meta": {
            "mode": mode,
            "every_ms": every_ms,
            "max_points": int(max_points),
            "agg_fn": agg_fn,
            "non_numeric_skipped": int(non_numeric),
            "query_language": "flux",
            "query": q.strip(),
        },
    }


def _rollup_window_key(win: str) -> str:
    s = re.sub(r"[^0-9A-Za-z]+", "_", str(win or "")).strip("_")
    return s or "win"


@app.post("/api/dq/multi_resolution")
def api_dq_multi_resolution():
    """Read-only multi-resolution graph data (Raw/Clean/Rollup).

    Part of Epic #406 (Module: Multi-Resolution Graph).
    """

    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    if int(cfg.get("influx_version", 2) or 2) != 2:
        return jsonify({"ok": False, "error": "InfluxDB v2 required"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({"ok": False, "error": "InfluxDB v2 requires token, org, bucket"}), 400

    body = request.get_json(force=True) or {}
    measurement = str(body.get("measurement") or "").strip()
    field = str(body.get("field") or "").strip()
    entity_id = str(body.get("entity_id") or "").strip() or None
    friendly_name = str(body.get("friendly_name") or "").strip() or None
    if not measurement or not field:
        return jsonify({"ok": False, "error": "measurement and field required"}), 400

    # Range: explicit start/stop or derived from days.
    start_dt = None
    stop_dt = None
    if body.get("start") and body.get("stop"):
        try:
            start_dt, stop_dt = _get_start_stop_from_payload(body)
        except Exception as e:
            return jsonify({"ok": False, "error": f"invalid start/stop: {e}"}), 400
    if not start_dt or not stop_dt:
        try:
            days = int(body.get("days") or 30)
        except Exception:
            days = 30
        days = max(1, min(3650, days))
        stop_dt = datetime.now(timezone.utc)
        start_dt = stop_dt - timedelta(days=days)

    try:
        max_points = int(body.get("max_points") or 1200)
    except Exception:
        max_points = 1200
    max_points = max(50, min(20000, max_points))

    qcfg = _quality_cfg_view(cfg)
    raw_bucket = str(qcfg.get("raw_bucket") or cfg.get("quality_raw_bucket") or "").strip()
    clean_bucket = str(qcfg.get("clean_bucket") or cfg.get("quality_clean_bucket") or "").strip()
    rollup_bucket = str(qcfg.get("rollup_bucket") or cfg.get("quality_rollup_bucket") or "").strip()

    out: dict[str, Any] = {
        "ok": True,
        "range": {"start": _dt_to_rfc3339_utc_full(start_dt), "stop": _dt_to_rfc3339_utc_full(stop_dt)},
        "series": {"measurement": measurement, "field": field, "entity_id": entity_id, "friendly_name": friendly_name},
        "quality": {"raw_bucket": raw_bucket, "clean_bucket": clean_bucket, "rollup_bucket": rollup_bucket, "rollups": qcfg.get("rollups")},
        "raw": None,
        "clean": None,
        "rollup": {"bucket": rollup_bucket, "levels": []},
    }

    # Raw/Clean
    try:
        if raw_bucket:
            out["raw"] = _dq_points_from_bucket_v2(cfg, bucket=raw_bucket, measurement=measurement, field=field, entity_id=entity_id, friendly_name=friendly_name, start_dt=start_dt, stop_dt=stop_dt, max_points=max_points, agg_fn="max")
    except Exception as e:
        out["raw"] = {"bucket": raw_bucket, "error": _short_influx_error(e)}
    try:
        if clean_bucket:
            out["clean"] = _dq_points_from_bucket_v2(cfg, bucket=clean_bucket, measurement=measurement, field=field, entity_id=entity_id, friendly_name=friendly_name, start_dt=start_dt, stop_dt=stop_dt, max_points=max_points, agg_fn="max")
    except Exception as e:
        out["clean"] = {"bucket": clean_bucket, "error": _short_influx_error(e)}

    # Rollup: try to pick a sensible field per window.
    levels = qcfg.get("rollups") if isinstance(qcfg.get("rollups"), list) else []
    for lv in levels:
        if not isinstance(lv, dict):
            continue
        win = str(lv.get("window") or "").strip()
        name = str(lv.get("name") or win).strip() or win
        if not win:
            continue
        win_s = _rollup_window_key(win)
        tried = [
            f"{field}__mean__{win_s}",
            f"{field}__last__{win_s}",
            f"{field}__max__{win_s}",
            f"{field}__min__{win_s}",
        ]
        chosen = None
        chosen_res = None
        err = None
        if rollup_bucket:
            for cand in tried:
                try:
                    res = _dq_points_from_bucket_v2(cfg, bucket=rollup_bucket, measurement=measurement, field=cand, entity_id=entity_id, friendly_name=friendly_name, start_dt=start_dt, stop_dt=stop_dt, max_points=max_points, agg_fn="max")
                    if isinstance(res, dict) and isinstance(res.get("rows"), list) and len(res.get("rows")):
                        chosen = cand
                        chosen_res = res
                        break
                except Exception as e:
                    err = _short_influx_error(e)
                    continue

        out["rollup"]["levels"].append({
            "name": name,
            "window": win,
            "window_key": win_s,
            "field_chosen": chosen,
            "fields_tried": tried,
            "data": chosen_res,
            "error": err,
        })

    return jsonify(out)


