@app.post("/api/icon_svg/set")
def api_icon_svg_set():
    """Set (or delete) icon SVG overrides.

    Input format:
    - {"key": "...data-ui...", "svg": "<svg...>...</svg>"}
    - {"items": {"<data-ui>": "<svg...>", "<data-ui2>": null}}
    """

    body = request.get_json(force=True) or {}
    items = body.get("items") if isinstance(body, dict) else None
    if items is None:
        k = body.get("key") if isinstance(body, dict) else None
        v = body.get("svg") if isinstance(body, dict) else None
        items = {k: v} if k else {}

    if not isinstance(items, dict):
        return jsonify({"ok": False, "error": "items must be an object"}), 400

    st = _ui_state_load()
    changed = 0
    deleted = 0
    rejected = 0

    for ui_key0, svg0 in items.items():
        try:
            ui_key = str(ui_key0 or "").strip()
        except Exception:
            rejected += 1
            continue
        if not ui_key or len(ui_key) > 160:
            rejected += 1
            continue

        state_key = _icon_svg_state_key(ui_key)
        if not _ui_state_key_ok(state_key):
            rejected += 1
            continue

        # Delete
        if svg0 is None or (isinstance(svg0, str) and not svg0.strip()):
            if state_key in st:
                st.pop(state_key, None)
                deleted += 1
            continue

        if not isinstance(svg0, str):
            rejected += 1
            continue

        svg, err, status = _svg_sanitize(svg0)
        if err:
            # Hard fail for single item writes (more user-friendly).
            if len(items) == 1:
                return jsonify({"ok": False, "error": err}), int(status or 400)
            rejected += 1
            continue
        if svg is None:
            rejected += 1
            continue
        if not _ui_state_val_ok(svg):
            if len(items) == 1:
                return jsonify({"ok": False, "error": "svg too large"}), 413
            rejected += 1
            continue

        if st.get(state_key) != svg:
            st[state_key] = svg
            changed += 1

    if changed or deleted:
        _ui_state_save(st)

    return jsonify({
        "ok": True,
        "changed": changed,
        "deleted": deleted,
        "rejected": rejected,
        "total": len(st),
    })


@app.post("/api/ui_state/set")
def api_ui_state_set():
    body = request.get_json(force=True) or {}

    items = body.get("items") if isinstance(body, dict) else None
    if items is None:
        # also allow single key/value
        k = body.get("key") if isinstance(body, dict) else None
        v = body.get("value") if isinstance(body, dict) else None
        items = {k: v} if k else {}

    if not isinstance(items, dict):
        return jsonify({"ok": False, "error": "items must be an object"}), 400

    st = _ui_state_load()
    changed = 0
    deleted = 0

    for k0, v0 in items.items():
        k = str(k0 or "").strip()
        if not _ui_state_key_ok(k):
            continue

        if v0 is None:
            if k in st:
                st.pop(k, None)
                deleted += 1
            continue

        # store as string (raw); caller can store JSON string if needed
        v = v0 if isinstance(v0, str) else json.dumps(v0, ensure_ascii=True)
        if not _ui_state_val_ok(v):
            continue
        if st.get(k) != v:
            st[k] = v
            changed += 1

    if changed or deleted:
        _ui_state_save(st)

    return jsonify({"ok": True, "changed": changed, "deleted": deleted, "total": len(st)})


@app.post("/api/ui_state/prune")
def api_ui_state_prune():
    body = request.get_json(force=True) or {}
    prefix = str(body.get("prefix") or "").strip()
    keep = body.get("keep")
    if not prefix:
        return jsonify({"ok": False, "error": "prefix required"}), 400
    if not _ui_state_key_ok(prefix):
        return jsonify({"ok": False, "error": "invalid prefix"}), 400
    if keep is None:
        keep = []
    if not isinstance(keep, list):
        return jsonify({"ok": False, "error": "keep must be a list"}), 400

    keep_set: set[str] = set()
    for k0 in keep:
        try:
            k = str(k0 or "").strip()
        except Exception:
            continue
        if not _ui_state_key_ok(k):
            continue
        if not k.startswith(prefix):
            continue
        keep_set.add(k)

    st = _ui_state_load()
    to_del = [k for k in st.keys() if isinstance(k, str) and k.startswith(prefix) and k not in keep_set]
    for k in to_del:
        st.pop(k, None)
    if to_del:
        _ui_state_save(st)
    return jsonify({"ok": True, "deleted": len(to_del), "prefix": prefix})


