@app.post("/api/app_state/set")
def api_app_state_set():
    body = request.get_json(force=True) or {}
    scope = str(body.get("scope") or "").strip()
    state = body.get("state") if isinstance(body.get("state"), dict) else None
    if not scope:
        return jsonify({"ok": False, "error": "scope required"}), 400
    if not _app_state_scope_ok(scope):
        return jsonify({"ok": False, "error": "invalid scope"}), 400
    if state is None:
        return jsonify({"ok": False, "error": "state must be an object"}), 400
    if not _app_state_size_ok(state):
        return jsonify({"ok": False, "error": "state too large"}), 413
    st = _app_state_load()
    prev = st.get(scope) if isinstance(st.get(scope), dict) else {}
    st[scope] = state
    _app_state_save(st)
    try:
        cfg = load_cfg()
        if _config_log_enabled(cfg):
            changes = []
            keys = sorted(set(prev.keys()) | set(state.keys()))
            for key in keys:
                old = prev.get(key)
                new = state.get(key)
                if old == new:
                    continue
                changes.append({"field": key, "old": _config_log_redact(key, old), "new": _config_log_redact(key, new)})
            if changes:
                LOG.info(_config_log_format({
                    "page": "server",
                    "area": scope,
                    "field": scope,
                    "source": "app_state",
                    "scope": scope,
                    "storage_key": APP_STATE_PATH.name,
                    "changes": changes,
                }))
    except Exception:
        pass
    return jsonify({"ok": True, "scope": scope})


