    try:
        path.unlink(missing_ok=True)
    except Exception as e:
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 500

    # adjust active if needed
    if _active_profile_get() == pid:
        xs = _profile_list()
