@app.post("/api/series_stats")
def api_series_stats():
    """Return basic stats for a measurement/field series."""
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}
    measurement = str(body.get("measurement") or "").strip()
    field = str(body.get("field") or "").strip()
    entity_id = str(body.get("entity_id") or "").strip() or None
    friendly_name = str(body.get("friendly_name") or "").strip() or None

    LOG.info("api.series_stats measurement=%s field=%s entity_id=%s",
        measurement, field, entity_id)

    if not measurement or not field:
        return jsonify({"ok": False, "error": "measurement and field required"}), 400

    try:
        with v2_client(cfg) as c:
            qapi = c.query_api()
            # Get count, min, max, first, last
            q = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: -10y)
  |> filter(fn: (r) => r._measurement == "{measurement}")
  |> filter(fn: (r) => r._field == "{field}")'''
            if entity_id:
                q += f'\n  |> filter(fn: (r) => r.entity_id == "{entity_id}")'
            if friendly_name:
                q += f'\n  |> filter(fn: (r) => r.friendly_name == "{friendly_name}")'
            q += '''
  |> group()
  |> sort(columns: ["_time"])
'''
            # Run multiple aggregations
            count_q = q + '  |> count()\n'
            min_q = q + '  |> min()\n'
            max_q = q + '  |> max()\n'
            first_q = q + '  |> first()\n'
            last_q = q + '  |> last()\n'

            stats: dict[str, Any] = {}
            try:
                for rec in qapi.query(count_q, org=cfg["org"]):
                    stats["count"] = rec.get_value()
            except Exception:
                pass
            try:
                for rec in qapi.query(min_q, org=cfg["org"]):
                    stats["min"] = rec.get_value()
            except Exception:
                pass
            try:
                for rec in qapi.query(max_q, org=cfg["org"]):
                    stats["max"] = rec.get_value()
            except Exception:
                pass
            try:
                for rec in qapi.query(first_q, org=cfg["org"]):
                    stats["oldest_time"] = rec.get_time()
                    stats["current_value"] = rec.get_value()
            except Exception:
                pass
            try:
                for rec in qapi.query(last_q, org=cfg["org"]):
                    stats["newest_time"] = rec.get_time()
                    stats["current_value"] = rec.get_value()
            except Exception:
                pass

            return jsonify({"ok": True, "stats": stats})
    except Exception as e:
        LOG.error("api.series_stats error: %s", e)
        return jsonify({"ok": False, "error": str(e)}), 500


def _client_event_log(kind_hint: str) -> Response:
    try:
        body = request.get_json(force=True) or {}
    except Exception:
        body = {}

    try:
        page = str(body.get("page") or "").strip()[:80]
        message = str(body.get("message") or "").strip()[:500]
        href = str(body.get("href") or "").strip()[:500]
        ua = str(body.get("ua") or "").strip()[:200]
        stack = str(body.get("stack") or "").strip()[:4000]
        extra = body.get("extra")
        try:
            extra_s = json.dumps(extra, ensure_ascii=True)[:2000] if extra is not None else ""
        except Exception:
            extra_s = str(extra)[:2000] if extra is not None else ""

        kind = ""
        if isinstance(extra, dict):
            try:
                kind = str(extra.get("kind") or "").strip().lower()
            except Exception:
                kind = ""

        log_fn = LOG.error if kind_hint == "error" else LOG.info
        if kind in ("analysis_debug", "selector_debug", "ui_debug"):
            log_fn = LOG.info

        log_fn(
            "client_%s page=%s msg=%s href=%s ua=%s stack=%s extra=%s",
            kind_hint,
            page,
            message,
            href,
            ua,
            stack,
            extra_s,
        )
        _perf_event_record(
            event_key=("client:error:" + (kind or kind_hint or "event")) if kind_hint == "error" else ("client:log:" + (kind or kind_hint or "event")),
            event_type="client_error" if kind_hint == "error" else "client_log",
            source="client",
            status="err" if kind_hint == "error" else "ok",
            page=page,
            ui=str((extra or {}).get("source") or "")[:120] if isinstance(extra, dict) else "",
            detail=message or kind or kind_hint,
            duration_ms=None,
            toggle_allowed=(kind_hint != "error"),
            is_error=(kind_hint == "error"),
            extra={"href": href[:200], "kind": kind[:60]},
        )
    except Exception:
        # Never fail the request.
        pass

    return jsonify({"ok": True})


def _perf_stats_bucket_add(
    buckets: dict[str, dict[str, Any]],
    *,
    event_key: str,
    event_type: str,
    source: str,
    at: str,
    duration_ms: int | None,
    status: str,
    page: str = "",
    ui: str = "",
    detail: str = "",
    toggle_allowed: bool = True,
    is_error: bool = False,
) -> None:
    key = str(event_key or "").strip()[:200]
    if not key:
        return
    row = buckets.get(key)
    if not isinstance(row, dict):
        row = {
            "event_key": key,
            "event_type": str(event_type or "")[:80],
            "source": str(source or "")[:40],
            "count": 0,
            "dur_count": 0,
            "dur_total_ms": 0,
            "dur_avg_ms": None,
            "dur_max_ms": None,
            "last_at": "",
            "last_duration_ms": None,
            "last_status": "",
            "page": str(page or "")[:80],
            "ui": str(ui or "")[:120],
            "detail": str(detail or "")[:400],
            "toggle_allowed": bool(toggle_allowed),
            "is_error": bool(is_error),
        }
        buckets[key] = row
    row["count"] = int(row.get("count", 0) or 0) + 1
    row["is_error"] = bool(row.get("is_error")) or bool(is_error)
    row["toggle_allowed"] = bool(row.get("toggle_allowed", True)) and bool(toggle_allowed)
    if at and str(at) > str(row.get("last_at") or ""):
        row["last_at"] = str(at)
        row["last_status"] = str(status or "")[:40]
        row["page"] = str(page or row.get("page") or "")[:80]
        row["ui"] = str(ui or row.get("ui") or "")[:120]
        row["detail"] = str(detail or row.get("detail") or "")[:400]
        if duration_ms is not None:
            row["last_duration_ms"] = int(max(0, int(duration_ms or 0)))
    if duration_ms is not None:
        dur = int(max(0, int(duration_ms or 0)))
        row["dur_count"] = int(row.get("dur_count", 0) or 0) + 1
        row["dur_total_ms"] = int(row.get("dur_total_ms", 0) or 0) + dur
        cur_max = row.get("dur_max_ms")
        row["dur_max_ms"] = dur if cur_max is None else max(int(cur_max or 0), dur)
        row["dur_avg_ms"] = int(round(float(row["dur_total_ms"]) / float(max(1, row["dur_count"]))))


def _perf_stats_collect(payload: dict[str, Any]) -> dict[str, Any]:
    start_dt, stop_dt, rk = _analysis_window_from_payload(payload)
    buckets: dict[str, dict[str, Any]] = {}

    with TRACE_LOCK:
        traces = [TRACE_INDEX.get(tid) for tid in list(TRACE_MEM)]
    for tr in traces:
        if not isinstance(tr, dict):
            continue
        try:
            _trace_normalize(tr, str(tr.get("trace_id") or ""))
        except Exception:
            pass
        tr_at = str(tr.get("started_at") or tr.get("last_at") or "")
        if not _event_ts_in_window(tr_at, start_dt, stop_dt):
            continue
        action = str(tr.get("action") or "").strip()
        if action:
            _perf_stats_bucket_add(
                buckets,
                event_key=f"trace:action:{action}",
                event_type="trace.action",
                source="trace",
                at=tr_at,
                duration_ms=int(tr.get("dur_ms") or 0) if tr.get("dur_ms") is not None else None,
                status=str(tr.get("status") or ""),
                page=str(tr.get("page") or ""),
                ui=action,
                detail=action,
            )
        for ev in (tr.get("ui_events") if isinstance(tr.get("ui_events"), list) else []):
            if not isinstance(ev, dict):
                continue
            at = str(ev.get("at") or tr_at)
            if not _event_ts_in_window(at, start_dt, stop_dt):
                continue
            ui = str(ev.get("ui") or "").strip()
            if not ui:
                continue
            _perf_stats_bucket_add(
                buckets,
                event_key=f"trace:ui_event:{ui}",
                event_type="ui_event",
                source="trace",
                at=at,
                duration_ms=None,
                status="ok",
                page=str(ev.get("page") or tr.get("page") or ""),
                ui=ui,
                detail=str(ev.get("text") or ui),
            )
        for span in (tr.get("spans") if isinstance(tr.get("spans"), list) else []):
            if not isinstance(span, dict):
                continue
            at = str(span.get("at") or tr_at)
            if not _event_ts_in_window(at, start_dt, stop_dt):
                continue
            method = str(span.get("method") or "GET").upper()[:16]
            path = str(span.get("path") or span.get("kind") or "").strip()[:240]
            _perf_stats_bucket_add(
                buckets,
                event_key=f"trace:server:{method} {path}",
                event_type=str(span.get("kind") or "http.request")[:80],
                source="server",
                at=at,
                duration_ms=int(span.get("dur_ms") or 0) if span.get("dur_ms") is not None else None,
                status=str(span.get("status") or ""),
                page=str(span.get("page") or tr.get("page") or ""),
                ui=str(span.get("action") or tr.get("action") or ""),
                detail=f"{method} {path}",
                is_error=str(span.get("status") or "") == "err",
                toggle_allowed=str(span.get("status") or "") != "err",
            )
        for span in (tr.get("client_spans") if isinstance(tr.get("client_spans"), list) else []):
            if not isinstance(span, dict):
                continue
            at = str(span.get("at") or tr_at)
            if not _event_ts_in_window(at, start_dt, stop_dt):
                continue
            method = str(span.get("method") or "GET").upper()[:16]
            url = str(span.get("url") or "").strip()[:240]
            _perf_stats_bucket_add(
                buckets,
                event_key=f"trace:client:{method} {url}",
                event_type=str(span.get("kind") or "http.client")[:80],
                source="client",
                at=at,
                duration_ms=int(span.get("dur_ms") or 0) if span.get("dur_ms") is not None else None,
                status=str(span.get("status") or ""),
                page=str(span.get("page") or tr.get("page") or ""),
                ui=str(span.get("action") or tr.get("action") or ""),
                detail=f"{method} {url}",
                is_error=str(span.get("status") or "") == "err",
                toggle_allowed=str(span.get("status") or "") != "err",
            )
        for q in (tr.get("queries") if isinstance(tr.get("queries"), list) else []):
            if not isinstance(q, dict):
                continue
            at = str(q.get("at") or tr_at)
            if not _event_ts_in_window(at, start_dt, stop_dt):
                continue
            label = str(q.get("label") or "query").strip()[:120]
            _perf_stats_bucket_add(
                buckets,
                event_key=f"trace:query:{label}",
                event_type="query",
                source="server",
                at=at,
                duration_ms=None,
                status="ok",
                page=str(tr.get("page") or ""),
                ui=str(tr.get("action") or ""),
                detail=label,
            )

    history_rows = _analysis_history_tail(limit=5000)
    for row in history_rows:
        if not isinstance(row, dict):
            continue
        at = str(row.get("at") or "")
        if not _event_ts_in_window(at, start_dt, stop_dt):
            continue
        extra = row.get("extra") if isinstance(row.get("extra"), dict) else {}
        kind = str(row.get("kind") or "")
        if kind == "perf_event":
            event_key = str(extra.get("event_key") or row.get("step") or "").strip()
            if not event_key:
                continue
            dur_val = extra.get("duration_ms")
            dur_ms = int(dur_val or 0) if dur_val is not None else None
            _perf_stats_bucket_add(
                buckets,
                event_key=event_key,
                event_type=str(extra.get("event_type") or kind)[:80],
                source=str(extra.get("source") or "server")[:40],
                at=at,
                duration_ms=dur_ms,
                status=str(row.get("status") or ""),
                page=str(row.get("page") or ""),
                ui=str(row.get("ui") or ""),
                detail=str(row.get("detail") or event_key),
                is_error=bool(extra.get("is_error")),
                toggle_allowed=bool(extra.get("toggle_allowed", True)),
            )
        elif kind == "worklog":
            event_key = "worklog:" + str(row.get("step") or row.get("page") or "worklog")[:160]
            dur_val = extra.get("duration_ms") if isinstance(extra, dict) else None
            dur_ms = int(dur_val or 0) if dur_val is not None else None
            _perf_stats_bucket_add(
                buckets,
                event_key=event_key,
                event_type="worklog",
                source="server",
                at=at,
                duration_ms=dur_ms,
                status=str(row.get("status") or ""),
                page=str(row.get("page") or ""),
                ui=str(extra.get("op") or "")[:120] if isinstance(extra, dict) else "",
                detail=str(row.get("detail") or event_key),
            )

    items = list(buckets.values())
    for row in items:
        row["enabled"] = _slow_event_key_enabled(str(row.get("event_key") or ""), is_error=bool(row.get("is_error")))
    by_count = sorted(items, key=lambda r: (-int(r.get("count") or 0), -(int(r.get("dur_avg_ms") or 0)), str(r.get("event_key") or "")))[:10]
    by_duration = sorted(items, key=lambda r: (-(int(r.get("dur_max_ms") or 0)), -(int(r.get("dur_avg_ms") or 0)), -int(r.get("count") or 0), str(r.get("event_key") or "")))[:10]
    return {
        "ok": True,
        "range": rk,
        "start": _dt_to_rfc3339_utc(start_dt) if start_dt is not None else "",
        "stop": _dt_to_rfc3339_utc(stop_dt) if stop_dt is not None else "",
        "rows_total": len(items),
        "top_count": by_count,
        "top_duration": by_duration,
    }


def _config_log_enabled(cfg: dict[str, Any] | None = None) -> bool:
    try:
        cur = cfg if isinstance(cfg, dict) else load_cfg()
        return bool(cur.get("log_config_changes", True))
    except Exception:
        return True


def _config_log_ack_load() -> None:
    global CONFIG_LOG_ACK_LOADED
    if CONFIG_LOG_ACK_LOADED:
        return
    CONFIG_LOG_ACK_LOADED = True
    try:
        if not CONFIG_LOG_ACK_PATH.exists():
            return
        raw = json.loads(CONFIG_LOG_ACK_PATH.read_text(encoding="utf-8"))
        ids = raw.get("ids") if isinstance(raw, dict) else None
        if not isinstance(ids, list):
            return
        for item in ids[-CONFIG_LOG_ACK_MAX:]:
            sid = str(item or "").strip()
            if not sid or sid in CONFIG_LOG_ACK_IDS:
                continue
            CONFIG_LOG_ACK_IDS.add(sid)
            CONFIG_LOG_ACK_ORDER.append(sid)
    except Exception:
        return


def _config_log_ack_save() -> None:
    try:
        CONFIG_LOG_ACK_PATH.parent.mkdir(parents=True, exist_ok=True)
        tmp = CONFIG_LOG_ACK_PATH.with_suffix(CONFIG_LOG_ACK_PATH.suffix + ".tmp")
        tmp.write_text(json.dumps({"ids": list(CONFIG_LOG_ACK_ORDER)[-CONFIG_LOG_ACK_MAX:]}, ensure_ascii=True), encoding="utf-8")
        os.replace(tmp, CONFIG_LOG_ACK_PATH)
    except Exception:
        return


def _config_log_record_seen(event_id: str) -> None:
    sid = str(event_id or "").strip()
    if not sid or sid in CONFIG_LOG_ACK_IDS:
        return
    CONFIG_LOG_ACK_IDS.add(sid)
    CONFIG_LOG_ACK_ORDER.append(sid)
    while len(CONFIG_LOG_ACK_ORDER) > CONFIG_LOG_ACK_MAX:
        try:
            old = CONFIG_LOG_ACK_ORDER.popleft()
        except Exception:
            break
        try:
            CONFIG_LOG_ACK_IDS.discard(old)
        except Exception:
            pass


def _config_log_redact(field_name: str, value: Any) -> Any:
    key = str(field_name or "").strip().lower()
    if key and any(tok in key for tok in ("token", "password", "secret", "admin_token")):
        return "***"
    if isinstance(value, (dict, list)):
        try:
            return json.dumps(value, ensure_ascii=True)[:500]
        except Exception:
            return str(value)[:500]
    return value


def _config_log_format(event: dict[str, Any]) -> str:
    page = str(event.get("page") or "").strip()[:80]
    area = str(event.get("area") or "").strip()[:160]
    field = str(event.get("field") or "").strip()[:160]
    source = str(event.get("source") or "").strip()[:80]
    storage_key = str(event.get("storage_key") or event.get("scope") or "").strip()[:160]
    changes = event.get("changes") if isinstance(event.get("changes"), list) else []
    safe = []
    for item in changes[:50]:
        if not isinstance(item, dict):
            continue
        name = str(item.get("field") or "").strip()[:160]
        safe.append({"field": name, "old": _config_log_redact(name, item.get("old")), "new": _config_log_redact(name, item.get("new"))})
    return "Config speicherung page=%s area=%s field=%s source=%s key=%s changes=%s" % (
        page,
        area,
        field,
        source,
        storage_key,
        json.dumps(safe, ensure_ascii=True),
    )


def _config_log_replay_pending() -> None:
    try:
        _config_log_ack_load()
        if not CONFIG_LOG_QUEUE_PATH.exists():
            return
        lines = CONFIG_LOG_QUEUE_PATH.read_text(encoding="utf-8").splitlines()
        dirty = False
        for line in lines[-10000:]:
            try:
                row = json.loads(line)
                event = row.get("event") if isinstance(row, dict) else None
            except Exception:
                continue
            if not isinstance(event, dict):
                continue
            eid = str(event.get("event_id") or "").strip()
            if not eid or eid in CONFIG_LOG_ACK_IDS:
                continue
            LOG.info(_config_log_format(event))
            _config_log_record_seen(eid)
            dirty = True
        if dirty:
            _config_log_ack_save()
    except Exception:
        return


@app.post("/api/client_log_batch")
def api_client_log_batch():
    cfg = load_cfg()
    if not _config_log_enabled(cfg):
        return jsonify({"ok": True, "acked": []})
    try:
        body = request.get_json(force=True) or {}
    except Exception:
        body = {}
    events = body.get("events") if isinstance(body, dict) else None
    if not isinstance(events, list):
        return jsonify({"ok": False, "error": "events must be a list"}), 400
    if len(events) > 200:
        return jsonify({"ok": False, "error": "too many events"}), 413

    with CONFIG_LOG_LOCK:
        _config_log_ack_load()
        _config_log_replay_pending()
        CONFIG_LOG_QUEUE_PATH.parent.mkdir(parents=True, exist_ok=True)
        acked: list[str] = []
        pending: list[dict[str, Any]] = []
        for raw in events:
            if not isinstance(raw, dict):
                continue
            eid = str(raw.get("event_id") or "").strip()[:120]
            if not eid:
                continue
            if eid in CONFIG_LOG_ACK_IDS:
                acked.append(eid)
                continue
            pending.append(raw)
        if pending:
            with CONFIG_LOG_QUEUE_PATH.open("a", encoding="utf-8") as f:
                for ev in pending:
                    f.write(json.dumps({"event": ev}, ensure_ascii=True) + "\n")
                try:
                    f.flush()
                    os.fsync(f.fileno())
                except Exception:
                    pass
            for ev in pending:
                try:
                    eid = str(ev.get("event_id") or "").strip()
                    LOG.info(_config_log_format(ev))
                    _config_log_record_seen(eid)
                    acked.append(eid)
                except Exception:
                    continue
            _config_log_ack_save()
    return jsonify({"ok": True, "acked": acked})


