def _undo_predicate(measurement_s: str, field_s: str, tags: dict[str, str]) -> str:
    def _pred_escape(v: str) -> str:
        return (v or "").replace("\\", "\\\\").replace('"', '\\"')

    parts = [f'_measurement="{_pred_escape(measurement_s)}"', f'_field="{_pred_escape(field_s)}"']
    for k, v in (tags or {}).items():
        if not k:
            continue
        parts.append(f'{k}="{_pred_escape(v)}"')
    return " AND ".join(parts)


def _undo_fetch_value(qapi, cfg: dict[str, Any], measurement: str, field: str, dt: datetime, tags: dict[str, str]) -> tuple[bool, float | int | None]:
    start = _dt_to_rfc3339_utc_full(dt - timedelta(seconds=2))
    stop = _dt_to_rfc3339_utc_full(dt + timedelta(seconds=2))
    extra_pred = ""
    for k, v in (tags or {}).items():
        extra_pred += f' and r["{k}"] == {_flux_str(v)}'
    q = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "{start}"), stop: time(v: "{stop}"))
  |> filter(fn: (r) => r._measurement == {_flux_str(measurement)} and r._field == {_flux_str(field)}{extra_pred})
  |> group()
  |> sort(columns: ["_time"])
  |> limit(n: 20)
'''
    tables = qapi.query(q, org=cfg["org"])
    best_rec = None
    best_abs = None
    for t in tables or []:
        for rec in getattr(t, "records", []) or []:
            rdt = rec.get_time()
            if not isinstance(rdt, datetime):
                continue
            delta = abs((rdt.astimezone(timezone.utc) - dt).total_seconds())
            if best_abs is None or delta < best_abs:
                best_abs = delta
                best_rec = rec
    if best_rec is None or best_abs is None or best_abs > 1.0:
        return False, None
    v = best_rec.get_value()
    if isinstance(v, bool) or not isinstance(v, (int, float)):
        return True, None
    return True, v


def _undo_row_key(row: dict[str, Any]) -> tuple[str, str, str, tuple[tuple[str, str], ...]]:
    measurement = str(row.get("_measurement") or "").strip()
    field = str(row.get("_field") or "").strip()
    t = str(row.get("_time") or "").strip()
    tags = _undo_row_tags(row)
    return measurement, field, t, tuple(sorted((str(k), str(v)) for k, v in (tags or {}).items()))


def _undo_verify_rows(
    qapi,
    cfg: dict[str, Any],
    rows: list[dict[str, Any]],
    *,
    must_exist: bool,
    must_match_value: bool,
) -> None:
    for row in rows or []:
        if not isinstance(row, dict):
            continue
        measurement = str(row.get("_measurement") or "").strip()
        field = str(row.get("_field") or "").strip()
        time_raw = str(row.get("_time") or "").strip()
        if not measurement or not field or not time_raw:
            continue
        dt = _parse_iso_datetime(time_raw)
        tags = _undo_row_tags(row)

        found, cur = _undo_fetch_value(qapi, cfg, measurement, field, dt, tags)
        if must_exist and not found:
            raise RuntimeError(f"Undo-Konflikt: Zeile fehlt ({measurement}/{field} @ {time_raw})")
        if not must_exist and found:
            raise RuntimeError(f"Undo-Konflikt: Zeile existiert bereits ({measurement}/{field} @ {time_raw})")

        if must_match_value and must_exist:
            want = row.get("_value")
            if isinstance(want, bool):
                continue
            if isinstance(want, (int, float)):
                if cur is None:
                    raise RuntimeError(f"Undo-Konflikt: Wert hat sich geaendert ({measurement}/{field} @ {time_raw})")
                try:
                    if float(cur) != float(want):
                        raise RuntimeError(
                            f"Undo-Konflikt: Wert hat sich geaendert ({measurement}/{field} @ {time_raw})"
                        )
                except Exception:
                    raise RuntimeError(
                        f"Undo-Konflikt: Wert hat sich geaendert ({measurement}/{field} @ {time_raw})"
                    )


def _undo_apply_rows(cfg: dict[str, Any], rows: list[dict[str, Any]], mode: str) -> list[dict[str, Any]]:
    # Deprecated: Undo/Repeat must go through the Change-Service.
    raise RuntimeError("deprecated: use ChangeBlocks engine")


def _undo_execute_action(cfg: dict[str, Any], action: dict[str, Any], direction: str) -> None:
    if not isinstance(action, dict):
        raise RuntimeError("invalid action")
    direction = str(direction or "").strip().lower()
    if direction not in ("undo", "repeat"):
        raise RuntimeError("invalid direction")

    before_rows = action.get("before_rows") if isinstance(action.get("before_rows"), list) else []
    after_rows = action.get("after_rows") if isinstance(action.get("after_rows"), list) else []

    meta = action.get("meta") if isinstance(action.get("meta"), dict) else {}
    bid = str(meta.get("change_block_id") or action.get("change_block_id") or "").strip()

    # Preferred path: reuse the persisted ChangeBlock created by the write path.
    if bid:
        try:
            if load_change_block(bid, include_items=False):
                out = undo_change_block(bid) if direction == "undo" else repeat_change_block(bid)
                if not out.get("ok"):
                    raise RuntimeError("undo/repeat conflict")
                return
        except Exception:
            # Fall back to synthesizing a block from before/after rows.
            pass

    if not bid:
        bid = uuid.uuid4().hex
        # Persist for future repeats (UndoManager stores `meta`).
        meta = dict(meta)
        meta["change_block_id"] = bid
        action["meta"] = meta
        action["change_block_id"] = bid

    items: list[dict[str, Any]] = []
    max_n = min(5000, max(len(before_rows), len(after_rows)))
    for i in range(max_n):
        b = before_rows[i] if i < len(before_rows) and isinstance(before_rows[i], dict) else None
        a = after_rows[i] if i < len(after_rows) and isinstance(after_rows[i], dict) else None
        row = a if a is not None else b
        if row is None:
            continue
        measurement = str(row.get("_measurement") or "").strip()
        field = str(row.get("_field") or "").strip()
        ts = str(row.get("_time") or "").strip()
        if not measurement or not field or not ts:
            continue
        tags = _undo_row_tags(row)
        op = "update"
        if b is None and a is not None:
            op = "create"
        elif b is not None and a is None:
            op = "delete"

        pid = {
            "bucket": str(cfg.get("bucket") or ""),
            "org": str(cfg.get("org") or ""),
            "measurement": measurement,
            "field": field,
            "timestamp": ts,
            "tag_set": tags,
        }
        items.append({
            "schema_version": CHANGE_ITEM_SCHEMA_VERSION,
            "item_id": uuid.uuid4().hex,
            "block_id": bid,
            "op": op,
            "point_identity": pid,
            "old_point": b,
            "new_point": a,
            "conflict_policy": "strict",
        })

    cb = {
        "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
        "block_id": bid,
        "created_at": _utc_now_iso_ms(),
        "source": {"user_id": None, "ip": _req_ip(), "ua": _req_ua(), "trigger_page": "history", "trigger_source": "undo_mgr", "trigger_action": direction},
        "operation_source": "undo_mgr",
        "reason": "undo_mgr",
        "status": "created",
        "undo_status": "not_run",
        "repeat_status": "not_run",
        "affected_count": len(items),
        "series_summary": {},
    }
    save_change_block(cb, items=items)
    out = undo_change_block(bid) if direction == "undo" else repeat_change_block(bid)
    if not out.get("ok"):
        raise RuntimeError("undo/repeat conflict")


@app.post("/api/undo/undo")
def api_undo_undo():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    mgr = _undo_mgr(cfg)
    action = mgr.pop_undo()
    if not action:
        return jsonify({"ok": False, "error": "no undo available"}), 404
    try:
        _undo_execute_action(cfg, action, direction="undo")
        action["undone"] = True
        action["repeat_available"] = True
        mgr.push_redo(action)
        return jsonify({"ok": True, "action": action})
    except Exception as e:
        # Put back on undo stack
        mgr.push_undo(action)
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 409


@app.post("/api/undo/repeat")
def api_undo_repeat():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    mgr = _undo_mgr(cfg)
    action = mgr.pop_redo()
    if not action:
        return jsonify({"ok": False, "error": "no repeat available"}), 404
    try:
        _undo_execute_action(cfg, action, direction="repeat")
        action["undone"] = False
        action["repeat_available"] = False
        mgr.push_undo(action)
        return jsonify({"ok": True, "action": action})
    except Exception as e:
        mgr.push_redo(action)
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 409


@app.get("/api/history_list")
def api_history_list():
    try:
        q = str(request.args.get("q") or "").strip().lower()
        action = str(request.args.get("action") or "").strip().lower()
        measurement = str(request.args.get("measurement") or "").strip().lower()
        entity_id = str(request.args.get("entity_id") or "").strip().lower()
        reason = str(request.args.get("reason") or "").strip().lower()
        try:
            limit = int(request.args.get("limit") or 200)
        except Exception:
            limit = 200
        if limit < 1:
            limit = 1
        if limit > 2000:
            limit = 2000

        rows = _history_read_all()
        # newest first
        rows = list(reversed(rows))

        def _match(it: dict[str, Any]) -> bool:
            try:
                if action and str(it.get("action") or "").lower() != action:
                    return False
                s = it.get("series") or {}
                if measurement and measurement not in str(s.get("measurement") or "").lower():
                    return False
                if entity_id and entity_id not in str(s.get("entity_id") or "").lower():
                    return False
                if reason and reason not in str(it.get("reason") or "").lower():
                    return False
                if q:
                    blob = json.dumps(it, ensure_ascii=True).lower()
                    if q not in blob:
                        return False
                return True
            except Exception:
                return False

        out: list[dict[str, Any]] = []
        for it in rows:
            if not isinstance(it, dict):
                continue
            if not _match(it):
                continue
            out.append(it)
            if len(out) >= limit:
                break

        return jsonify({"ok": True, "rows": out})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 500


@app.post("/api/raw_history_summary")
def api_raw_history_summary():
    try:
        body = request.get_json(force=True) or {}
        measurement = str(body.get("measurement") or "").strip()
        field = str(body.get("field") or "").strip()
        entity_id = str(body.get("entity_id") or "").strip() or None
        friendly_name = str(body.get("friendly_name") or "").strip() or None
        times = body.get("times")

        if not measurement or not field:
            return jsonify({"ok": False, "error": "measurement and field required"}), 400
        if not isinstance(times, list) or not times:
            return jsonify({"ok": False, "error": "times must be a non-empty list"}), 400

        raw_time_map: dict[str, str] = {}
        for it in times:
            raw_key = str(it or "").strip()
            norm = _history_time_key(raw_key)
            if raw_key and norm:
                raw_time_map[raw_key] = norm
        wanted_keys = set(raw_time_map.values())
        if not wanted_keys:
            return jsonify({"ok": True, "rows": {}, "undoable": {}})

        all_rows = _history_read_all()
        rolled_back_refs = {
            str(it.get("ref_id") or "").strip()
            for it in all_rows
            if isinstance(it, dict) and str(it.get("action") or "").strip().lower() == "rollback"
        }

        grouped: dict[str, list[dict[str, Any]]] = {k: [] for k in raw_time_map.keys()}
        undoable: dict[str, dict[str, Any]] = {}

        for it in reversed(all_rows):
            if not isinstance(it, dict):
                continue
            if not _history_series_matches(it, measurement, field, entity_id, friendly_name):
                continue
            time_key = _history_time_key(it.get("time"))
            if not time_key or time_key not in wanted_keys:
                continue

            trigger = _history_trigger_meta(it)
            pub = {
                "id": str(it.get("id") or ""),
                "at": str(it.get("at") or ""),
                "time": str(it.get("time") or ""),
                "action": str(it.get("action") or ""),
                "old_value": it.get("old_value"),
                "new_value": it.get("new_value"),
                "reason": str(it.get("reason") or ""),
                "ref_id": str(it.get("ref_id") or ""),
                "change_block_id": str(it.get("change_block_id") or ""),
                "change_block_kind": str(it.get("change_block_kind") or ""),
                "change_block_size": it.get("change_block_size"),
                "change_block_start": str(it.get("change_block_start") or ""),
                "change_block_end": str(it.get("change_block_end") or ""),
                **trigger,
            }
            is_raw_change = (
                trigger["trigger_page"] == "dashboard"
                and trigger["trigger_source"] == "raw"
                and str(it.get("action") or "").strip().lower() in ("overwrite", "delete")
                and trigger["trigger_button"] in ("raw_paste", "raw_delete", "raw_linear_range", "raw_copy_first_range")
                and str(it.get("id") or "").strip() not in rolled_back_refs
            )
            for raw_key, norm in raw_time_map.items():
                if norm != time_key:
                    continue
                grouped[raw_key].append(pub)
                if raw_key not in undoable and is_raw_change:
                    undoable[raw_key] = pub

        return jsonify({"ok": True, "rows": grouped, "undoable": undoable})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 500


@app.post("/api/history_rollback")
def api_history_rollback():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}
    confirm = body.get("confirm", False)
    ok_confirm = (
        confirm is True
        or str(confirm).strip().lower() in ("1", "true", "yes", "on")
    )
    if not ok_confirm:
        return jsonify({"ok": False, "error": "Confirmation required"}), 400

    ids = body.get("ids")
    since_seconds = body.get("since_seconds")

    rows = _history_read_all()

    wanted: list[dict[str, Any]] = []
    if isinstance(ids, list) and ids:
        idset = {str(x) for x in ids if str(x)}
        for it in rows:
            if isinstance(it, dict) and str(it.get("id") or "") in idset:
                wanted.append(it)
    elif since_seconds is not None:
        try:
            s = int(since_seconds)
        except Exception:
            s = 0
        if s <= 0:
            return jsonify({"ok": False, "error": "since_seconds must be > 0"}), 400
        cutoff = datetime.now(timezone.utc) - timedelta(seconds=s)
        for it in rows:
            if not isinstance(it, dict):
                continue
            at = str(it.get("at") or "")
            try:
                dt_at = _parse_iso_datetime(at)
            except Exception:
                continue
            if dt_at >= cutoff:
                wanted.append(it)
    else:
        return jsonify({"ok": False, "error": "ids or since_seconds required"}), 400

    # Rollback newest first
    wanted.sort(key=lambda x: str(x.get("at") or ""), reverse=True)

    # Change-Service rollback: build a ChangeBlock representing the original changes,
    # then undo it via the engine. (No direct writes here.)
    for it in wanted:
        if str(it.get("action") or "").strip().lower() == "combine_copy":
            return jsonify({
                "ok": False,
                "error": "combine_copy rollback not supported yet (requires Change-Service bulk support)",
            }), 400

    block_id = uuid.uuid4().hex
    change_items: list[dict[str, Any]] = []
    for it in wanted:
        action = str(it.get("action") or "").strip().lower()
        if action not in ("overwrite", "delete"):
            continue
        s = it.get("series") if isinstance(it.get("series"), dict) else {}
        measurement = str(s.get("measurement") or "").strip()
        field = str(s.get("field") or "").strip()
        tags = s.get("tags") if isinstance(s.get("tags"), dict) else {}
        t_raw = str(it.get("time") or "").strip()
        if not measurement or not field or not t_raw:
            continue
        old_val = it.get("old_value")
        new_val = it.get("new_value")
        if old_val is None:
            continue

        before_row = {"_time": t_raw, "_measurement": measurement, "_field": field, "_value": old_val, **tags}
        after_row = None
        if action == "overwrite":
            after_row = {"_time": t_raw, "_measurement": measurement, "_field": field, "_value": new_val, **tags}

        pid = {
            "bucket": str(cfg.get("bucket") or ""),
            "org": str(cfg.get("org") or ""),
            "measurement": measurement,
            "field": field,
            "timestamp": t_raw,
            "tag_set": tags,
        }
        change_items.append({
            "schema_version": CHANGE_ITEM_SCHEMA_VERSION,
            "item_id": uuid.uuid4().hex,
            "block_id": block_id,
            "op": "update" if action == "overwrite" else "delete",
            "point_identity": pid,
            "old_point": before_row,
            "new_point": after_row,
            "conflict_policy": "strict",
            "meta": {"history_ref_id": str(it.get("id") or "")},
        })

    cb = {
        "schema_version": CHANGE_BLOCK_SCHEMA_VERSION,
        "block_id": block_id,
        "created_at": _utc_now_iso_ms(),
        "source": {"user_id": None, "ip": _req_ip(), "ua": _req_ua(), "trigger_page": "history", "trigger_source": "history_rollback"},
        "operation_source": "history_rollback",
        "reason": "Rollback",
        "status": "created",
        "undo_status": "not_run",
        "repeat_status": "not_run",
        "affected_count": len(change_items),
        "series_summary": {},
    }
    try:
        save_change_block(cb, items=change_items)
        out = undo_change_block(block_id)
        if not out.get("ok"):
            return jsonify({"ok": False, "error": "conflict", "validation": out.get("validation"), "change_block_id": block_id}), 409
        applied = int(out.get("applied") or 0)
    except Exception as e:
        return jsonify({"ok": False, "error": str(e) or e.__class__.__name__}), 500

    # Record rollback events in history (audit)
    for it in wanted:
        action = str(it.get("action") or "").strip().lower()
        if action not in ("overwrite", "delete"):
            continue
        s = it.get("series") if isinstance(it.get("series"), dict) else {}
        measurement = str(s.get("measurement") or "").strip()
        field = str(s.get("field") or "").strip()
        tags = s.get("tags") if isinstance(s.get("tags"), dict) else {}
        t_raw = str(it.get("time") or "").strip()
        _history_append({
            "kind": "rollback",
            "ref_id": it.get("id"),
            "series": {
                "measurement": measurement,
                "field": field,
                "entity_id": s.get("entity_id"),
                "friendly_name": s.get("friendly_name"),
                "tags": tags,
            },
            "time": t_raw,
            "action": "rollback",
            "old_value": it.get("new_value"),
            "new_value": it.get("old_value"),
            "reason": "Rollback",
            "change_block_id": block_id,
            "ip": _req_ip(),
            "ua": _req_ua(),
        })

        try:
            dirty_series.add((measurement, field, str(s.get("entity_id") or "").strip() or None, str(s.get("friendly_name") or "").strip() or None))
        except Exception:
            pass

    try:
        for m, f, eid, fn in dirty_series:
            _dash_cache_mark_dirty_series(m, f, eid, fn, "history_rollback")
            _stats_cache_mark_dirty_series(m, f, eid, fn, "history_rollback")
            _analysis_cache_mark_dirty_series(cfg, m, f, eid, fn, "history_rollback")
    except Exception:
        pass

    return jsonify({"ok": True, "applied": applied, "message": f"Rollback applied: {applied}", "change_block_id": block_id})


def _safe_data_file(root: Path, name: str) -> Path:
    """Resolve a user-provided filename safely within a root directory."""

    n = (name or "").strip()
    if not n or "/" in n or "\\" in n or ".." in n:
        raise ValueError("invalid file name")
    p = (root / n).resolve()
    rr = root.resolve()
    if rr not in p.parents and p != rr:
        raise ValueError("path traversal")
    return p


@app.post("/api/export")
def api_export():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}

    fmt = str(body.get("format") or "text").strip().lower()
    if fmt not in ("text", "xlsx"):
        return jsonify({"ok": False, "error": "format must be text or xlsx"}), 400

    delim = str(body.get("delimiter") or ";")
    if len(delim) != 1:
        delim = ";"

    measurement = str(body.get("measurement") or "").strip()
    field = str(body.get("field") or "").strip()
    entity_id = str(body.get("entity_id") or "").strip() or None
    friendly_name = str(body.get("friendly_name") or "").strip() or None
    if not measurement or not field:
        return jsonify({"ok": False, "error": "measurement and field required"}), 400

    tz_name = str(body.get("tz_name") or "").strip() or None
    try:
        tz_off = body.get("tz_offset_minutes")
        tz_offset_minutes = int(tz_off) if tz_off is not None and str(tz_off).strip() != "" else None
    except Exception:
        tz_offset_minutes = None

    # Export window: prefer explicit start/stop.
    try:
        start_dt, stop_dt = _get_start_stop_from_payload(body)
    except Exception as e:
        return jsonify({"ok": False, "error": f"invalid start/stop: {e}"}), 400
    if not start_dt or not stop_dt:
        return jsonify({"ok": False, "error": "start and stop required"}), 400

    if int(cfg.get("influx_version", 2)) != 2:
        return jsonify({"ok": False, "error": "export currently supports InfluxDB v2 only"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({
            "ok": False,
            "error": "InfluxDB v2 requires token, org, bucket. Bitte in /config YAML einlesen und speichern.",
        }), 400

    extra = flux_tag_filter(entity_id, friendly_name)
    start = _dt_to_rfc3339_utc(start_dt)
    stop = _dt_to_rfc3339_utc(stop_dt)
    q = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "{start}"), stop: time(v: "{stop}"))
  |> filter(fn: (r) => r._measurement == {_flux_str(measurement)} and r._field == {_flux_str(field)}{extra})
  |> keep(columns: ["_time","_value","_measurement","_field","entity_id","friendly_name"])
  |> sort(columns: ["_time"], desc: false)
'''

    EXPORT_DIR.mkdir(parents=True, exist_ok=True)
    file_id = uuid.uuid4().hex
    ext = "xlsx" if fmt == "xlsx" else "csv"
    filename = f"export__{file_id}.{ext}"
    out_path = (EXPORT_DIR / filename)

    try:
        rows: list[tuple[str, object, str, str, str, str]] = []
        with v2_client(cfg) as c:
            for rec in c.query_api().query_stream(q, org=cfg["org"]):
                try:
                    t = rec.get_time()
                    v = rec.get_value()
                    if v is None or not isinstance(t, datetime):
                        continue
                    tv = t.astimezone(timezone.utc)
                    t_local = _fmt_ui_local_ts(tv, tz_name, tz_offset_minutes)
                    m = str(rec.values.get("_measurement") or measurement)
                    f = str(rec.values.get("_field") or field)
                    eid = str(rec.values.get("entity_id") or "")
                    fn = str(rec.values.get("friendly_name") or "")
                    rows.append((t_local, v, eid, fn, m, f))
                except Exception:
                    continue

        if fmt == "xlsx":
            try:
                import openpyxl  # type: ignore
            except Exception:
                return jsonify({"ok": False, "error": "openpyxl not available"}), 500

            wb = openpyxl.Workbook()
            ws = wb.active
            ws.title = "export"
            ws.append(["time", "value", "entity_id", "friendly_name", "_measurement", "_field"])
            for r in rows:
                ws.append(list(r))
            wb.save(out_path)
        else:
            with out_path.open("w", encoding="utf-8", newline="") as f:
                f.write(f"# timezone={tz_name or ''}\n")
                f.write(f"# tz_offset_minutes={tz_offset_minutes if tz_offset_minutes is not None else ''}\n")
                w = csv.writer(f, delimiter=delim)
                w.writerow(["time", "value", "entity_id", "friendly_name", "_measurement", "_field"])
                for r in rows:
                    w.writerow(list(r))

        return jsonify({
            "ok": True,
            "download_url": f"./api/export_download?file={filename}",
            "meta": {"rows": len(rows), "format": fmt, "delimiter": delim},
        })
    except Exception as e:
        try:
            if out_path.exists():
                out_path.unlink()
        except Exception:
            pass
        return jsonify({"ok": False, "error": _short_influx_error(e)}), 500


def _export_job_public(job: dict[str, Any]) -> dict[str, Any]:
    written = int(job.get("rows_written") or 0)
    return {
        "id": job.get("id"),
        "state": job.get("state"),
        "message": job.get("message"),
        "started_at": job.get("started_at"),
        "elapsed": _job_elapsed_hms(job),
        "rows_written": written,
        "format": job.get("format"),
        "file": job.get("file"),
        "download_url": job.get("download_url"),
        "query": job.get("query") or "",
        "cancelled": bool(job.get("cancelled")),
        "error": job.get("error"),
        "ready": job.get("state") in ("done", "error", "cancelled"),
    }


def _export_job_thread(
    job_id: str,
    cfg: dict[str, Any],
    fmt: str,
    delim: str,
    measurement: str,
    field: str,
    entity_id: str | None,
    friendly_name: str | None,
    start_dt: datetime,
    stop_dt: datetime,
    tz_name: str | None,
    tz_offset_minutes: int | None,
    out_dir: str | None,
) -> None:
    with EXPORT_LOCK:
        job = EXPORT_JOBS.get(job_id)
    if not job:
        return

    def set_state(state: str, msg: str) -> None:
        with EXPORT_LOCK:
            if job_id in EXPORT_JOBS:
                EXPORT_JOBS[job_id]["state"] = state
                EXPORT_JOBS[job_id]["message"] = msg
                if state in ("done", "error", "cancelled"):
                    _job_set_finished(EXPORT_JOBS[job_id])

    def set_error(msg: str) -> None:
        with EXPORT_LOCK:
            if job_id in EXPORT_JOBS:
                EXPORT_JOBS[job_id]["error"] = msg

    def set_progress(**kw: Any) -> None:
        with EXPORT_LOCK:
            j = EXPORT_JOBS.get(job_id)
            if not j:
                return
            for k, v in kw.items():
                j[k] = v

    def is_cancelled() -> bool:
        with EXPORT_LOCK:
            j = EXPORT_JOBS.get(job_id) or {}
            if bool(j.get("cancelled")):
                return True

            try:
                max_s = int(cfg.get("jobs_max_runtime_seconds", 0) or 0)
            except Exception:
                max_s = 0
            if max_s <= 0:
                return False
            try:
                started_mono = float(j.get("started_mono") or 0.0)
            except Exception:
                started_mono = 0.0
            if started_mono > 0 and (time.monotonic() - started_mono) >= float(max_s):
                EXPORT_JOBS[job_id]["cancelled"] = True
                try:
                    LOG.warning("job_auto_cancel type=export job_id=%s reason=max_runtime_seconds exceeded (%s)", job_id, max_s)
                except Exception:
                    pass
                return True
            return False

    out_root = export_dir_from_target(out_dir)
    out_root.mkdir(parents=True, exist_ok=True)
    ext = "xlsx" if fmt == "xlsx" else "csv"
    filename = f"export_job__{job_id}.{ext}"
    part = f"{filename}.part"
    out_path = (out_root / filename)
    part_path = (out_root / part)

    extra = flux_tag_filter(entity_id, friendly_name)
    start = _dt_to_rfc3339_utc(start_dt)
    stop = _dt_to_rfc3339_utc(stop_dt)
    q = f'''
from(bucket: "{cfg["bucket"]}")
  |> range(start: time(v: "{start}"), stop: time(v: "{stop}"))
  |> filter(fn: (r) => r._measurement == {_flux_str(measurement)} and r._field == {_flux_str(field)}{extra})
  |> keep(columns: ["_time","_value","_measurement","_field","entity_id","friendly_name"])
  |> sort(columns: ["_time"], desc: false)
'''

    set_state("running", "Export laeuft...")
    set_progress(query=q.strip(), rows_written=0, file=None, download_url=None)

    count = 0
    last_tick = time.monotonic()

    try:
        with v2_client(cfg) as c:
            qapi = c.query_api()

            if fmt == "xlsx":
                try:
                    import openpyxl  # type: ignore
                except Exception as e:
                    raise RuntimeError("openpyxl not available") from e

                wb = openpyxl.Workbook()
                ws = wb.active
                ws.title = "export"
                ws.append(["time", "value", "entity_id", "friendly_name", "_measurement", "_field"])

                for rec in qapi.query_stream(q, org=cfg["org"]):
                    if is_cancelled():
                        set_state("cancelled", "Abgebrochen")
                        raise RuntimeError("cancelled")
                    try:
                        t = rec.get_time()
                        v = rec.get_value()
                        if v is None or not isinstance(t, datetime):
                            continue
                        tv = t.astimezone(timezone.utc)
                        t_local = _fmt_ui_local_ts(tv, tz_name, tz_offset_minutes)
                        m = str(rec.values.get("_measurement") or measurement)
                        f = str(rec.values.get("_field") or field)
                        eid = str(rec.values.get("entity_id") or "")
                        fn = str(rec.values.get("friendly_name") or "")
                        ws.append([t_local, v, eid, fn, m, f])
                        count += 1
                    except Exception:
                        continue
                    now = time.monotonic()
                    if (now - last_tick) >= 0.25:
                        set_progress(rows_written=count)
                        last_tick = now

                if is_cancelled():
                    set_state("cancelled", "Abgebrochen")
                    raise RuntimeError("cancelled")
                wb.save(part_path)
            else:
                with part_path.open("w", encoding="utf-8", newline="") as f:
                    f.write(f"# timezone={tz_name or ''}\n")
                    f.write(f"# tz_offset_minutes={tz_offset_minutes if tz_offset_minutes is not None else ''}\n")
                    w = csv.writer(f, delimiter=delim)
                    w.writerow(["time", "value", "entity_id", "friendly_name", "_measurement", "_field"])
                    for rec in qapi.query_stream(q, org=cfg["org"]):
                        if is_cancelled():
                            set_state("cancelled", "Abgebrochen")
                            raise RuntimeError("cancelled")
                        try:
                            t = rec.get_time()
                            v = rec.get_value()
                            if v is None or not isinstance(t, datetime):
                                continue
                            tv = t.astimezone(timezone.utc)
                            t_local = _fmt_ui_local_ts(tv, tz_name, tz_offset_minutes)
                            m = str(rec.values.get("_measurement") or measurement)
                            fld = str(rec.values.get("_field") or field)
                            eid = str(rec.values.get("entity_id") or "")
                            fn = str(rec.values.get("friendly_name") or "")
                            w.writerow([t_local, v, eid, fn, m, fld])
                            count += 1
                        except Exception:
                            continue

                        now = time.monotonic()
                        if (now - last_tick) >= 0.25:
                            set_progress(rows_written=count)
                            last_tick = now

        if is_cancelled():
            set_state("cancelled", "Abgebrochen")
            raise RuntimeError("cancelled")

        try:
            if out_path.exists():
                out_path.unlink()
        except Exception:
            pass
        part_path.replace(out_path)

        dl = f"./api/export_job/download?job_id={job_id}"
        set_progress(rows_written=count, file=filename, download_url=dl)
        set_state("done", f"Export fertig. Zeilen: {count}")
        return
    except Exception as e:
        msg = str(e)
        if "cancelled" in msg:
            try:
                if part_path.exists():
                    part_path.unlink()
            except Exception:
                pass
            try:
                if out_path.exists():
                    out_path.unlink()
            except Exception:
                pass
            return

        set_state("error", "Fehler")
        set_error(_short_influx_error(e))
        try:
            if part_path.exists():
                part_path.unlink()
        except Exception:
            pass
        try:
            if out_path.exists():
                out_path.unlink()
        except Exception:
            pass
        return


@app.post("/api/export_job/start")
def api_export_job_start():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    body = request.get_json(force=True) or {}

    target_dir = export_dir_from_target(body.get("target_dir"))

    fmt = str(body.get("format") or "text").strip().lower()
    if fmt not in ("text", "xlsx"):
        return jsonify({"ok": False, "error": "format must be text or xlsx"}), 400

    delim = str(body.get("delimiter") or ";")
    if len(delim) != 1:
        delim = ";"

    measurement = str(body.get("measurement") or "").strip()
    field = str(body.get("field") or "").strip()
    entity_id = str(body.get("entity_id") or "").strip() or None
    friendly_name = str(body.get("friendly_name") or "").strip() or None
    if not measurement or not field:
        return jsonify({"ok": False, "error": "measurement and field required"}), 400

    tz_name = str(body.get("tz_name") or "").strip() or None
    try:
        tz_off = body.get("tz_offset_minutes")
        tz_offset_minutes = int(tz_off) if tz_off is not None and str(tz_off).strip() != "" else None
    except Exception:
        tz_offset_minutes = None

    try:
        start_dt, stop_dt = _get_start_stop_from_payload(body)
    except Exception as e:
        return jsonify({"ok": False, "error": f"invalid start/stop: {e}"}), 400
    if not start_dt or not stop_dt:
        return jsonify({"ok": False, "error": "start and stop required"}), 400

    if int(cfg.get("influx_version", 2)) != 2:
        return jsonify({"ok": False, "error": "export currently supports InfluxDB v2 only"}), 400
    if not (cfg.get("token") and cfg.get("org") and cfg.get("bucket")):
        return jsonify({
            "ok": False,
            "error": "InfluxDB v2 requires token, org, bucket. Bitte in /config YAML einlesen und speichern.",
        }), 400

    job_id = uuid.uuid4().hex
    job = {
        "id": job_id,
        "state": "queued",
        "message": "Warte...",
        "started_at": datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z"),
        "started_mono": time.monotonic(),
        "cancelled": False,
        "error": None,
        "rows_written": 0,
        "format": fmt,
        "file": None,
        "download_url": None,
        "query": "",
        "out_dir": str(target_dir),
    }

    with EXPORT_LOCK:
        EXPORT_JOBS[job_id] = job
        cutoff = time.monotonic() - (6 * 60 * 60)
        old = [k for k, v in EXPORT_JOBS.items() if float(v.get("started_mono") or 0) < cutoff]
        for k in old:
            if k != job_id:
                EXPORT_JOBS.pop(k, None)

    LOG.info(
        "job_start type=export job_id=%s ip=%s ua=%s fmt=%s measurement=%s field=%s entity_id=%s friendly_name=%s out_dir=%s",
        job_id,
        _req_ip(),
        _req_ua(),
        fmt,
        measurement,
        field,
        entity_id or "",
        friendly_name or "",
        str(target_dir),
    )

    t = threading.Thread(
        daemon=True,
        target=_export_job_thread,
        args=(
            job_id,
            cfg,
            fmt,
            delim,
            measurement,
            field,
            entity_id,
            friendly_name,
            start_dt,
            stop_dt,
            tz_name,
            tz_offset_minutes,
            str(target_dir),
        ),
    )
    t.start()
    return jsonify({"ok": True, "job_id": job_id})


