_ROLLUP_SCHED_STARTED = False


def _rollup_due_now(cfg: dict[str, Any]) -> bool:
    try:
        mode = str(cfg.get("rollup_refresh_mode") or "manual").strip().lower()
        if mode not in ("hours", "daily", "weekly", "manual"):
            mode = "manual"
        if mode == "manual":
            return False

        st = _timers_state_get("rollup")
        last_ts = 0.0
        try:
            last_run = _parse_iso_datetime(str(st.get("last_run_at") or "").strip())
            last_ts = last_run.timestamp() if last_run else 0.0
        except Exception:
            last_ts = 0.0

        if mode == "hours":
            try:
                h = int(cfg.get("rollup_refresh_hours") or 24)
            except Exception:
                h = 24
            if h <= 0:
                return False
            if last_ts <= 0:
                return True
            return (datetime.now(timezone.utc).timestamp() - last_ts) >= float(h * 3600)

        at = str(cfg.get("rollup_refresh_daily_at") or "04:00:00").strip() or "04:00:00"
        hh, mm, ss = _timer_parse_hms(at, (4, 0, 0))
        wd = _timer_parse_weekday(cfg.get("rollup_refresh_weekday"), default=0)

        now_local = datetime.now().astimezone()
        boundary = _timer_last_boundary_local(now_local, mode=mode, hh=hh, mm=mm, ss=ss, weekday=wd)
        if not boundary:
            return False
        if last_ts <= 0:
            return True
        last_local = datetime.fromtimestamp(last_ts, tz=timezone.utc).astimezone(now_local.tzinfo)
        return last_local < boundary
    except Exception:
        return False


def _rollup_inflight() -> bool:
    with ROLLUP_LOCK:
        for j in ROLLUP_JOBS.values():
            try:
                st = str(j.get("state") or "")
                if st and st not in ("done", "error", "cancelled"):
                    return True
            except Exception:
                continue
    return False


def _rollup_scheduler_loop() -> None:
    """Scheduled trigger for rollup runs (best-effort)."""

    while True:
        try:
            cfg = _overlay_from_yaml_if_enabled(load_cfg())
            if not bool(cfg.get("rollup_enabled", True)) or not bool(cfg.get("rollup_auto_update", False)):
                time.sleep(60)
                continue
            if int(cfg.get("influx_version", 2) or 2) != 2:
                time.sleep(60)
                continue
            if not _rollup_due_now(cfg):
                time.sleep(60)
                continue
            if _rollup_inflight():
                time.sleep(60)
                continue

            profiles = _rollup_profiles_load(cfg)
            prof = next((p for p in profiles if isinstance(p, dict) and bool(p.get("enabled", True))), None)
            if not prof:
                time.sleep(60)
                continue
            profile_id = str(prof.get("id") or "default").strip() or "default"
            delete_source_after = bool(prof.get("delete_source_after_default", False))

            try:
                _plan, union_start, union_stop = _rollup_plan_level_windows(
                    prof,
                    now_utc=datetime.now(timezone.utc),
                    start_override=None,
                    stop_override=None,
                )
            except Exception:
                time.sleep(60)
                continue

            job_id = uuid.uuid4().hex
            run_id = uuid.uuid4().hex
            now_iso = _utc_now_iso_ms()
            job = {
                "id": job_id,
                "type": "rollup_run",
                "timer_id": "rollup",
                "state": "pending",
                "message": "Job wird gestartet...",
                "started_at": now_iso,
                "updated_at": now_iso,
                "started_mono": time.monotonic(),
                "cancelled": False,
                "error": None,
                "profile_id": profile_id,
                "run_id": run_id,
                "start": _dt_to_rfc3339_utc_full(union_start),
                "stop": _dt_to_rfc3339_utc_full(union_stop),
                "delete_source_after": delete_source_after,
                "trigger_page": "scheduler",
                "trigger_ip": None,
                "trigger_ua": None,
            }
            with ROLLUP_LOCK:
                ROLLUP_JOBS[job_id] = job
            th = threading.Thread(target=_rollup_job_thread, args=(job_id,), daemon=True)
            th.start()
            try:
                _timer_mark_started("rollup", job_id=job_id)
            except Exception:
                pass
            try:
                _timer_event_append("rollup", "scheduler_start", {"job_id": job_id, "profile_id": profile_id})
            except Exception:
                pass
        except Exception:
            pass
        time.sleep(60)


def _rollup_scheduler_start() -> None:
    global _ROLLUP_SCHED_STARTED
    if _ROLLUP_SCHED_STARTED:
        return
    _ROLLUP_SCHED_STARTED = True
    t = threading.Thread(target=_rollup_scheduler_loop, daemon=True)
    t.start()
    try:
        LOG.info("rollup scheduler started")
    except Exception:
        pass


try:
    _rollup_scheduler_start()
except Exception:
    pass


_WATCHLIST_SCHED_STARTED = False


def _watchlist_scheduler_loop() -> None:
    """Scheduled trigger for watchlist runs (best-effort)."""

    while True:
        try:
            xs = _watchlists_load()
            for w in xs:
                if not isinstance(w, dict):
                    continue
                wid = str(w.get("id") or "").strip()
                if not wid:
                    continue
                tid = _watchlist_timer_id(wid)
                if not bool(w.get("enabled", True)) or not bool(w.get("auto_update", True)):
                    continue
                if not _watchlist_due_now(w):
                    continue
                if _watchlist_run_inflight(tid):
                    continue
                try:
                    run_id = _watchlist_start_run(wid, trigger_page="scheduler", timer_id=tid)
                    try:
                        _timer_event_append(tid, "scheduler_start", {"run_id": run_id, "watchlist_id": wid})
                    except Exception:
                        pass
                except Exception:
                    continue
        except Exception:
            pass
        time.sleep(60)


def _watchlist_scheduler_start() -> None:
    global _WATCHLIST_SCHED_STARTED
    if _WATCHLIST_SCHED_STARTED:
        return
    _WATCHLIST_SCHED_STARTED = True
    t = threading.Thread(target=_watchlist_scheduler_loop, daemon=True)
    t.start()
    try:
        LOG.info("watchlist scheduler started")
    except Exception:
        pass


try:
    _watchlist_scheduler_start()
except Exception:
    pass

_VERSION_RE = re.compile(r"^[0-9A-Za-z][0-9A-Za-z._-]*$")


def _read_addon_version() -> str:
    env = (os.environ.get("ADDON_VERSION") or "").strip()
    if env and env not in ("0", "null") and _VERSION_RE.match(env):
        return env

    # Fallback to the metadata file baked into the image.
    try:
        meta = Path(__file__).resolve().parent / "addon_config.yaml"
        if meta.exists():
            data = yaml.safe_load(meta.read_text(encoding="utf-8")) or {}
            if isinstance(data, dict):
                v = (data.get("version") or "").strip()
                if v and _VERSION_RE.match(v):
                    return v
    except Exception:
        pass

    return "dev"


ADDON_VERSION = _read_addon_version()


@app.context_processor
def _inject_globals():
    return {"addon_version": ADDON_VERSION}


@app.get("/api/info")
def api_info():
    cfg = _overlay_from_yaml_if_enabled(load_cfg())
    eff_v, det_v, det_src = _effective_influx_version(cfg)
    return jsonify({
        "ok": True,
        "version": ADDON_VERSION,
        "ha_platform": _ha_platform(),
        "influx_cli_available": _influx_cli_available(),
        "active_database_mode": str(cfg.get("active_database_mode") or "v2"),
        "influx_configured_mode": str(cfg.get("influx_version_mode") or "manual"),
        "influx_configured_version": int(cfg.get("influx_version", 2) or 2),
        "influx_detected_version": det_v,
        "influx_detection_source": det_src,
        "influx_effective_version": eff_v,
    })


@app.get("/api/sysinfo")
def api_sysinfo():
    cfg = load_cfg()
    rss = _process_rss_bytes()
    data_bytes = _addon_data_usage_bytes()

    # Add-on process uptime (best-effort)
    uptime_s = None
    try:
        uptime_s = int(max(0.0, time.monotonic() - float(PROCESS_STARTED_MONO)))
    except Exception:
        uptime_s = None

    disk_total = None
    disk_free = None
    try:
        du = shutil.disk_usage(str(DATA_DIR))
        disk_total = int(du.total)
        disk_free = int(du.free)
    except Exception:
        pass

    load1 = None
    load5 = None
    load15 = None
    try:
        a, b, c = os.getloadavg()
        load1, load5, load15 = float(a), float(b), float(c)
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "sys": {
            "started_at": PROCESS_STARTED_AT,
            "uptime_seconds": uptime_s,
            "uptime": _hms(uptime_s) if isinstance(uptime_s, int) else None,
            "rss_bytes": rss,
            "rss": _fmt_bytes(rss),
            "addon_data_bytes": data_bytes,
            "addon_data": _fmt_bytes(data_bytes),
            "disk_total_bytes": disk_total,
            "disk_free_bytes": disk_free,
            "disk_total": _fmt_bytes(disk_total),
            "disk_free": _fmt_bytes(disk_free),
            "cpu_count": os.cpu_count(),
            "loadavg_1": load1,
            "loadavg_5": load5,
            "loadavg_15": load15,
            "ui_status_show_sysinfo": bool(cfg.get("ui_status_show_sysinfo", False)),
        }
    })


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8099)
